                        <div class="admin-dispute-item-copy">
                          <strong>{{ item.title }}</strong>
                          <small v-if="item.auditLabel">{{ item.auditLabel }}</small>
                          <small v-if="item.nextAction">{{ item.nextAction }}</small>
                          <small>{{ item.project }} / {{ item.status }}</small>
