                        <div class="admin-dispute-item-actions">
                          <a v-if="item.url" :href="item.url" target="_blank" rel="noreferrer" aria-label="Open dispute evidence">
                            <Link2 :size="12" />
                          </a>
                          <button
                            v-if="item.canExecute"
                            type="button"
                            :disabled="releasingTaskID === item.id"
                            @click="executeAdminOpsAction(item)"
                          >
                            {{ releasingTaskID === item.id ? item.busyLabel : item.actionLabel }}
                          </button>
                        </div>
                      </article>
                    </div>
                    <small v-else>{{ dashboardSearch ? 'No matching signals' : 'No open signals' }}</small>
                  </article>
                </div>
                <article v-else class="dash-empty-state compact">
                  <strong>{{ adminConsoleLoading ? 'Loading dispute center...' : 'No dispute lanes' }}</strong>
                  <p>{{ adminConsoleLoading ? 'Syncing admin moderation lanes.' : 'Admin dispute and moderation lanes will appear here.' }}</p>
                </article>
              </section>

              <section class="dash-card admin-ops-card">
                <div class="card-title-row">
                  <div>
                    <h2>Ops Queue</h2>
                    <p>Review submissions, disputes, moderation, fraud, security, and payout audit signals.</p>
                  </div>
                  <span>{{ adminOpsRows.length }} rows</span>
                </div>
                <div v-if="adminOpsRows.length" class="admin-ops-list">
                  <article v-for="item in adminOpsRows" :key="item.id" class="admin-ops-row">
                    <span :class="['ledger-event-type', item.tone]">{{ item.severity }}</span>
                    <div>
                      <strong>{{ item.title }}</strong>
                      <p>{{ item.body }}</p>
                      <small v-if="item.nextAction">{{ item.nextAction }}</small>
                      <small v-if="item.auditLabel || item.amount">{{ item.auditLabel }}<template v-if="item.auditLabel && item.amount"> / </template>{{ item.amount }}</small>
                      <small>{{ item.project }} ┬╖ {{ item.task || item.reference }} ┬╖ {{ item.when }}</small>
                    </div>
                    <b>{{ item.status }}</b>
                    <a v-if="item.url" :href="item.url" target="_blank" rel="noreferrer">
                      <Link2 :size="12" />
                      Open
                    </a>
                    <button v-if="item.canExecute" type="button" :disabled="releasingTaskID === item.id" @click="executeAdminOpsAction(item)">
                      {{ releasingTaskID === item.id ? item.busyLabel : item.actionLabel }}
                    </button>
                  </article>
                </div>
                <article v-else class="dash-empty-state compact">
                  <strong>{{ adminConsoleLoading ? 'Loading ops queue...' : 'No admin ops items' }}</strong>
                  <p>{{ adminConsoleLoading ? 'Fetching moderation and payout signals.' : 'Review submissions and moderation alerts will appear here.' }}</p>
                </article>
