                    <article v-for="row in adminReputationRows" :key="row.id">
                      <div>
                        <strong>{{ row.worker }}</strong>
                        <small>{{ row.flags }}</small>
                      </div>
                      <span>{{ row.score }}</span>
                      <b>{{ row.risk }}</b>
                      <small>{{ row.tasks }} tasks ┬╖ {{ row.paid }}</small>
