                <div v-if="dashboardAgentRows.length" class="dashboard-agent-grid">
                  <article v-for="agent in dashboardAgentRows" :key="agent.type">
                    <span :class="['popular-agent-icon', agent.tone]">
                      <component :is="agent.icon" :size="22" />
                    </span>
                    <div>
                      <strong>{{ agent.title }}</strong>
                      <small>{{ agent.displayBody }}</small>
                      <p>{{ agent.capability }}</p>
                    </div>
                    <b>{{ agent.status }}</b>
                  </article>
                </div>
                <article v-else-if="!dashboardAgentQueueRows.length" class="dash-empty-state compact">
                  <strong>{{ marketplaceLoading || agentQueueLoading ? 'Loading AI agents...' : (dashboardSearch ? 'No agents match search' : 'No agent queue yet') }}</strong>
                  <p>{{ marketplaceLoading || agentQueueLoading ? 'Fetching agent task lanes.' : (dashboardSearch ? 'Clear search to show routed agent lanes and work packets.' : 'AI-scoped tasks will appear after a funded project allows agents.') }}</p>
                  <div v-if="!marketplaceLoading && !agentQueueLoading" class="dashboard-tool-empty-actions compact">
                    <button v-if="dashboardSearch" type="button" @click="dashboardSearch = ''">
                      <X :size="13" />
                      Clear Search
                    </button>
                    <button type="button" @click="openProjectWizard">
                      <Plus :size="13" />
                      Start Project
                    </button>
                    <button type="button" @click="openDashboardSection('repo-import')">
                      <UploadCloud :size="13" />
                      Import Repo
                    </button>
                    <button type="button" @click="refreshDashboardToolSection">
                      <RefreshCw :size="13" />
                      Refresh
                    </button>
                  </div>
                </article>
                <div v-if="agentQueueError" class="deployment-error">{{ agentQueueError }}</div>
                <div v-if="dashboardAgentQueueRows.length" class="dashboard-agent-task-list">
                  <article v-for="task in dashboardAgentQueueRows" :key="task.id">
                    <span :class="['popular-agent-icon', task.tone]">
                      <Bot :size="18" />
                    </span>
                    <div class="agent-task-main">
                      <strong>{{ task.issue }} {{ task.title }}</strong>
                      <small>{{ task.project }} - {{ task.lane }} - {{ task.reward }}</small>
                      <p>{{ task.summary }}</p>
                      <em>{{ task.evidence }}</em>
                      <em v-if="task.nextAction">{{ task.nextAction }}</em>
                      <div v-if="task.actionRows.length" class="agent-task-actions">
                        <button
                          v-for="action in task.actionRows"
                          :key="action.key"
                          type="button"
                          :disabled="recordingAgentActionKey === action.key"
                          @click="recordAgentQueueAction(task, action)"
                        >
                          <Sparkles :size="12" />
                          {{ recordingAgentActionKey === action.key ? 'Recording' : action.shortLabel }}
                        </button>
                      </div>
                      <div v-if="task.packetRows.length" class="agent-work-packet" aria-label="Agent work packet">
                        <span v-for="packet in task.packetRows" :key="packet.label">
                          <b>{{ packet.label }}</b>
                          <small>{{ packet.value }}</small>
                        </span>
                      </div>
                      <ol v-if="task.runbookRows.length" class="agent-runbook-strip" aria-label="Agent runbook">
                        <li v-for="step in task.runbookRows" :key="step.key">
                          <b>{{ step.step }}</b>
                          <span>{{ step.label }}</span>
                          <small>{{ step.method }} {{ step.endpoint }}</small>
                        </li>
                      </ol>
                    </div>
                    <b>{{ task.readiness }}</b>
                    <div class="agent-task-links">
                      <a :href="task.protocolUrl" target="_blank" rel="noreferrer">
                        Manifest
                      </a>
                      <a v-if="task.workflowUrl" :href="task.workflowUrl" target="_blank" rel="noreferrer">
                        Workflow
                      </a>
                      <a v-if="task.workflowPulseUrl" :href="task.workflowPulseUrl" target="_blank" rel="noreferrer">
                        Pulse
                      </a>
                      <a v-if="task.deploymentUrl" :href="task.deploymentUrl" target="_blank" rel="noreferrer">
                        Deploy
                      </a>
                    </div>
                    <button type="button" :disabled="claimingBountyID === task.id" @click="claimMarketplaceBounty(task)">
                      {{ claimingBountyID === task.id ? 'Claiming' : 'Claim' }}
                    </button>
                  </article>
                </div>
              </section>

              <section v-else-if="dashboardSection === 'repo-import'" class="dash-card dashboard-tool-card">
                <div class="card-title-row">
                  <div>
                    <h2>Repository Import</h2>
                    <p>Import a GitHub issue queue, score open issues, and turn the result into a funded MergeOS project.</p>
                  </div>
                  <span>{{ repoImportedIssues.length }} issues</span>
                </div>
                <div class="dashboard-tool-form">
                  <label :class="{ invalid: repoImportFieldError('repoUrl') }">
                    <span>GitHub repository URL</span>
                    <input
                      v-model.trim="projectSetupForm.repoUrl"
                      :aria-invalid="Boolean(repoImportFieldError('repoUrl'))"
                      type="url"
                      placeholder="https://github.com/owner/repo"
                      @input="clearRepoImportFieldError('repoUrl')"
                      @keyup.enter="loadRepoIssues"
                    />
                    <small v-if="repoImportFieldError('repoUrl')" class="dashboard-tool-field-error">{{ repoImportFieldError('repoUrl') }}</small>
                  </label>
                  <button type="button" :disabled="repoImportBusy" @click="loadRepoIssues">
                    <Search :size="14" />
                    {{ repoImportBusy ? 'Scanning' : 'Load Issues' }}
                  </button>
                  <button type="button" @click="openProjectWizard({ intent: 'repo-import' })">
                    <Plus :size="14" />
                    Open Wizard
                  </button>
                </div>
                <p v-if="repoImportError" class="deployment-error">{{ repoImportError }}</p>
                <div v-if="repoImportedIssues.length" class="dashboard-issue-list">
                  <article v-for="issue in repoImportedIssues.slice(0, 8)" :key="issue.number">
                    <span>#{{ issue.number }}</span>
                    <div>
                      <strong>{{ issue.title }}</strong>
                      <small>{{ toTitleLabel(issue.complexity) }} - score {{ issue.score }} - {{ formatMRGFromCents(issue.estimated_cents) }}</small>
                    </div>
                  </article>
                </div>
                <section v-if="repoImportedIssues.length" class="repo-import-next-panel">
                  <div>
                    <strong>Scored task graph ready</strong>
                    <p>{{ repoImportResult.owner }}/{{ repoImportResult.name }} has {{ repoImportedIssues.length }} issue{{ repoImportedIssues.length === 1 ? '' : 's' }} ready for scope, budget, and escrow funding.</p>
                  </div>
                  <div class="dashboard-tool-empty-actions compact">
                    <button type="button" @click="continueImportedRepoProject('scope')">
                      <GitBranch :size="13" />
                      Continue to Scope
                    </button>
                    <button type="button" @click="continueImportedRepoProject('estimate')">
                      <Calculator :size="13" />
                      Estimate Budget
                    </button>
                    <button type="button" @click="continueImportedRepoProject('funding')">
                      <CircleDollarSign :size="13" />
                      Open Funding
                    </button>
                  </div>
                </section>
                <article v-else class="dash-empty-state compact">
                  <strong>{{ repoImportBusy ? 'Loading repo issues...' : 'No imported issues yet' }}</strong>
                  <p>{{ repoImportBusy ? 'Calling the public repository issue scanner.' : 'Enter a public GitHub repository URL to score open issues.' }}</p>
                </article>
              </section>

              <section v-else-if="dashboardSection === 'issue-scanner'" class="dash-card dashboard-tool-card">
                <div class="card-title-row">
                  <div>
                    <h2>AI Issue Scanner</h2>
