                    <component :is="dashboardIssueScannerPrimaryAction.icon" :size="14" />
                    {{ dashboardIssueScannerPrimaryAction.label }}
                  </button>
                </div>
                <div class="repo-intel-stats">
                  <span v-for="stat in dashboardRepositoryIntelligenceStats" :key="stat.label" :class="stat.tone">
                    <strong>{{ stat.value }}</strong>
                    {{ stat.label }}
                  </span>
                </div>
                <div v-if="dashboardRepositoryIntelligenceError" class="deployment-error">{{ dashboardRepositoryIntelligenceError }}</div>
                <div v-if="dashboardRepositoryFindingRows.length" class="repo-finding-list">
                  <article v-for="finding in dashboardRepositoryFindingRows" :key="finding.id">
                    <span :class="finding.tone">{{ finding.severity }}</span>
                    <div>
                      <strong>{{ finding.title }}</strong>
                      <small>{{ finding.path }} - {{ finding.kind }}</small>
                    </div>
                  </article>
                </div>
                <article v-else class="dash-empty-state compact">
                  <strong>{{ dashboardIssueScannerEmptyState.title }}</strong>
                  <p>{{ dashboardIssueScannerEmptyState.body }}</p>
