                      :aria-invalid="Boolean(priceEvaluationFieldError('title'))"
                      placeholder="Repository refactor, bug fix, or SaaS build"
                      @input="clearPriceEvaluationFieldError('title')"
                    />
                    <small v-if="priceEvaluationFieldError('title')" class="dashboard-tool-field-error">{{ priceEvaluationFieldError('title') }}</small>
                  </label>
                  <label>
                    <span>Tech stack</span>
                    <input v-model.trim="projectSetupForm.techStack" placeholder="Vue, Go, PostgreSQL" />
                  </label>
                  <label class="wide" :class="{ invalid: priceEvaluationFieldError('scope') }">
                    <span>Scope</span>
                    <textarea
                      v-model.trim="projectSetupForm.overview"
                      :aria-invalid="Boolean(priceEvaluationFieldError('scope'))"
