                      placeholder="Describe the work, risks, integrations, and acceptance expectations"
                      @input="clearPriceEvaluationFieldError('scope')"
                    ></textarea>
                    <small v-if="priceEvaluationFieldError('scope')" class="dashboard-tool-field-error">{{ priceEvaluationFieldError('scope') }}</small>
                  </label>
                  <button type="button" :disabled="priceEvaluationBusy" @click="runProjectPriceEvaluation">
