                  </article>
                  <article v-for="item in priceEvaluation.breakdown.slice(0, 3)" :key="item.category">
                    <span>{{ item.category }}</span>
                    <strong>{{ formatMRGFromCents(item.amount_cents) }}</strong>
                    <small>{{ item.reason }}</small>
                  </article>
                </div>
                <p v-if="priceEvaluationError" class="deployment-error">{{ priceEvaluationError }}</p>
              </section>

              <section v-else-if="dashboardSection === 'analytics'" class="dash-card dashboard-tool-card">
