                    <p>{{ dashboardProjectView.body }}</p>
                  </div>
                  <span :class="['live-badge', dashboardStatusClass(dashboardProjectView.status)]">{{ dashboardProjectView.status }}</span>
                </div>

                <div class="dash-project-actions">
