                    >
                      <component :is="action.icon" :size="15" />
                      {{ action.label }}
                    </button>
                  </template>
                  <button v-if="dashboardSelectedProject" type="button" @click="copyDashboardProjectShareLink">
                    <Share2 :size="15" />
                    Share
