                    >
                      <MoreHorizontal :size="16" />
                    </button>
                    <section v-if="dashboardProjectActionsVisible" class="dashboard-project-actions-panel" aria-label="Project actions">
                      <button
                        v-for="item in dashboardProjectActionLinks"
                        :key="item.label"
