                    <button type="button" :disabled="dashboardDeliverySnapshotLoading || !dashboardSelectedProject" @click="loadDashboardDeliverySnapshotData(dashboardSelectedProject?.id)">
                      <RefreshCw :size="14" />
                      {{ dashboardDeliverySnapshotLoading ? 'Syncing' : 'Refresh' }}
                    </button>
                  </div>
                </div>

                <div class="delivery-snapshot-main">
                  <div class="delivery-snapshot-progress">
                    <span class="delivery-snapshot-icon"><LayoutDashboard :size="18" /></span>
                    <div>
                      <strong>{{ dashboardDeliverySnapshotView.progress }}%</strong>
                      <small>{{ dashboardDeliverySnapshotView.generated }}</small>
                      <div class="mini-progress"><i :style="{ width: `${dashboardDeliverySnapshotView.progress}%` }" /></div>
                    </div>
                  </div>

                  <div class="delivery-snapshot-stats">
                    <span v-for="stat in dashboardDeliverySnapshotStats" :key="stat.label" :class="stat.tone">
                      <strong>{{ stat.value }}</strong>
                      {{ stat.label }}
                      <small>{{ stat.caption }}</small>
                    </span>
                  </div>
                </div>

                <div v-if="dashboardDeliverySnapshotError" class="deployment-error">{{ dashboardDeliverySnapshotError }}</div>
                <div class="delivery-snapshot-components">
                  <span v-for="component in dashboardDeliverySnapshotComponents" :key="component.key" :class="{ ready: component.loaded }">
                    <i :class="component.tone" />
