                  :aria-selected="isDashboardProjectTabActive(tabItem) ? 'true' : 'false'"
                  @click="handleDashboardProjectTab(tabItem)"
                >
                  {{ tabItem }}
                  <span v-if="dashboardProjectTabCount(tabItem)">{{ dashboardProjectTabCount(tabItem) }}</span>
                </button>
              </div>

              <section class="dash-overview-grid">
