                      <div class="mini-progress"><i :style="{ width: `${dashboardEscrowView.progress}%` }" /></div>
                    </div>
                  </div>

                  <div class="escrow-stat-grid" aria-label="Escrow reserve summary">
                    <span v-for="stat in dashboardEscrowStats" :key="stat.label" :class="stat.tone">
                      <strong>{{ stat.value }}</strong>
                      {{ stat.label }}
                    </span>
                  </div>

                  <div v-if="dashboardEscrowError" class="deployment-error">{{ dashboardEscrowError }}</div>
                  <article v-else-if="dashboardEscrowLoading && !dashboardEscrow" class="dash-empty-state compact">
                    <strong>Loading escrow control...</strong>
                    <p>Syncing reserves, payout releases, and task-level balances.</p>
                  </article>
                  <div v-else-if="dashboardEscrowTaskRows.length" class="escrow-task-list">
                    <article v-for="task in dashboardEscrowTaskRows" :key="task.id">
                      <span>#{{ task.issueNumber }}</span>
