                      </div>
                      <article v-else class="repo-intel-empty">
                        <strong>{{ dashboardIssueScannerEmptyState.title }}</strong>
                        <small>{{ dashboardRepositoryScan ? (dashboardRepositoryScan.status === 'ready' ? 'Repository scan is clear.' : dashboardRepositoryScan.summary) : dashboardIssueScannerEmptyState.body }}</small>
                        <div v-if="dashboardIssueScannerEmptyActions.length" class="dashboard-tool-empty-actions compact">
                          <button
                            v-for="action in dashboardIssueScannerEmptyActions"
                            :key="action.label"
                            type="button"
                            :disabled="action.disabled"
                            @click="action.run()"
                          >
                            <component :is="action.icon" :size="13" />
                            {{ action.label }}
                          </button>
                        </div>
                      </article>
                    </section>

                    <section class="repo-intel-section">
                      <div class="repo-intel-section-head">
                        <strong>Dependencies</strong>
                        <small>{{ dashboardRepositoryScanStats.dependency_files || 0 }} manifests</small>
                      </div>
                      <div v-if="dashboardRepositoryDependencyRows.length" class="repo-dependency-list">
                        <article v-for="dependency in dashboardRepositoryDependencyRows" :key="dependency.key">
                          <div>
                            <strong>{{ dependency.ecosystem }}</strong>
                            <small>{{ dependency.path }}</small>
                          </div>
                          <span :class="dependency.tone">{{ dependency.packages }} - {{ dependency.lockfile }}</span>
