                        <small>{{ dashboardTaskGraphStats.edge_count || 0 }} dependencies</small>
                      </div>
                      <div v-if="dashboardTaskGraphRows.length" class="repo-task-graph-list">
                        <article v-for="node in dashboardTaskGraphRows" :key="node.id">
                          <span>#{{ node.issueNumber }}</span>
                          <div>
                            <strong>{{ node.title }}</strong>
                            <small>{{ node.lane }} - {{ node.agent }} - {{ node.blockedBy }}</small>
