                  v-for="action in dashboardProjectBootstrapActions"
                  :key="action.label"
                  type="button"
                  :disabled="action.disabled"
                  @click="action.run()"
                >
                  <component :is="action.icon" :size="13" />
                  {{ action.label }}
                </button>
              </div>
            </article>
          </section>

          <section class="dash-card rail-card workflow-pulse-card">
            <div class="card-title-row">
              <h2>Workflow Pulse</h2>
              <span :class="['dashboard-status-pill', dashboardStatusClass(dashboardWorkflowPulseView.status)]">{{ dashboardWorkflowPulseView.status }}</span>
            </div>
            <div class="ai-workflow-summary">
              <span><GitBranch :size="16" /></span>
