            <div v-else-if="dashboardWorkflowPulseStages.length" class="ai-workflow-list">
              <article v-for="stage in dashboardWorkflowPulseStages" :key="stage.id">
                <span :class="['notification-dot', stage.tone]" />
                <div>
                  <strong>{{ stage.title }}</strong>
                  <small>{{ stage.body }}</small>
                </div>
                <b>{{ stage.status }}</b>
              </article>
            </div>
            <article v-else class="dash-empty-state compact">
              <strong>{{ dashboardWorkflowPulseLoading ? 'Loading pulse...' : 'No workflow pulse yet' }}</strong>
              <p>{{ dashboardWorkflowPulseLoading ? 'Syncing delivery stages.' : 'Select a project to inspect the delivery pulse.' }}</p>
              <div v-if="!dashboardWorkflowPulseLoading && !dashboardSelectedProject" class="dashboard-tool-empty-actions compact">
                <button
                  v-for="action in dashboardProjectBootstrapActions"
                  :key="action.label"
                  type="button"
                  :disabled="action.disabled"
