                <span :class="['ledger-trust-icon', contract.tone]">
                  <component :is="contract.icon" :size="15" />
                </span>
                <div>
                  <strong>{{ contract.title }}</strong>
                  <small>{{ contract.version }}</small>
                </div>
                <b :class="contract.statusTone">{{ contract.status }}</b>
              </div>
              <p>{{ contract.body }}</p>
              <dl class="live-event-contract-meta">
                <div>
                  <dt>Schema</dt>
                  <dd>{{ contract.schema }}</dd>
                </div>
                <div>
                  <dt>Source</dt>
                  <dd>{{ contract.sourceLabel }}</dd>
                </div>
                <div>
                  <dt>Proof</dt>
                  <dd>{{ contract.proofLabel }}</dd>
                </div>
              </dl>
              <div class="live-event-contract-actions">
                <button type="button" :disabled="!contract.filterLabel" @click="setLiveFeedType(contract.filterLabel)">
                  {{ contract.filterActionLabel }}
                  <ArrowRight :size="12" />
                </button>
                <button type="button" @click="copyLiveEventContract(contract)">
                  Copy ref
                  <Link2 :size="12" />
                </button>
              </div>
            </article>
          </div>
        </section>

        <section class="live-feed-content">
          <div class="ledger-main-card live-feed-main-card">
            <div class="live-feed-toolbar">
              <div>
                <span class="marketplace-eyebrow">PUBLIC TIMELINE</span>
                <h2>Delivery activity</h2>
                <p class="live-feed-result-label">{{ liveFeedResultLabel }}</p>
              </div>
              <div class="ledger-table-actions">
                <button type="button" @click="loadLiveFeedData">
                  <RefreshCw :size="14" />
                  Refresh
                </button>
                <button type="button" @click="openPublicPage('ledger')">
                  Ledger Logs
                  <ArrowRight :size="13" />
                </button>
              </div>
            </div>

            <div v-if="liveFeedLoading" class="live-feed-state">Loading public activity...</div>
            <div v-else-if="liveFeedError" class="live-feed-state error">{{ liveFeedError }}</div>
            <div v-else-if="!liveFeedAllItemsView.length" class="live-feed-state">No live activity yet. Fund a project to create the first public events.</div>
            <div v-else-if="!liveFeedItemsView.length" class="live-feed-state">No live activity matches this filter.</div>
            <div v-else class="live-feed-list">
              <article v-for="item in liveFeedItemsView" :key="item.id" class="live-feed-row">
                <span :class="['ledger-event-type', item.tone]">
                  <component :is="item.icon" :size="15" />
                  {{ item.typeLabel }}
                </span>
                <div class="live-feed-row-copy">
                  <div>
                    <strong>{{ item.title }}</strong>
                    <span>{{ item.status }}</span>
                  </div>
                  <p>{{ item.body }}</p>
                  <small>{{ item.project }} ┬╖ {{ item.actor }} ┬╖ {{ item.meta }}<template v-if="item.auditLabel"> ┬╖ {{ item.auditLabel }}</template></small>
                </div>
                <div class="live-feed-row-meta">
                  <strong v-if="item.amount" :class="['ledger-amount', item.amountTone]">{{ item.amount }}</strong>
                  <span v-else>{{ item.date }}</span>
                  <div v-if="item.url || item.rawReference || item.rawContractReference" class="ledger-ref-actions">
                    <button v-if="item.url || item.rawReference" class="ledger-ref-button" type="button" @click="handleLiveFeedReference(item)">
                      {{ item.reference || (item.url ? 'Open proof' : 'Copy ref') }}
                      <Link2 :size="12" />
                    </button>
                    <button v-if="item.rawContractReference" class="ledger-ref-button contract-ref-button" type="button" @click="copyContractReference(item)">
                      {{ item.contractReference }}
                      <Hash :size="12" />
                    </button>
                  </div>
                </div>
              </article>
            </div>
          </div>

          <aside class="ledger-rail">
            <section class="ledger-side-card">
              <div class="side-card-head">
                <h2>Activity Types</h2>
                <button type="button" @click="loadLiveFeedData">Refresh</button>
              </div>
              <div class="live-feed-type-list">
                <button
                  v-for="row in liveFeedTypeOptions"
                  :key="row.label"
                  :class="{ active: activeLiveFeedType === row.label }"
                  type="button"
                  @click="setLiveFeedType(row.label)"
                >
                  <span :class="['notification-dot', row.tone]" />
                  <strong>{{ row.label }}</strong>
                  <small>{{ row.count }}</small>
                </button>
                <article v-if="!liveFeedAllItemsView.length">
                  <span class="notification-dot blue" />
                  <strong>Waiting for events</strong>
                  <small>0</small>
                </article>
              </div>
            </section>

            <section class="ledger-side-card">
              <div class="side-card-head">
                <h2>Active Contributors</h2>
                <button type="button" @click="openPublicPage('marketplace')">Directory</button>
              </div>
              <div v-if="liveFeedContributorRows.length" class="live-contributor-list">
                <article v-for="contributor in liveFeedContributorRows" :key="contributor.key">
                  <span :class="['market-avatar', 'small', contributor.tone]">{{ contributor.initials }}</span>
                  <div>
                    <div class="live-contributor-topline">
                      <strong>{{ contributor.name }}</strong>
                      <span :class="['live-contributor-status', contributor.statusTone]">{{ contributor.status }}</span>
                    </div>
                    <p>{{ contributor.role }}</p>
                    <small>{{ contributor.meta }}</small>
                  </div>
                </article>
              </div>
              <p v-else class="live-feed-empty-copy">Accepted contributors will appear as the feed records work.</p>
            </section>

            <section class="ledger-side-card">
              <h2>Latest Signal</h2>
              <div v-if="liveFeedLatestProject" class="live-feed-latest">
                <span :class="['ledger-project-logo', liveFeedLatestProject.tone]">{{ projectInitialFor(liveFeedLatestProject.project) }}</span>
                <div>
                  <strong>{{ liveFeedLatestProject.title }}</strong>
                  <p>{{ liveFeedLatestProject.body }}</p>
                  <small>{{ liveFeedLatestProject.meta }}</small>
                </div>
              </div>
              <p v-else class="live-feed-empty-copy">No current signal.</p>
            </section>
          </aside>
        </section>
      </div>
    </main>

    <main v-else-if="publicPage === 'ledger'" id="top" class="ledger-page">
      <div class="home-container ledger-shell">
        <section class="ledger-hero">
          <div class="ledger-hero-copy">
            <span class="marketplace-eyebrow">LEDGER LOGS</span>
            <div class="ledger-title-row">
              <h1>Ledger Logs</h1>
              <span class="ledger-public-badge">
                <Globe2 :size="14" />
                Real data
              </span>
            </div>
            <p>Transparent platform activity from the live ledger. Payments, token mints, PR handoffs, deployment gates, AI actions, and payouts are loaded from the backend.</p>

            <div class="ledger-trust-row" aria-label="Ledger trust signals">
              <article v-for="item in ledgerTrustItems" :key="item.title">
                <span :class="['ledger-trust-icon', item.tone]">
                  <component :is="item.icon" :size="16" />
                </span>
                <div>
                  <strong>{{ item.title }}</strong>
                  <small>{{ item.body }}</small>
                </div>
              </article>
            </div>
          </div>

          <aside class="ledger-live-card" aria-label="Ledger proof metrics">
            <div class="ledger-card-head">
              <h2>Proof on MergeOS</h2>
              <span class="ledger-live-dot">Live</span>
            </div>
            <div class="ledger-live-grid">
              <article v-for="stat in ledgerLiveStats" :key="stat.label">
                <strong>{{ stat.value }}</strong>
                <span>{{ stat.label }}</span>
              </article>
            </div>
            <button type="button" aria-label="Refresh ledger logs" @click="loadLedgerData">
              <BarChart3 :size="14" />
              Refresh ledger
              <ArrowRight :size="14" />
            </button>
          </aside>
        </section>

        <section class="ledger-economy-strip" aria-label="MRG token economy">
          <article v-for="card in ledgerEconomyCards" :key="card.label">
            <span :class="['ledger-economy-icon', card.tone]">
              <component :is="card.icon" :size="17" />
            </span>
            <div>
              <small>{{ card.label }}</small>
              <strong>{{ card.value }}</strong>
              <span>{{ card.caption }}</span>
            </div>
          </article>
        </section>

        <section class="ledger-proof-lanes" aria-label="Public proof coverage">
          <article v-for="lane in ledgerProofLanes" :key="lane.key">
            <div class="ledger-proof-lane-head">
              <span :class="['ledger-economy-icon', lane.tone]">
                <component :is="lane.icon" :size="17" />
              </span>
              <b :class="lane.statusTone">{{ lane.status }}</b>
            </div>
            <strong>{{ lane.title }}</strong>
            <p>{{ lane.body }}</p>
            <div class="ledger-proof-lane-meta">
              <span>{{ lane.countLabel }}</span>
              <small>{{ lane.latestLabel }}</small>
            </div>
            <button type="button" :aria-label="lane.ariaLabel" @click="applyLedgerProofLane(lane)">
              {{ lane.actionLabel }}
              <ArrowRight :size="12" />
            </button>
          </article>
        </section>

        <section class="ledger-economy-detail-grid" aria-label="MRG economy operations">
          <article class="ledger-economy-panel">
            <div class="ledger-economy-panel-head">
              <div>
                <span>Balances</span>
                <h2>Reserve accounts</h2>
              </div>
              <small>{{ ledgerEconomyBalanceRows.length }} rows</small>
            </div>
            <div v-if="ledgerEconomyBalanceRows.length" class="ledger-economy-balance-list">
              <article v-for="row in ledgerEconomyBalanceRows" :key="row.id">
                <span :class="['ledger-economy-mini-icon', row.tone]">
                  <component :is="row.icon" :size="15" />
                </span>
                <div>
                  <strong>{{ row.label }}</strong>
                  <small>{{ row.role }} - {{ row.count }}</small>
                </div>
                <b>{{ row.amount }}</b>
              </article>
            </div>
            <p v-else>{{ ledgerLoading ? 'Syncing public reserve accounts.' : 'Reserve accounts appear after funding or payout events.' }}</p>
          </article>

          <article class="ledger-economy-panel">
            <div class="ledger-economy-panel-head">
              <div>
                <span>Flows</span>
                <h2>Ledger movement</h2>
              </div>
              <small>{{ ledgerEconomyFlowRows.length }} types</small>
            </div>
            <div v-if="ledgerEconomyFlowRows.length" class="ledger-economy-flow-list">
              <article v-for="row in ledgerEconomyFlowRows" :key="row.type">
                <span :class="['ledger-economy-mini-icon', row.tone]">
                  <component :is="row.icon" :size="15" />
                </span>
                <div>
                  <strong>{{ row.label }}</strong>
                  <small>{{ row.countLabel }} - latest #{{ row.latestSequence }}</small>
                </div>
                <b>{{ row.amount }}</b>
              </article>
            </div>
            <p v-else>{{ ledgerLoading ? 'Syncing public flow groups.' : 'Ledger flow groups will appear with the first economy event.' }}</p>
          </article>

          <article class="ledger-economy-panel">
            <div class="ledger-economy-panel-head">
              <div>
                <span>Recent</span>
                <h2>Economy entries</h2>
              </div>
              <small>{{ ledgerEconomyRecentRows.length }} entries</small>
            </div>
            <div v-if="ledgerEconomyRecentRows.length" class="ledger-economy-recent-list">
              <article v-for="row in ledgerEconomyRecentRows" :key="row.key">
                <span :class="['ledger-economy-mini-icon', row.tone]">
                  <component :is="row.icon" :size="15" />
                </span>
                <div>
                  <strong>{{ row.label }}</strong>
                  <small>{{ row.reference }} - {{ row.when }}</small>
                  <button v-if="row.hash" type="button" @click="copyLedgerReference(row.hash)">
                    <Hash :size="12" />
                    {{ row.shortHash }}
                  </button>
                </div>
                <b>{{ row.amount }}</b>
              </article>
            </div>
            <p v-else>{{ ledgerLoading ? 'Syncing recent token economy entries.' : 'Recent funding, reserve, fee, and payout entries will appear here.' }}</p>
          </article>
        </section>

        <section id="ledger-events" class="ledger-content">
          <div class="ledger-main-card">
            <div class="ledger-tabs-row">
              <div class="ledger-tabs" role="tablist" aria-label="Ledger activity">
                <button
                  v-for="tabItem in ledgerTabs"
                  :key="tabItem"
                  :class="{ active: tabItem === activeLedgerTab }"
                  type="button"
                  role="tab"
                  @click="activeLedgerTab = tabItem"
                >
                  {{ tabItem }}
                </button>
              </div>

              <div class="ledger-table-actions">
                <button :class="{ active: activeLedgerProject !== 'All Projects' }" type="button" @click="toggleLedgerProjectMenu">
                  {{ activeLedgerProjectLabel }}
                  <ChevronDown :size="13" />
                </button>
                <button :class="{ active: ledgerFiltersActive || ledgerAdvancedFiltersVisible }" type="button" @click="toggleLedgerAdvancedFilters">
                  <Filter :size="14" />
                  Filters
                </button>
              </div>
            </div>

            <section v-if="ledgerProjectMenuVisible || ledgerAdvancedFiltersVisible" class="ledger-filter-bar" aria-label="Ledger filters">
              <div v-if="ledgerProjectMenuVisible" class="ledger-project-filter-list">
                <button
                  v-for="option in ledgerProjectOptions"
                  :key="option.value"
                  :class="{ active: option.value === activeLedgerProject }"
                  type="button"
                  @click="setLedgerProjectFilter(option.value)"
                >
                  <span>{{ option.label }}</span>
                  <small>{{ option.count }}</small>
                </button>
              </div>

              <div v-if="ledgerAdvancedFiltersVisible" class="ledger-advanced-filter-grid">
                <label class="ledger-filter-search">
                  <Search :size="15" />
                  <input v-model.trim="ledgerSearch" placeholder="Search refs, projects, actors..." />
                </label>
                <label>
                  <span>Type</span>
                  <select v-model="activeLedgerEventType">
                    <option v-for="option in ledgerEventTypeOptions" :key="option" :value="option">{{ option }}</option>
                  </select>
                </label>
                <label>
                  <span>Status</span>
                  <select v-model="activeLedgerStatus">
                    <option v-for="option in ledgerStatusOptions" :key="option" :value="option">{{ option }}</option>
                  </select>
                </label>
                <button class="ledger-clear-filter-button" type="button" :disabled="!ledgerFiltersActive" @click="clearLedgerFilters">
                  Clear
                </button>
              </div>

              <p class="ledger-filter-summary">
                {{ ledgerFilterResultLabel }}
              </p>
            </section>

            <div class="ledger-table-wrap">
              <table class="ledger-table">
                <thead>
                  <tr>
                    <th>Time (UTC)</th>
                    <th>Type</th>
                    <th>Project</th>
                    <th>Amount</th>
                    <th>Status</th>
                    <th>Tx / Ref</th>
                  </tr>
                </thead>
                <tbody>
                  <tr v-if="ledgerLoading">
                    <td class="ledger-state-cell" colspan="6">Loading real ledger entries...</td>
                  </tr>
                  <tr v-else-if="ledgerError">
                    <td class="ledger-state-cell error" colspan="6">{{ ledgerError }}</td>
                  </tr>
                  <tr v-else-if="ledgerEvents.length === 0">
                    <td class="ledger-state-cell" colspan="6">{{ ledgerEmptyStateLabel }}</td>
                  </tr>
                  <template v-else>
                    <tr v-for="event in ledgerEvents" :key="event.key">
                      <td>
                        <strong>{{ event.date }}</strong>
                        <span>{{ event.time }}</span>
                      </td>
                      <td>
                        <span :class="['ledger-event-type', event.tone]">
                          <component :is="event.icon" :size="15" />
                          {{ event.type }}
                        </span>
                      </td>
                      <td>
                        <div class="ledger-project-cell">
                          <span :class="['ledger-project-logo', event.projectTone]">{{ event.projectInitial }}</span>
                          <div>
                            <strong>{{ event.project }}</strong>
                            <span>by {{ event.company }}</span>
                          </div>
                        </div>
                      </td>
                      <td>
                        <strong :class="['ledger-amount', event.amountTone]">{{ event.amount }}</strong>
                        <span v-if="event.secondaryAmount">{{ event.secondaryAmount }}</span>
                      </td>
                      <td>
                        <span class="ledger-status">{{ event.status }}</span>
                      </td>
                      <td>
                        <div class="ledger-ref-actions">
                          <button class="ledger-ref-button" type="button" @click="handleLedgerEventReference(event)">
                            {{ event.ref }}
                            <Link2 :size="12" />
                          </button>
                          <button v-if="event.rawContractReference" class="ledger-ref-button contract-ref-button" type="button" @click="copyContractReference(event)">
                            {{ event.contractReference }}
                            <Hash :size="12" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  </template>
                </tbody>
              </table>
            </div>

            <button class="ledger-load-button" type="button" @click="loadLedgerData">
              Refresh ledger
              <ChevronDown :size="13" />
            </button>
          </div>

          <aside class="ledger-rail">
            <section class="ledger-side-card">
              <div class="side-card-head">
                <h2>Trending Projects</h2>
                <button type="button" @click="openMarketplaceSection('marketplace-projects')">View all <ArrowRight :size="13" /></button>
              </div>
              <div class="ledger-project-list">
                <article v-if="ledgerTrendingProjects.length === 0">
                  <span class="ledger-project-logo green">M</span>
                  <div>
                    <div>
                      <strong>No funded projects yet</strong>
                    </div>
                    <small>Real projects will appear after payment.</small>
                    <p>
                      <b>0 {{ tokenSymbol }} Escrow</b>
                      <span>0 Contributors</span>
                      <span>0 PRs</span>
                    </p>
                  </div>
                </article>
                <article v-for="project in ledgerTrendingProjects" :key="project.title">
                  <span :class="['ledger-project-logo', project.tone]">{{ project.initial }}</span>
                  <div>
                    <div>
                      <strong>{{ project.title }}</strong>
                      <span class="ledger-live-dot compact">Live</span>
                    </div>
                    <small>by {{ project.company }}</small>
                    <p>
                      <b>{{ project.escrow }}</b>
                      <span>{{ project.contributors }} Contributors</span>
                      <span>{{ project.prs }} PRs</span>
                    </p>
                  </div>
                </article>
              </div>
            </section>

            <section class="ledger-side-card ledger-verified-card">
              <h2>
                <ShieldCheck :size="16" />
                Verified by MergeOS
              </h2>
              <ul>
                <li v-for="check in ledgerVerificationChecks" :key="check">
                  <CheckCircle2 :size="13" />
                  {{ check }}
                </li>
              </ul>
              <button type="button" @click="openTransparencyDocs">
                Learn more about transparency
                <ArrowRight :size="13" />
              </button>
            </section>

            <section class="ledger-side-card ledger-chain-card">
              <h2>Hash-chain proof</h2>
              <p>{{ ledgerProofSummary.body }}</p>
              <button type="button" @click="copyLedgerProofRoot">
                Copy public root
                <Link2 :size="13" />
              </button>
              <button v-if="ledgerProofContractReference" type="button" @click="copyLedgerContractReference">
                Copy contract ref
                <Hash :size="13" />
              </button>
              <div class="ledger-chain-row" v-for="chain in ledgerChainRows" :key="chain.label">
                <span>{{ chain.label }}</span>
                <strong>{{ chain.value }}</strong>
              </div>
            </section>
          </aside>
        </section>

        <section class="ledger-footer-stats" aria-label="Ledger totals">
          <article>
              <ShieldCheck :size="18" />
              <div>
                <strong>Built for transparency.</strong>
                <span>Ready for builder verification.</span>
              </div>
            </article>
          <article v-for="stat in ledgerFooterStats" :key="stat.label">
            <strong>{{ stat.value }}</strong>
            <span>{{ stat.label }}</span>
          </article>
        </section>
      </div>
    </main>

    <main v-else-if="publicPage === 'marketplace'" :key="marketplacePageRenderKey" id="top" class="marketplace-page">
      <div class="home-container marketplace-layout">
        <section class="marketplace-main">
          <section class="marketplace-hero" aria-labelledby="marketplace-title">
            <div class="marketplace-copy">
              <span class="marketplace-eyebrow">{{ publicMarketplaceCopy.eyebrow }}</span>
              <h1 id="marketplace-title">
                {{ publicMarketplaceCopy.titlePrefix }} <span>{{ publicMarketplaceCopy.titleHighlight }}</span>
              </h1>
              <p>
                {{ publicMarketplaceCopy.body }}
              </p>

              <div class="marketplace-actions">
                <button class="primary-button large" type="button" @click="openProjectWizard">
                  {{ publicMarketplaceCopy.postProject }}
                </button>
                <button class="secondary-button large" type="button" @click="openPublicPage('how-it-works')">
                  <span class="play-icon" aria-hidden="true">
                    <ArrowRight :size="14" />
                  </span>
                  {{ publicMarketplaceCopy.howItWorks }}
                </button>
              </div>

              <div class="marketplace-trust" :aria-label="publicMarketplaceCopy.trustLabel">
                <article v-for="item in marketplaceTrustItems" :key="item.title">
                  <span :class="['marketplace-trust-icon', item.tone]">
                    <component :is="item.icon" :size="17" />
                  </span>
                  <div>
                    <strong>{{ item.title }}</strong>
                    <small>{{ item.body }}</small>
                  </div>
                </article>
              </div>
            </div>

            <aside class="marketplace-visual" :aria-label="publicMarketplaceCopy.visualLabel">
              <span class="market-route route-one"></span>
              <span class="market-route route-two"></span>
              <span class="route-node route-node-green">
                <CheckCircle2 :size="17" />
              </span>
              <span class="route-node route-node-purple">
                <UsersRound :size="18" />
              </span>
              <span class="route-node route-node-orange">
                <Code2 :size="18" />
              </span>

              <article class="market-float-card talent-preview-card">
                <div class="talent-card-top">
                  <span class="market-avatar avatar-green">{{ marketplaceHeroProject.clientInitials }}</span>
                  <div>
                    <span class="star-icons">
                      <CheckCircle2 :size="13" fill="currentColor" />
                    </span>
                    <small>{{ marketplaceHeroProject.taskLabel }}</small>
                    <b>{{ marketplaceHeroProject.badge }}</b>
                  </div>
                </div>
                <strong>{{ marketplaceHeroProject.title }}</strong>
                <div class="mini-tags">
                  <span v-for="tag in marketplaceHeroProject.tags.slice(0, 3)" :key="tag">{{ tag }}</span>
                </div>
                <div class="talent-card-bottom">
                  <strong>{{ marketplaceHeroProject.budget }}</strong>
                  <span>{{ marketplaceHeroProject.timeline }}</span>
                </div>
              </article>

              <article class="market-code-card">
                <code>
                  function <span>mergeOS</span>() {<br />
                  &nbsp;&nbsp;return <b>"{{ publicMarketplaceCopy.codeReturn }}"</b>;<br />
                  }
                </code>
              </article>

              <article id="marketplace-agent-preview" class="market-float-card agent-preview-card">
                <div>
                  <span class="agent-icon">
                    <Bot :size="18" />
                  </span>
                  <small>{{ publicMarketplaceCopy.aiAgent }}</small>
                  <button :aria-label="publicMarketplaceCopy.moreAgentActions" type="button" @click="openMarketplaceAgentActions">
                    <MoreHorizontal :size="17" />
                  </button>
                </div>
                <strong>{{ marketplaceHeroAgent.title }}</strong>
                <p>{{ marketplaceHeroAgent.displayBody || marketplaceHeroAgent.body }}</p>
              </article>
            </aside>
          </section>

          <section class="marketplace-filter-panel" :key="`marketplace-filters-${activeLocale}`" :aria-label="publicMarketplaceCopy.searchLabel">
            <label class="marketplace-search">
              <Search :size="18" />
              <input
                :key="`marketplace-search-${activeLocale}`"
                v-model.trim="marketplaceSearch"
                :placeholder="publicMarketplaceCopy.searchPlaceholder"
              />
            </label>

            <div class="marketplace-selects">
              <button :class="{ active: activeMarketplaceCategory !== 'All' }" type="button" @click="cycleMarketplaceCategory">
                {{ publicMarketplaceCopy.categoryPrefix }} {{ marketplaceCategoryLabel(activeMarketplaceCategory) }}
                <ChevronDown :size="14" />
              </button>
              <button :class="{ active: activeMarketplaceBudget !== 'Any budget' }" type="button" @click="cycleMarketplaceBudget">
                {{ marketplaceBudgetLabel(activeMarketplaceBudget) }}
                <ChevronDown :size="14" />
              </button>
              <button :class="{ active: activeMarketplaceDelivery !== 'Any delivery' }" type="button" @click="cycleMarketplaceDelivery">
                {{ marketplaceDeliveryLabel(activeMarketplaceDelivery) }}
                <ChevronDown :size="14" />
              </button>
              <button class="more-filter-button" type="button" @click="clearMarketplaceFilters">
                <Filter :size="15" />
                {{ publicMarketplaceCopy.clearFilters }}
              </button>
            </div>

            <div class="marketplace-categories" role="tablist" :aria-label="publicMarketplaceCopy.categoriesLabel">
              <button
                v-for="category in marketplaceCategories"
                :key="category"
                :class="{ active: category === activeMarketplaceCategory }"
                type="button"
                role="tab"
                @click="activeMarketplaceCategory = category"
              >
                {{ marketplaceCategoryLabel(category) }}
              </button>
            </div>
          </section>

          <section id="marketplace-projects" class="featured-projects-section">
            <div class="section-heading-row">
              <h2>
                <Star :size="17" />
                {{ publicMarketplaceCopy.sections.projects }}
              </h2>
              <div class="marketplace-data-status">
                <span v-if="marketplaceLoading">{{ publicMarketplaceCopy.loadingLiveData }}</span>
                <template v-else-if="marketplaceError">
                  <span>{{ marketplaceError }}</span>
                  <button type="button" @click="loadMarketplaceData">{{ publicMarketplaceCopy.retry }}</button>
                </template>
                <span v-else>{{ marketplaceSummaryLabel }}</span>
              </div>
            </div>

            <div v-if="marketplaceProjectsView.length" class="marketplace-project-grid">
              <article
                v-for="project in marketplaceProjectsView"
                :key="project.id"
                class="marketplace-project-card"
                :style="{ '--project-accent': project.accent, '--project-soft': project.soft }"
              >
                <div class="project-card-top">
                  <span class="project-market-icon">
                    <component :is="project.icon" :size="24" />
                  </span>
                  <span :class="['project-status-badge', project.badgeTone]">{{ project.badge }}</span>
                </div>
                <h3>{{ project.title }}</h3>
                <p>{{ project.body }}</p>
                <div class="project-tag-row">
                  <span v-for="tag in project.tags" :key="tag">{{ tag }}</span>
                  <span v-if="project.extra">+{{ project.extra }}</span>
                </div>
                <div class="project-money-row">
                  <strong>{{ project.budget }}</strong>
                  <span :class="{ urgent: project.urgent }">{{ project.timeline }}</span>
                </div>
                <div class="project-client-row">
                  <span class="market-avatar small" :class="project.avatarTone">{{ project.clientInitials }}</span>
                  <strong>{{ project.client }}</strong>
                  <CheckCircle2 v-if="project.verified" :size="15" />
                  <span class="project-rating">
                    <ListTodo :size="13" />
                    {{ project.taskLabel }}
                  </span>
                </div>
                <div class="project-protocol-row">
                  <button type="button" @click="openExternalURL(project.workflowUrl)">
                    {{ publicMarketplaceCopy.workflow }}
                    <Link2 :size="12" />
                  </button>
                  <button type="button" @click="openExternalURL(project.workflowPulseUrl)">
                    {{ publicMarketplaceCopy.pulse }}
                    <Link2 :size="12" />
                  </button>
                </div>
              </article>
            </div>
            <article v-else class="marketplace-empty-state">
              <strong>{{ marketplaceProjectEmptyState.title }}</strong>
              <p>{{ marketplaceProjectEmptyState.body }}</p>
              <div v-if="marketplaceProjectEmptyActions.length" class="marketplace-empty-actions">
                <button
                  v-for="action in marketplaceProjectEmptyActions"
                  :key="action.label"
                  :class="{ primary: action.primary }"
                  type="button"
                  @click="action.run()"
                >
                  <component :is="action.icon" :size="13" />
                  {{ action.label }}
                </button>
              </div>
            </article>

            <button class="view-projects-button" type="button" @click="loadMarketplaceData">
              {{ publicMarketplaceCopy.refreshLiveData }}
              <ArrowRight :size="15" />
            </button>
          </section>

          <section id="marketplace-bounties" class="marketplace-bounty-section" :aria-label="publicMarketplaceCopy.sections.bounties">
            <div class="section-heading-row">
              <h2>
                <ListTodo :size="17" />
                {{ publicMarketplaceCopy.sections.bounties }}
              </h2>
              <div class="marketplace-data-status">
                <span>{{ marketplaceBountiesView.length }} {{ publicMarketplaceCopy.liveBountyTasks }}</span>
              </div>
            </div>

            <div v-if="marketplaceBountiesView.length" class="marketplace-bounty-list">
              <article v-for="bounty in marketplaceBountiesView" :key="bounty.id">
                <span :class="['marketplace-bounty-icon', bounty.tone]">
                  <component :is="bounty.icon" :size="18" />
                </span>
                <div>
                  <div class="marketplace-bounty-title">
                    <strong>{{ bounty.title }}</strong>
                    <span>{{ bounty.issue }}</span>
                  </div>
                  <p>{{ bounty.acceptance }}</p>
                  <small>{{ bounty.project }} / {{ bounty.lane }}</small>
                </div>
                <div class="marketplace-bounty-meta">
                  <strong>{{ bounty.reward }}</strong>
                  <button
                    class="claim-button"
                    type="button"
                    :disabled="claimingBountyID === bounty.id"
                    @click="claimMarketplaceBounty(bounty)"
                  >
                    {{ claimingBountyID === bounty.id ? publicMarketplaceCopy.claiming : publicMarketplaceCopy.claim }}
                    <GitPullRequest :size="12" />
                  </button>
                  <button v-if="bounty.url" type="button" @click="openExternalURL(bounty.url)">
                    {{ publicMarketplaceCopy.issue }}
                    <Link2 :size="12" />
                  </button>
                  <button type="button" @click="openExternalURL(bounty.protocolUrl)">
                    {{ publicMarketplaceCopy.manifest }}
                    <Bot :size="12" />
                  </button>
                </div>
              </article>
            </div>
            <article v-else class="marketplace-empty-state compact">
              <strong>{{ marketplaceBountyEmptyState.title }}</strong>
              <p>{{ marketplaceBountyEmptyState.body }}</p>
              <div v-if="marketplaceBountyEmptyActions.length" class="marketplace-empty-actions">
                <button
                  v-for="action in marketplaceBountyEmptyActions"
                  :key="action.label"
                  :class="{ primary: action.primary }"
                  type="button"
                  @click="action.run()"
                >
                  <component :is="action.icon" :size="13" />
                  {{ action.label }}
                </button>
              </div>
            </article>
          </section>

          <section id="marketplace-contributor-board" class="marketplace-contributor-board" :aria-label="publicMarketplaceCopy.contributorBoard.title">
            <div class="section-heading-row">
              <div>
                <span class="marketplace-eyebrow">{{ publicMarketplaceCopy.contributorBoard.eyebrow }}</span>
                <h2>
                  <UsersRound :size="17" />
                  {{ publicMarketplaceCopy.contributorBoard.title }}
                </h2>
                <p>{{ publicMarketplaceCopy.contributorBoard.body }}</p>
              </div>
              <div class="marketplace-data-status">
                <span>{{ marketplaceContributorBoardSummary }}</span>
              </div>
            </div>

            <div v-if="marketplaceContributorBoardRows.length" class="marketplace-contributor-grid">
              <article v-for="contributor in marketplaceContributorBoardRows" :key="contributor.workerId">
                <div class="marketplace-contributor-top">
                  <span :class="['market-avatar', contributor.tone]">{{ contributor.initials }}</span>
                  <div>
                    <strong>{{ contributor.name }}</strong>
                    <small>{{ contributor.role }}</small>
                  </div>
                  <b :class="contributor.statusTone">{{ contributor.status }}</b>
                </div>
                <div class="marketplace-contributor-stats">
                  <span>
                    <small>{{ publicMarketplaceCopy.contributorBoard.acceptedLabel }}</small>
                    <strong>{{ contributor.taskCount }}</strong>
                  </span>
                  <span>
                    <small>{{ publicMarketplaceCopy.contributorBoard.earnedLabel }}</small>
                    <strong>{{ contributor.earned }}</strong>
                  </span>
                  <span>
                    <small>{{ publicMarketplaceCopy.contributorBoard.reputationLabel }}</small>
                    <strong>{{ contributor.reputation }}</strong>
                  </span>
                </div>
                <div class="marketplace-contributor-proof">
                  <span :class="['notification-dot', contributor.riskTone]" />
                  <small>{{ contributor.riskLabel }}</small>
                  <small>{{ contributor.lastPaidLabel }}</small>
                </div>
              </article>
            </div>

            <article v-else class="marketplace-empty-state compact">
              <strong>{{ publicMarketplaceCopy.contributorBoard.emptyTitle }}</strong>
              <p>{{ publicMarketplaceCopy.contributorBoard.emptyBody }}</p>
              <div class="marketplace-empty-actions">
                <button class="primary" type="button" @click="openPublicPage('live')">
                  <Zap :size="13" />
                  {{ publicMarketplaceCopy.contributorBoard.liveAction }}
                </button>
                <button type="button" @click="loadMarketplaceData">
                  <RefreshCw :size="13" />
                  {{ publicMarketplaceCopy.refreshLiveData }}
                </button>
              </div>
            </article>
          </section>

          <section id="marketplace-agents" class="marketplace-agent-section" :aria-label="publicMarketplaceCopy.sections.agents">
            <div class="section-heading-row">
              <h2>
                <Bot :size="17" />
                {{ publicMarketplaceCopy.sections.agents }}
              </h2>
              <div class="marketplace-data-status">
                <span>{{ marketplaceAgentSummaryLabel }}</span>
              </div>
            </div>

            <section class="marketplace-agent-matrix" :aria-labelledby="marketplaceAgentCapabilityMatrix.titleId">
              <div class="marketplace-agent-matrix-copy">
                <span class="marketplace-eyebrow">{{ marketplaceAgentCapabilityMatrix.eyebrow }}</span>
                <h3 :id="marketplaceAgentCapabilityMatrix.titleId">{{ marketplaceAgentCapabilityMatrix.title }}</h3>
                <p>{{ marketplaceAgentCapabilityMatrix.body }}</p>
                <div class="marketplace-agent-matrix-actions">
                  <button type="button" @click="routeMarketplaceAgent()">
                    <Sparkles :size="13" />
                    {{ marketplaceAgentCapabilityMatrix.primaryAction }}
                  </button>
                  <button type="button" @click="openMarketplaceAgentActions">
                    <ListTodo :size="13" />
                    {{ marketplaceAgentCapabilityMatrix.secondaryAction }}
                  </button>
                </div>
              </div>
              <div class="marketplace-agent-matrix-grid">
                <article v-for="lane in marketplaceAgentCapabilityMatrix.rows" :key="lane.key">
                  <div class="marketplace-agent-matrix-head">
                    <span :class="['public-card-icon', lane.tone]">
                      <component :is="lane.icon" :size="17" />
                    </span>
                    <div>
                      <strong>{{ lane.title }}</strong>
                      <p>{{ lane.body }}</p>
                    </div>
                  </div>
                  <dl>
                    <div>
                      <dt>{{ marketplaceAgentCapabilityMatrix.inputLabel }}</dt>
                      <dd>{{ lane.input }}</dd>
                    </div>
                    <div>
                      <dt>{{ marketplaceAgentCapabilityMatrix.outputLabel }}</dt>
                      <dd>{{ lane.output }}</dd>
                    </div>
                    <div>
                      <dt>{{ marketplaceAgentCapabilityMatrix.evidenceLabel }}</dt>
                      <dd>{{ lane.evidence }}</dd>
                    </div>
                  </dl>
                </article>
              </div>
            </section>

            <section class="marketplace-agent-packets" :aria-labelledby="marketplaceAgentWorkPackets.titleId">
              <div class="marketplace-agent-packets-head">
                <div>
                  <span class="marketplace-eyebrow">{{ marketplaceAgentWorkPackets.eyebrow }}</span>
                  <h3 :id="marketplaceAgentWorkPackets.titleId">{{ marketplaceAgentWorkPackets.title }}</h3>
                  <p>{{ marketplaceAgentWorkPackets.body }}</p>
                </div>
                <button type="button" :disabled="agentQueueLoading" @click="loadMarketplaceData">
                  <RefreshCw :class="{ 'loading-spin': agentQueueLoading }" :size="13" />
                  {{ publicMarketplaceCopy.refreshLiveData }}
                </button>
              </div>
              <div v-if="marketplaceAgentWorkPacketRows.length" class="marketplace-agent-packet-grid">
                <article v-for="packet in marketplaceAgentWorkPacketRows" :key="packet.id">
                  <div class="marketplace-agent-packet-top">
                    <span :class="['popular-agent-icon', packet.tone]">
                      <component :is="packet.icon" :size="20" />
                    </span>
                    <div>
                      <strong>{{ packet.issue }} {{ packet.title }}</strong>
                      <small>{{ packet.project }} / {{ packet.lane }} / {{ packet.reward }}</small>
                    </div>
                    <b>{{ packet.readiness }}</b>
                  </div>
                  <p>{{ packet.summary }}</p>
                  <div class="marketplace-agent-packet-stats">
                    <span>
                      <small>{{ marketplaceAgentWorkPackets.contextLabel }}</small>
                      <strong>{{ packet.contextRows.length }}</strong>
                    </span>
                    <span>
                      <small>{{ marketplaceAgentWorkPackets.actionsLabel }}</small>
                      <strong>{{ packet.actionCount }}</strong>
                    </span>
                    <span>
                      <small>{{ marketplaceAgentWorkPackets.runbookLabel }}</small>
                      <strong>{{ packet.runbookCount }}</strong>
                    </span>
                    <span>
                      <small>{{ marketplaceAgentWorkPackets.evidenceLabel }}</small>
                      <strong>{{ packet.evidenceCount }}</strong>
                    </span>
                  </div>
                  <div v-if="packet.contextRows.length" class="marketplace-agent-context-row">
                    <a v-for="context in packet.contextRows" :key="context.label" :href="context.href" target="_blank" rel="noreferrer">
                      <component :is="context.icon" :size="12" />
                      {{ context.label }}
                    </a>
                  </div>
                  <ol v-if="packet.runbookRows.length" class="marketplace-agent-runbook">
                    <li v-for="step in packet.runbookRows" :key="step.key">
                      <b>{{ step.step }}</b>
                      <span>{{ step.label }}</span>
                      <small>{{ step.method }} {{ step.endpoint }}</small>
                    </li>
                  </ol>
                  <div v-if="packet.actionRows.length" class="marketplace-agent-action-row">
                    <span v-for="action in packet.actionRows" :key="action.key">
                      <Sparkles :size="12" />
                      {{ action.label }}
                    </span>
                  </div>
                </article>
              </div>
              <article v-else class="marketplace-empty-state compact">
                <strong>{{ marketplaceAgentWorkPackets.emptyTitle }}</strong>
                <p>{{ marketplaceLoading || agentQueueLoading ? marketplaceAgentWorkPackets.loadingBody : marketplaceAgentWorkPackets.emptyBody }}</p>
                <div class="marketplace-empty-actions">
                  <button class="primary" type="button" @click="openProjectWizard">
                    <Plus :size="13" />
                    {{ publicMarketplaceCopy.postProject }}
                  </button>
                  <button type="button" @click="openRepositoryImportEntry">
                    <GitBranch :size="13" />
                    {{ publicMarketplaceCopy.emptyActions.importRepo }}
                  </button>
                </div>
              </article>
            </section>

            <div v-if="marketplaceAgentSectionRows.length" class="marketplace-agent-grid">
              <article v-for="agent in marketplaceAgentSectionRows" :key="agent.type">
                <div class="marketplace-agent-top">
                  <span :class="['popular-agent-icon', agent.tone]">
                    <component :is="agent.icon" :size="22" />
                  </span>
                  <b :class="agent.statusTone">{{ agent.status }}</b>
                </div>
                <h3>{{ agent.title }}</h3>
                <p>{{ agent.capability }}</p>
                <div class="marketplace-agent-capabilities" :aria-label="publicMarketplaceCopy.agentCapabilityLabel || publicMarketplaceTranslations['en-US'].agentCapabilityLabel">
                  <span v-for="capability in agent.capabilities" :key="capability.key" :class="{ active: capability.active }">
                    <component :is="capability.icon" :size="12" />
                    {{ capability.label }}
                  </span>
                </div>
                <div class="marketplace-agent-stats">
                  <span>
                    <small>{{ publicMarketplaceCopy.openTasks }}</small>
                    <strong>{{ agent.openTaskCount }}</strong>
                  </span>
                  <span>
                    <small>{{ publicMarketplaceCopy.rewardPool }}</small>
                    <strong>{{ agent.rewardLabel }}</strong>
                  </span>
                  <span>
                    <small>{{ publicMarketplaceCopy.capacity }}</small>
                    <strong>{{ agent.capacityLabel }}</strong>
                  </span>
                </div>
                <div v-if="agent.chips.length" class="marketplace-agent-chip-row">
                  <span v-for="chip in agent.chips" :key="chip">{{ chip }}</span>
                </div>
                <div class="marketplace-agent-actions">
                  <button type="button" @click="routeMarketplaceAgent(agent)">
                    <Sparkles :size="13" />
                    {{ publicMarketplaceCopy.routeWork }}
                  </button>
                  <button type="button" @click="openMarketplaceAgentActions">
                    <ListTodo :size="13" />
                    {{ publicMarketplaceCopy.queue }}
                  </button>
                </div>
              </article>
            </div>
            <article v-else class="marketplace-empty-state compact">
              <strong>{{ marketplaceAgentEmptyState.title }}</strong>
              <p>{{ marketplaceAgentEmptyState.body }}</p>
              <div v-if="marketplaceAgentEmptyActions.length" class="marketplace-empty-actions">
                <button
                  v-for="action in marketplaceAgentEmptyActions"
                  :key="action.label"
                  :class="{ primary: action.primary }"
                  type="button"
                  @click="action.run()"
                >
                  <component :is="action.icon" :size="13" />
                  {{ action.label }}
                </button>
              </div>
            </article>
          </section>

          <section id="marketplace-benefits" class="marketplace-benefit-strip" :aria-label="publicMarketplaceCopy.sections.benefits">
            <article v-for="benefit in marketplaceBenefits" :key="benefit.title">
              <span>
                <component :is="benefit.icon" :size="23" />
              </span>
              <div>
                <strong>{{ benefit.title }}</strong>
                <p>{{ benefit.body }}</p>
              </div>
            </article>
          </section>
        </section>

        <aside class="marketplace-rail">
          <section id="marketplace-contributors" class="marketplace-side-card">
            <div class="side-card-head">
              <h2>{{ publicMarketplaceCopy.sections.contributors }}</h2>
              <button type="button" @click="openMarketplaceSection('marketplace-contributors')">{{ publicMarketplaceCopy.viewAll }}</button>
            </div>
            <div class="contributor-list">
              <article v-for="contributor in marketplaceContributorsView" :key="contributor.workerId">
                <span>{{ contributor.rank }}</span>
                <span class="market-avatar small" :class="contributor.tone">{{ contributor.initials }}</span>
                <div>
                  <strong>{{ contributor.name }}</strong>
                  <small>{{ contributor.role }}</small>
                  <small>{{ contributor.earnedLabel }}</small>
                </div>
              </article>
              <article v-if="!marketplaceContributorsView.length" class="marketplace-side-empty">
                <div>
                  <strong>{{ publicMarketplaceCopy.noPayoutsTitle }}</strong>
                  <small>{{ publicMarketplaceCopy.noPayoutsBody }}</small>
                </div>
              </article>
            </div>
          </section>

          <section class="marketplace-side-card">
            <div class="side-card-head">
              <h2>{{ publicMarketplaceCopy.sections.workQueue }}</h2>
              <button type="button" @click="loadMarketplaceData">{{ publicMarketplaceCopy.refresh }}</button>
            </div>
            <div class="agent-list">
              <article v-for="agent in marketplaceAgentsView" :key="agent.type">
                <span :class="['popular-agent-icon', agent.tone]">
                  <component :is="agent.icon" :size="21" />
                </span>
                <div>
                  <strong>{{ agent.title }}</strong>
                  <small>{{ agent.displayBody || agent.body }}</small>
                  <small class="agent-status-label">{{ agent.status }}</small>
                </div>
              </article>
              <article v-if="!marketplaceAgentsView.length" class="marketplace-side-empty">
                <div>
                  <strong>{{ publicMarketplaceCopy.noAgentTasksTitle }}</strong>
                  <small>{{ publicMarketplaceCopy.noAgentTasksBody }}</small>
                </div>
              </article>
            </div>
          </section>
        </aside>
      </div>
    </main>

    <div v-if="repoTaskFundingVisible" class="modal-backdrop repo-task-funding-backdrop" role="presentation" @click.self="closeRepositoryTaskFunding">
      <section class="repo-task-funding-modal" role="dialog" aria-modal="true" aria-labelledby="repo-task-funding-title" tabindex="-1" @keydown.esc="closeRepositoryTaskFunding">
        <header class="repo-task-funding-head">
          <div>
            <span>
              <CircleDollarSign :size="15" />
              Repository bounty funding
            </span>
            <h2 id="repo-task-funding-title">{{ repoTaskFundingTask?.title || 'Fund suggested task' }}</h2>
            <p>{{ repoTaskFundingTask?.fundingHint || 'Reserve escrow for this repository task and publish it to the marketplace.' }}</p>
          </div>
          <button class="auth-close-button" type="button" aria-label="Close repository task funding" @click="closeRepositoryTaskFunding">
            <X :size="20" />
          </button>
        </header>

        <div v-if="repoTaskFundingShouldShowErrors && repoTaskFundingValidationList.length" class="wizard-validation-banner repo-task-funding-validation" role="alert">
          <strong>Fix funding details</strong>
          <ul>
            <li v-for="item in repoTaskFundingValidationList" :key="item.field">{{ item.message }}</li>
          </ul>
        </div>

        <section class="repo-task-funding-summary">
          <article>
            <small>Escrow funding</small>
            <strong>{{ repoTaskFundingAmountLabel }}</strong>
          </article>
          <article>
            <small>Task reward</small>
            <strong>{{ repoTaskFundingRewardLabel }}</strong>
          </article>
          <article>
            <small>Evidence gate</small>
            <strong>{{ repoTaskFundingEvidenceLabel }}</strong>
          </article>
        </section>

        <section class="repo-task-evidence-panel" aria-label="Evidence required before release">
          <div>
            <strong>Release conditions</strong>
            <small>Payout stays locked until review evidence satisfies these checks.</small>
          </div>
          <ul>
            <li v-for="item in repoTaskFundingEvidenceChecklist" :key="item">
              <CheckCircle2 :size="13" />
              <span>{{ item }}</span>
            </li>
          </ul>
        </section>

        <section class="wizard-section full" :class="{ invalid: repoTaskFundingFieldError('paymentMethod') }">
          <div class="wizard-section-title">
            <strong>Payment method</strong>
            <small>Verify funding before the task becomes claimable.</small>
          </div>
          <div class="payment-choice-grid repo-task-payment-grid">
            <button
              v-for="method in paymentMethodOptions"
              :key="method.label"
              :class="{ selected: repoTaskFundingMethod === method.label }"
              class="select-tile horizontal rich"
              type="button"
              @click="repoTaskFundingMethod = method.label"
            >
              <component :is="method.icon" :size="18" />
              <span>
                <strong>{{ method.label }}</strong>
                <small>{{ method.caption }}</small>
              </span>
            </button>
          </div>
          <p v-if="repoTaskFundingFieldError('paymentMethod')" class="wizard-field-error">{{ repoTaskFundingFieldError('paymentMethod') }}</p>
        </section>

        <div v-if="repoTaskFundingMethod === 'Credit / Debit card'" class="card-input-grid repo-task-card-grid">
          <label class="wizard-field full" :class="{ invalid: repoTaskFundingFieldError('cardNumber') }">
            <span>Card number</span>
            <input v-model.trim="repoTaskFundingCardForm.cardNumber" autocomplete="cc-number" inputmode="numeric" placeholder="4242 4242 4242 4242" />
            <p v-if="repoTaskFundingFieldError('cardNumber')" class="wizard-field-error">{{ repoTaskFundingFieldError('cardNumber') }}</p>
          </label>
          <label class="wizard-field" :class="{ invalid: repoTaskFundingFieldError('cardExpiry') }">
            <span>Expiry date</span>
            <input v-model.trim="repoTaskFundingCardForm.expiry" autocomplete="cc-exp" inputmode="numeric" placeholder="MM / YY" />
            <p v-if="repoTaskFundingFieldError('cardExpiry')" class="wizard-field-error">{{ repoTaskFundingFieldError('cardExpiry') }}</p>
          </label>
          <label class="wizard-field" :class="{ invalid: repoTaskFundingFieldError('cardCvc') }">
            <span>CVC</span>
            <input v-model.trim="repoTaskFundingCardForm.cvc" autocomplete="cc-csc" inputmode="numeric" placeholder="CVC" />
            <p v-if="repoTaskFundingFieldError('cardCvc')" class="wizard-field-error">{{ repoTaskFundingFieldError('cardCvc') }}</p>
          </label>
          <label class="wizard-field" :class="{ invalid: repoTaskFundingFieldError('cardholderName') }">
            <span>Cardholder name</span>
            <input v-model.trim="repoTaskFundingCardForm.cardholderName" autocomplete="cc-name" placeholder="Name on card" />
            <p v-if="repoTaskFundingFieldError('cardholderName')" class="wizard-field-error">{{ repoTaskFundingFieldError('cardholderName') }}</p>
          </label>
        </div>

        <div v-else-if="repoTaskFundingMethod === 'USDC'" class="payment-reference-box">
          <label class="wizard-field full" :class="{ invalid: repoTaskFundingFieldError('cryptoReference') }">
            <span>Solana signature</span>
