const props = defineProps({
  initialPath: { type: String, default: '' },
});

function normalizeRoutePath(path = '/') {
  const pathname = String(path || '/').split('?')[0].split('#')[0] || '/';
  const normalized = pathname.replace(/\/+$/, '') || '/';
  return normalized.startsWith('/') ? normalized : `/${normalized}`;
}

function normalizePublicPage(page = 'home') {
  return publicPageNames.has(page) ? page : 'home';
}

function publicPageFromPath(path = '/') {
  const normalizedPath = normalizeRoutePath(path);
  const match = Object.entries(publicPagePaths).find(([, routePath]) => routePath === normalizedPath);
  if (match) return match[0];
  const aliasMatch = Object.entries(publicPagePathAliases).find(([, aliases]) =>
    aliases.some((alias) => normalizeRoutePath(alias) === normalizedPath),
  );
  if (aliasMatch) return aliasMatch[0];
  return match?.[0] || 'home';
}

function publicPathForPage(page = 'home') {
  return publicPagePaths[normalizePublicPage(page)] || '/';
}

function normalizeProjectWizardStep(step = 1) {
  return Math.min(4, Math.max(1, Number(step) || 1));
}

function projectWizardRouteFromPath(path = '/') {
  const normalizedPath = normalizeRoutePath(path);
  const stepMatch = Object.entries(projectWizardStepPaths).find(([, routePath]) => routePath === normalizedPath);
  if (stepMatch) return { stage: 'setup', step: Number(stepMatch[0]) };
  if (normalizedPath === '/project/new/details' || normalizedPath === '/projects/new') return { stage: 'setup', step: 1 };
  if (normalizedPath === projectWizardStagePaths.funding) return { stage: 'funding', step: 4 };
  if (normalizedPath === projectWizardStagePaths.success) return { stage: 'success', step: 4 };
  return null;
}

function projectWizardPathForState(stage = 'setup', step = 1) {
  if (stage === 'funding') return projectWizardStagePaths.funding;
  if (stage === 'success') return projectWizardStagePaths.success;
  return projectWizardStepPaths[normalizeProjectWizardStep(step)] || projectWizardStepPaths[1];
}

function getBrowserStorage() {
  if (!hasWindow || !('localStorage' in window)) {
    return null;
  }
  try {
    return window.localStorage;
  } catch {
    return null;
  }
}

const browserStorage = getBrowserStorage();

function readStoredToken() {
  try {
    return browserStorage?.getItem('mergeos_token') || '';
  } catch {
    return '';
  }
}

function writeStoredToken(value) {
  try {
    browserStorage?.setItem('mergeos_token', value);
  } catch {
    // Storage can be disabled in embedded browsers; auth still works for this session.
  }
}

function removeStoredToken() {
  try {
    browserStorage?.removeItem('mergeos_token');
  } catch {
    // Ignore storage failures so logout never leaves the UI stuck.
  }
}

function readStoredLocale() {
  try {
    const stored = browserStorage?.getItem(localeStorageKey) || '';
    return localeOptions.some((option) => option.code === stored) ? stored : 'en-US';
  } catch {
    return 'en-US';
  }
}

function writeStoredLocale(value) {
  try {
    browserStorage?.setItem(localeStorageKey, value);
  } catch {
    // Locale preference is best-effort and should not block navigation.
  }
}

function isLocaleMergeObject(value) {
  return Boolean(value && typeof value === 'object' && !Array.isArray(value));
}

function mergeLocaleCopy(base = {}, override = {}) {
  if (!isLocaleMergeObject(base)) {
    return override === undefined ? base : override;
  }
  const merged = { ...base };
  Object.entries(override || {}).forEach(([key, value]) => {
    const baseValue = base[key];
    merged[key] = isLocaleMergeObject(baseValue) && isLocaleMergeObject(value)
      ? mergeLocaleCopy(baseValue, value)
      : value;
  });
  return merged;
}

function localizedLocaleCopy(translations = {}, localeCode = 'en-US') {
  return mergeLocaleCopy(translations['en-US'] || {}, translations[localeCode] || {});
}

function writePendingProjectFunding(value = {}) {
  try {
    browserStorage?.setItem(pendingProjectFundingStorageKey, JSON.stringify(value));
  } catch {
    // The project checkout can be restarted if browser storage is unavailable.
  }
}

function readPendingProjectFunding() {
  try {
    const raw = browserStorage?.getItem(pendingProjectFundingStorageKey);
    return raw ? JSON.parse(raw) : null;
  } catch {
    return null;
  }
}

function clearPendingProjectFunding() {
  try {
    browserStorage?.removeItem(pendingProjectFundingStorageKey);
  } catch {
    // Ignore storage failures; this only affects retry convenience.
  }
}

function writePendingRepositoryTaskFunding(value = {}) {
  try {
    browserStorage?.setItem(pendingRepositoryTaskFundingStorageKey, JSON.stringify(value));
  } catch {
    // The funding flow can still be retried if browser storage is unavailable.
  }
}

function readPendingRepositoryTaskFunding() {
  try {
    const raw = browserStorage?.getItem(pendingRepositoryTaskFundingStorageKey);
    return raw ? JSON.parse(raw) : null;
  } catch {
    return null;
  }
}

function clearPendingRepositoryTaskFunding() {
  try {
    browserStorage?.removeItem(pendingRepositoryTaskFundingStorageKey);
  } catch {
    // Ignore storage failures; pending checkout state is best-effort UI state.
  }
}

