const liveFeedAllItemsView = computed(() =>
  (liveFeedData.value.items || [])
    .map(mapPublicLiveFeedItem)
    .sort((a, b) => (Date.parse(b.createdAt || '') || 0) - (Date.parse(a.createdAt || '') || 0)),
);
const liveFeedTypeOptions = computed(() => {
  const counts = new Map();
  for (const item of liveFeedAllItemsView.value) {
    counts.set(item.typeLabel, (counts.get(item.typeLabel) || 0) + 1);
  }
  const coreLabels = new Set(liveFeedCoreTypeOptions.map((row) => row.label));
  const coreRows = liveFeedCoreTypeOptions.map((row) => ({
    ...row,
    count: counts.get(row.label) || 0,
  }));
  const extraRows = Array.from(counts.entries())
    .filter(([label]) => !coreLabels.has(label))
    .slice(0, 8)
    .map(([label, count], index) => ({
      label,
      count,
      tone: ['green', 'blue', 'purple', 'amber', 'slate', 'green', 'blue', 'purple'][index % 8],
    }));
  return [
    { label: 'All activity', count: liveFeedAllItemsView.value.length, tone: 'green' },
    ...coreRows,
    ...extraRows,
  ];
});
const liveFeedItemsView = computed(() => {
  if (activeLiveFeedType.value === 'All activity') return liveFeedAllItemsView.value;
  return liveFeedAllItemsView.value.filter((item) => item.typeLabel === activeLiveFeedType.value);
});
const liveFeedResultLabel = computed(() => {
  const visible = liveFeedItemsView.value.length;
  const total = liveFeedAllItemsView.value.length;
  if (!total) return 'Waiting for public realtime events';
  if (activeLiveFeedType.value === 'All activity') return `${total} live event${total === 1 ? '' : 's'} visible`;
  return `${visible} of ${total} events match ${activeLiveFeedType.value}`;
});
