const publicDeliveryVerificationCopy = computed(() =>
  publicDeliveryVerificationTranslations[activeLocale.value] || publicDeliveryVerificationTranslations['en-US'],
);

const publicDeliveryVerificationGateDefinitions = [
  {
    key: 'pr-evidence',
    icon: GitPullRequest,
    tone: 'green',
    rawTypes: ['task_submitted', 'task_accepted'],
    fallbackFilter: 'Review Submitted',
    ledgerPredicate: (item) => String(item.type || '').startsWith('task_') || /pull request|pr accepted|review submitted|workflow event/i.test(ledgerProofItemText(item)),
  },
  {
    key: 'deployment-gate',
    icon: Rocket,
    tone: 'blue',
    rawTypes: ['deployment_validation', 'deployment_status'],
    fallbackFilter: 'Deployment Validation',
    ledgerPredicate: (item) => /deployment|release gate|environment|rollout|qa handoff/i.test(ledgerProofItemText(item)),
  },
  {
    key: 'ai-review',
    icon: Bot,
    tone: 'purple',
    rawTypes: ['ai_review', 'agent_action'],
    fallbackFilter: 'AI Review',
    ledgerPredicate: (item) => /ai_review|agent_action|ai review|agent action|agent proof|security|test/i.test(ledgerProofItemText(item)),
  },
  {
    key: 'payout-proof',
    icon: ShieldCheck,
    tone: 'amber',
    fallbackFilter: 'Project Funded',
    predicate: (item) => (
      item.rawType === 'task_accepted'
      || item.rawType.startsWith('ledger_')
      || /payment|payout|escrow|release|mint/i.test(`${item.rawType} ${item.typeLabel} ${item.title}`)
    ),
    ledgerPredicate: (item) => /task_payment|payment|reserve|escrow|release|payout|token_mint|platform_fee/i.test(ledgerProofItemText(item)),
  },
];

function publicDeliveryVerificationEventLabel(count = 0) {
  const copy = publicDeliveryVerificationCopy.value;
  return `${count} ${count === 1 ? copy.eventSingular : copy.eventPlural}`;
}

function deliveryVerificationLedgerLatestLabel(item = null) {
  if (!item) return publicDeliveryVerificationCopy.value.proofPending;
  const project = ledgerProjectFilterLabel(item);
  const when = item.created_at ? formatLedgerDateTime(item.created_at).time : '';
  return [project, when].filter(Boolean).join(' / ') || publicDeliveryVerificationCopy.value.proofPending;
}

const publicDeliveryVerificationGateRows = computed(() => {
  const copy = publicDeliveryVerificationCopy.value;
  return publicDeliveryVerificationGateDefinitions.map((definition, index) => {
    const liveRows = liveFeedAllItemsView.value.filter((item) => liveFeedLaneMatches(item, definition));
    const ledgerRows = ledgerEventItems.value
      .filter((item) => definition.ledgerPredicate?.(item))
      .sort((a, b) => (Date.parse(b.created_at || '') || 0) - (Date.parse(a.created_at || '') || 0));
    const latest = liveRows[0] || null;
    const latestLedger = ledgerRows[0] || null;
    const translated = copy.gates[index] || [];
    const ready = Boolean(liveRows.length || ledgerRows.length);
    return {
      ...definition,
      sequence: String(index + 1).padStart(2, '0'),
      title: translated[0] || definition.key,
      body: translated[1] || '',
      ready,
      liveCount: liveRows.length,
      ledgerCount: ledgerRows.length,
      liveLabel: publicDeliveryVerificationEventLabel(liveRows.length),
      ledgerLabel: publicDeliveryVerificationEventLabel(ledgerRows.length),
      latestLabel: latest ? `${latest.typeLabel} / ${latest.project} / ${latest.time}` : deliveryVerificationLedgerLatestLabel(latestLedger),
      filterLabel: latest?.typeLabel || definition.fallbackFilter,
      actionLabel: liveRows.length ? copy.filterTimeline : copy.waitingAction,
      status: ready ? copy.live : copy.waiting,
      statusTone: ready ? definition.tone : 'slate',
      icon: definition.icon,
      tone: definition.tone,
    };
  });
});

const publicDeliveryVerificationStats = computed(() => {
  const copy = publicDeliveryVerificationCopy.value;
  return publicDeliveryVerificationGateRows.value.map((gate, index) => ({
    label: gate.title,
    value: String(gate.liveCount + gate.ledgerCount),
    caption: copy.statsCaptions[index] || gate.latestLabel,
    icon: gate.icon,
    tone: gate.tone,
  }));
});

const publicDeliveryVerificationEvidenceRows = computed(() => {
  const liveRows = liveFeedAllItemsView.value
    .filter((item) => publicDeliveryVerificationGateDefinitions.some((definition) => liveFeedLaneMatches(item, definition)))
    .slice(0, 6)
    .map((item) => ({
      key: `live-${item.id}`,
      title: item.title,
      body: item.body,
      meta: `${item.typeLabel} / ${item.project} / ${item.actor} / ${item.time}`,
      proof: item.contractReference || item.reference || publicDeliveryVerificationCopy.value.proofPending,
      icon: item.icon || GitPullRequest,
      tone: item.tone || 'blue',
    }));
  if (liveRows.length) return liveRows;
  return ledgerEventItems.value
    .filter((item) => publicDeliveryVerificationGateDefinitions.some((definition) => definition.ledgerPredicate?.(item)))
    .slice(0, 4)
    .map((item, index) => {
      const event = mapLedgerTransparencyEvent(item);
      return {
        key: `ledger-${item.id || item.sequence || index}`,
        title: event.title,
        body: event.body,
        meta: `${event.type} / ${event.project} / ${event.when}`,
        proof: event.ref || publicDeliveryVerificationCopy.value.proofPending,
        icon: event.icon || ShieldCheck,
        tone: event.tone || 'green',
      };
    });
});

const publicDeliveryVerificationAnchorRows = computed(() => {
  const copy = publicDeliveryVerificationCopy.value;
  return publicDeliveryVerificationGateRows.value.map((gate, index) => ({
    key: `anchor-${gate.key}`,
    title: copy.anchors[index] || gate.title,
    countLabel: `${gate.ledgerLabel} / ${gate.latestLabel}`,
    status: gate.ledgerCount ? copy.covered : copy.waiting,
    statusTone: gate.ledgerCount ? gate.tone : 'slate',
    icon: gate.icon,
    tone: gate.tone,
  }));
});

const liveFeedLatestProject = computed(() =>
