  return {
    schemas: Number(stats.schema_count) || protocolDocumentRowsRaw.value.length,
    endpoints: Number(stats.public_endpoint_count) || protocolEndpointRowsRaw.value.length,
    contexts: Number(stats.agent_context_url_count) || Object.keys(protocolAgentContextMap.value).length,
    realtime: Number(stats.realtime_stream_count) || (protocolManifestView.value.realtime?.websocket_path ? 1 : 0),
