    { label: actions.refreshLiveData, icon: RefreshCw, primary: false, run: () => loadMarketplaceData() },
  ];
});
const marketplaceSummaryLabel = computed(() => {
  const stats = marketplaceStats.value;
  const projects = Number(stats.project_count) || marketplaceData.value.projects?.length || 0;
  const tasks = Number(stats.open_task_count) || 0;
  const labels = publicMarketplaceCopy.value.summarySuffix;
  return `${projects} ${labels.liveProjects} / ${tasks} ${labels.openTasks} / ${formatPublicMRGFromCents(stats.total_budget_cents)} ${labels.verified}`;
});
const marketplaceHeroProject = computed(() => marketplaceProjectsView.value[0] || emptyMarketplaceProjectView.value);
const marketplaceContributorsView = computed(() =>
  (marketplaceData.value.contributors || []).map((contributor, index) => ({
    rank: index + 1,
    workerId: contributor.worker_id || contributor.name || `contributor-${index}`,
    initials: initialsFor(contributor.name || contributor.worker_id || 'FW'),
    name: contributor.name || contributor.worker_id || 'Contributor',
    role: contributor.agent_type ? toTitleLabel(contributor.agent_type) : toTitleLabel(contributor.kind || 'human contributor'),
    earned: formatPublicMRGFromCents(contributor.earned_cents),
    earnedLabel: `${formatPublicMRGFromCents(contributor.earned_cents)} ${publicMarketplaceCopy.value.earnedSuffix}`,
    tone: marketplaceAvatarTones[index % marketplaceAvatarTones.length],
  })),
);
const marketplaceHasContributorRows = computed(() => (marketplaceData.value.contributors || []).length > 0);
const marketplaceContributorBoardRows = computed(() => {
  const query = marketplaceSearch.value.toLowerCase();
  const active = activeMarketplaceCategory.value;
  const copy = publicMarketplaceCopy.value.contributorBoard;
  return (marketplaceData.value.contributors || [])
    .filter((contributor) => {
      const role = contributor.agent_type ? toTitleLabel(contributor.agent_type) : toTitleLabel(contributor.kind || 'human contributor');
      const flags = Array.isArray(contributor.flags) ? contributor.flags.map(toTitleLabel) : [];
      const haystack = [
        contributor.worker_id,
        contributor.name,
        contributor.kind,
        contributor.agent_type,
        contributor.reputation_level,
        contributor.risk_level,
        ...flags,
      ].filter(Boolean).join(' ').toLowerCase();
      const matchesSearch = !query || haystack.includes(query);
      const matchesCategory = active === 'All'
        || role.includes(active)
        || flags.includes(active)
        || toTitleLabel(contributor.reputation_level).includes(active);
      return matchesSearch && matchesCategory && matchesMarketplaceBudget(contributor.earned_cents);
    })
    .slice(0, 6)
    .map((contributor, index) => {
      const workerId = contributor.worker_id || contributor.name || `contributor-${index}`;
      const displaySeed = contributor.name || workerId;
      const displayName = (/^0x/i.test(displaySeed) ? shortWallet(displaySeed) : displaySeed) || copy.nameFallback;
      const taskCount = Number(contributor.task_count) || 0;
      const earnedCents = Number(contributor.earned_cents) || 0;
      const reputationScore = Number(contributor.reputation_score) || 0;
      const reputationLevel = toTitleLabel(contributor.reputation_level || copy.reputationFallback);
      const riskLevel = toTitleLabel(contributor.risk_level || copy.riskFallback);
      const riskText = String(contributor.risk_level || '').toLowerCase();
      const lastPaidAt = contributor.last_paid_at ? new Date(contributor.last_paid_at) : null;
      const hasPaidDate = Boolean(lastPaidAt && !Number.isNaN(lastPaidAt.getTime()) && lastPaidAt.getUTCFullYear() > 2001);
      const paidDate = hasPaidDate ? formatLedgerDateTime(lastPaidAt).date : '';
      return {
        workerId,
        initials: initialsFor(displayName || 'FW'),
        name: displayName,
        role: contributor.agent_type ? toTitleLabel(contributor.agent_type) : toTitleLabel(contributor.kind || 'human contributor'),
        taskCount,
        earnedCents,
        earned: formatPublicMRGFromCents(earnedCents),
        reputation: reputationScore ? `${reputationLevel} ${reputationScore}` : reputationLevel,
        riskLabel: `${copy.riskLabel}: ${riskLevel}`,
        riskTone: riskText.includes('high') ? 'red' : (riskText.includes('medium') ? 'amber' : 'green'),
        lastPaidLabel: paidDate ? `${copy.lastPaidLabel} ${paidDate}` : copy.waitingForPayout,
        status: taskCount > 0 ? copy.paidStatus : copy.readyStatus,
        statusTone: taskCount > 0 ? 'green' : 'slate',
        tone: marketplaceAvatarTones[index % marketplaceAvatarTones.length],
      };
    });
});
const marketplaceContributorBoardSummary = computed(() => {
  const copy = publicMarketplaceCopy.value.contributorBoard;
  if (marketplaceLoading.value) return copy.loading;
  if (marketplaceFiltersActive.value && marketplaceHasContributorRows.value && !marketplaceContributorBoardRows.value.length) {
    return copy.filtered;
  }
  const rows = marketplaceContributorBoardRows.value;
  const taskCount = rows.reduce((sum, contributor) => sum + contributor.taskCount, 0);
  const earnedCents = rows.reduce((sum, contributor) => sum + contributor.earnedCents, 0);
  return `${rows.length} ${copy.summaryParts.contributors} / ${taskCount} ${copy.summaryParts.accepted} / ${formatHomeMRGFromCents(earnedCents)}`;
});

