const publicAdminOpsCopy = computed(() =>
  publicAdminOpsTranslations[activeLocale.value] || publicAdminOpsTranslations['en-US'],
);

const publicAdminOpsLoading = computed(() =>
  ledgerLoading.value || marketplaceLoading.value || liveFeedLoading.value || (isAdminUser.value && adminConsoleLoading.value),
);

function adminOpsSignalText(item = {}) {
  return [
    item.rawType,
    item.typeLabel,
    item.type,
    item.title,
    item.body,
    item.project,
    item.status,
    item.reference,
    ledgerProofItemText(item),
  ].filter(Boolean).join(' ').toLowerCase();
}

const publicAdminOpsSummary = computed(() => {
  const publicOpsRows = [...ledgerEventItems.value, ...liveFeedAllItemsView.value].filter((item) =>
    /dispute|moderation|risk|fraud|security|payout|release|payment|escrow|treasury|token|reserve|admin/i.test(adminOpsSignalText(item)),
  );
  const disputeRows = publicOpsRows.filter((item) => /dispute|blocked|review needed|moderation|risk|fraud|unsafe|security/i.test(adminOpsSignalText(item)));
  const payoutRows = publicOpsRows.filter((item) => /task_payment|manual_credit|payout|release|auto_release|payment/i.test(adminOpsSignalText(item)));
  const privateDisputes = isAdminUser.value ? Number(adminConsole.value.disputes?.stats?.total_count) || 0 : 0;
  const privateOps = isAdminUser.value ? Number(adminConsole.value.ops?.stats?.total_count) || 0 : 0;
  const privatePayoutRows = isAdminUser.value ? (adminConsole.value.ledger || []).filter((entry) => entry.type === 'task_payment' || entry.type === 'manual_credit').length : 0;
  return {
    treasuryCents: ledgerTreasuryCents.value || Number(ledgerEconomyTotals.value.platform_fee_cents) || 0,
    reserveCents: ledgerRemainingReserveCents.value,
    releasedCents: ledgerReleasedCents.value,
    opsCount: Math.max(publicOpsRows.length, privateOps + privateDisputes),
    disputeCount: Math.max(disputeRows.length, privateDisputes),
    payoutCount: Math.max(Number(ledgerEconomyStats.value.payout_count) || payoutRows.length, privatePayoutRows),
    proofCount: ledgerEventItems.value.length || ledgerRawEntries.value.length,
    publicOpsRows,
    disputeRows,
    payoutRows,
  };
});

const publicAdminOpsStatus = computed(() => {
  const copy = publicAdminOpsCopy.value.status;
  if (publicAdminOpsLoading.value) return { label: copy.syncing, tone: 'blue' };
  if (ledgerError.value || liveFeedError.value || marketplaceError.value || adminConsoleError.value) return { label: copy.review, tone: 'amber' };
  const summary = publicAdminOpsSummary.value;
  if (summary.opsCount || summary.payoutCount || summary.proofCount) return { label: copy.active, tone: 'green' };
  return { label: copy.ready, tone: 'amber' };
});

const publicAdminOpsStats = computed(() => {
  const copy = publicAdminOpsCopy.value;
  const summary = publicAdminOpsSummary.value;
  return [
    {
      label: copy.stats[0]?.[0] || 'Treasury',
      value: formatLedgerMRGFromCents(summary.treasuryCents || summary.reserveCents),
      caption: copy.stats[0]?.[1] || '',
      icon: CircleDollarSign,
      tone: 'green',
    },
    {
      label: copy.stats[1]?.[0] || 'Ops signals',
      value: String(summary.opsCount),
      caption: copy.stats[1]?.[1] || '',
      icon: ShieldCheck,
      tone: 'amber',
    },
    {
      label: copy.stats[2]?.[0] || 'Payouts',
      value: String(summary.payoutCount),
      caption: copy.stats[2]?.[1] || '',
      icon: Trophy,
      tone: 'purple',
    },
    {
      label: copy.stats[3]?.[0] || 'Ledger anchors',
      value: String(summary.proofCount),
      caption: copy.stats[3]?.[1] || '',
      icon: Hash,
      tone: 'blue',
    },
  ];
});

const publicAdminGovernanceRows = computed(() => {
  const copy = publicAdminOpsCopy.value;
  const summary = publicAdminOpsSummary.value;
  const rows = copy.lanes || publicAdminOpsTranslations['en-US'].lanes;
  const signals = copy.signals || publicAdminOpsTranslations['en-US'].signals;
  const definitions = [
    {
      key: 'treasury',
      icon: BarChart3,
      tone: 'green',
      value: formatLedgerMRGFromCents(summary.reserveCents),
      count: summary.reserveCents,
    },
    {
      key: 'disputes',
      icon: ShieldCheck,
      tone: summary.disputeCount ? 'amber' : 'green',
      value: String(summary.disputeCount),
      count: summary.disputeCount,
    },
    {
      key: 'payouts',
      icon: Trophy,
      tone: summary.payoutCount ? 'purple' : 'slate',
      value: String(summary.payoutCount),
      count: summary.payoutCount,
    },
    {
      key: 'moderation',
      icon: Eye,
      tone: summary.opsCount ? 'blue' : 'green',
      value: String(summary.opsCount),
      count: summary.opsCount,
    },
    {
      key: 'ledger',
      icon: Hash,
      tone: summary.proofCount ? 'green' : 'slate',
      value: String(summary.proofCount),
      count: summary.proofCount,
    },
  ];
  return definitions.map((definition, index) => {
    const row = rows[index] || [];
    const active = Number(definition.count) > 0;
    return {
      ...definition,
      title: row[0] || definition.key,
      body: row[1] || '',
      signal: `${definition.value} ${signals[index] || ''}`.trim(),
      active,
      status: active ? publicAdminOpsStatus.value.label : (publicAdminOpsCopy.value.status.ready || 'Ready'),
      statusTone: active ? definition.tone : 'slate',
    };
  });
});

const publicAdminOpsQueueRows = computed(() => {
  const rows = publicAdminOpsSummary.value.publicOpsRows
    .slice()
    .sort((a, b) => (Date.parse(b.created_at || b.createdAt || '') || 0) - (Date.parse(a.created_at || a.createdAt || '') || 0))
    .slice(0, 5)
    .map((item, index) => {
      const isLive = Boolean(item.rawType || item.typeLabel);
      const event = isLive ? item : mapLedgerTransparencyEvent(item);
      const type = isLive ? item.typeLabel : event.type;
      const project = isLive ? item.project : event.project;
      const when = isLive ? item.time : event.time;
      const body = isLive ? item.body : `${event.company} / ${event.secondaryAmount || event.status}`;
      return {
        key: `admin-ops-${isLive ? item.id : event.key || index}`,
        title: isLive ? item.title : event.type,
        body,
        meta: [type, project, when].filter(Boolean).join(' / '),
        status: isLive ? item.status : event.status,
        statusTone: (isLive ? item.tone : event.tone) || 'green',
        icon: (isLive ? item.icon : event.icon) || ShieldCheck,
        tone: (isLive ? item.tone : event.tone) || 'green',
      };
    });
  return rows;
});

const publicAdminProofRows = computed(() => {
  const recent = ledgerEconomyRecentRows.value.slice(0, 4).map((row) => ({
    key: `economy-${row.key}`,
    title: row.label || row.type || publicAdminOpsCopy.value.proofTitle,
    meta: [row.reference, row.amount].filter(Boolean).join(' / '),
    reference: row.shortHash || row.hash || row.reference,
    icon: row.icon || Hash,
    tone: row.tone || 'green',
  }));
  if (recent.length) return recent;
  const ledgerRows = ledgerEventItems.value.slice(0, 4).map((item, index) => {
    const event = mapLedgerTransparencyEvent(item);
    return {
      key: `ledger-${event.key || index}`,
      title: event.type,
      meta: `${event.project} / ${event.time}`,
      reference: event.contractReference || event.ref,
      icon: event.icon || Hash,
      tone: event.tone || 'green',
    };
  });
  if (ledgerRows.length) return ledgerRows;
  const copy = publicAdminOpsCopy.value;
  return [{
    key: 'admin-proof-empty',
    title: copy.emptyProofTitle,
    meta: copy.emptyProofMeta,
    reference: copy.emptyProofBody,
    icon: Hash,
    tone: 'amber',
  }];
});

