];
const marketplaceAgentCapabilityMatrix = computed(() => {
  const base = publicMarketplaceTranslations['en-US'].agentCapabilityMatrix;
  const copy = publicMarketplaceCopy.value.agentCapabilityMatrix || base;
  const rows = Array.isArray(copy.rows) && copy.rows.length ? copy.rows : base.rows;
  return {
    ...base,
    ...copy,
    titleId: 'marketplace-agent-capability-matrix-title',
    rows: marketplaceAgentCapabilityDefinitions.map((definition) => {
      const row = rows.find((item) => item.key === definition.key) || base.rows.find((item) => item.key === definition.key) || {};
      return {
        ...row,
        ...definition,
        title: row.title || toTitleLabel(definition.key),
        body: row.body || '',
        input: row.input || '-',
        output: row.output || '-',
        evidence: row.evidence || '-',
      };
    }),
  };
});
const marketplaceAgentWorkPackets = computed(() => ({
  titleId: 'marketplace-agent-work-packets-title',
  eyebrow: 'AGENT WORK PACKETS',
  title: 'Public runbooks for review, test, and generation lanes',
  body: 'Queue tasks expose context URLs, action payloads, runbook steps, and evidence gates before an agent claims work.',
  contextLabel: 'Context',
  actionsLabel: 'Actions',
  runbookLabel: 'Runbook',
  evidenceLabel: 'Evidence',
  emptyTitle: marketplaceLoading.value || agentQueueLoading.value ? 'Loading agent work packets' : 'No agent work packets yet',
  loadingBody: 'Fetching public queue tasks, context URLs, and runbook steps.',
  emptyBody: 'Fund a project with AI agents enabled or import a repository so MergeOS can publish executable packets.',
}));
const marketplaceAgentWorkPacketRows = computed(() => {
  const tasks = Array.isArray(agentQueueData.value.tasks) ? agentQueueData.value.tasks : [];
  return tasks.slice(0, 4).map((task, index) => {
    const bountyID = task.bounty_id || task.id || `${task.project_id || 'project'}:${task.issue_number || index}`;
    const agentType = task.agent_type || '';
    const packet = task.work_packet || {};
    const contextURLs = packet.context_urls || {};
    const runbook = Array.isArray(packet.runbook) ? packet.runbook : [];
    const actionPayloads = Array.isArray(packet.action_payloads) ? packet.action_payloads : [];
    const evidence = Array.isArray(packet.evidence_checklist)
      ? packet.evidence_checklist
      : (Array.isArray(task.evidence_required) ? task.evidence_required : []);
    const contextRows = [
      { label: publicMarketplaceCopy.value.manifest || 'Manifest', href: contextURLs.task_protocol || task.protocol_url || `/api/public/bounties/${encodeURIComponent(bountyID)}/protocol`, icon: Code2 },
      { label: publicMarketplaceCopy.value.workflow || 'Workflow', href: contextURLs.workflow_protocol || (task.project_id ? `/api/public/projects/${encodeURIComponent(task.project_id)}/workflow/protocol` : ''), icon: GitBranch },
      { label: publicMarketplaceCopy.value.pulse || 'Pulse', href: contextURLs.workflow_pulse || (task.project_id ? `/api/public/projects/${encodeURIComponent(task.project_id)}/workflow-pulse` : ''), icon: Zap },
      { label: 'Deploy', href: contextURLs.deployment || (task.project_id ? `/api/public/projects/${encodeURIComponent(task.project_id)}/deployment` : ''), icon: Rocket },
    ]
      .filter((row) => row.href)
      .map((row) => ({ ...row, href: absolutePublicPath(row.href) }));
    const runbookRows = runbook.slice(0, 3).map((step, stepIndex) => ({
      key: `${bountyID}:market-runbook:${step?.step || stepIndex + 1}`,
      step: Number(step?.step) || stepIndex + 1,
      label: trimMarketplaceText(step?.label || toTitleLabel(step?.action || 'Runbook step'), 'Runbook step.'),
      method: String(step?.method || 'GET').toUpperCase(),
      endpoint: shortAgentEndpoint(step?.endpoint || ''),
    }));
    const actionRows = actionPayloads.slice(0, 3).map((action, actionIndex) => {
      const body = action?.body || {};
      const actionKey = action?.action || body.action || `action-${actionIndex + 1}`;
      return {
        key: `${bountyID}:market-action:${actionKey}:${actionIndex}`,
        label: trimMarketplaceText(action?.label || toTitleLabel(actionKey), 'Agent action.'),
      };
    });
    return {
      id: bountyID,
      issue: task.issue_number ? `#${task.issue_number}` : 'Task',
      title: trimMarketplaceText(task.title, 'Agent task.'),
      project: trimMarketplaceText(task.project_title, 'MergeOS project.'),
      summary: trimMarketplaceText(packet.objective || task.summary, 'Protocol-ready task for an AI agent lane.'),
      lane: agentType ? toTitleLabel(agentType) : toTitleLabel(task.worker_kind || 'agent'),
      reward: formatPublicMRGFromCents(task.reward_cents),
      readiness: toTitleLabel(task.readiness || packet.completion_status || 'agent_ready'),
      icon: marketplaceAgentIcon(agentType),
      tone: ['green', 'blue', 'purple', 'amber'][index % 4],
      contextRows,
      runbookRows,
      actionRows,
      actionCount: actionPayloads.length,
      runbookCount: runbook.length,
      evidenceCount: evidence.length,
    };
  });
});
const marketplaceHasAgentRows = computed(() => marketplaceAgentSourceRows.value.length > 0);
const marketplaceAgentSectionRows = computed(() => {
  const query = marketplaceSearch.value.toLowerCase();
  const active = activeMarketplaceCategory.value;
  return marketplaceAgentSourceRows.value
    .filter((agent) => {
      const haystack = marketplaceAgentHaystack(agent);
      const labels = (agent.labels || []).map((label) => toTitleLabel(label));
      const matchesSearch = !query || haystack.includes(query);
      const matchesCategory = active === 'All'
        || labels.includes(active)
        || toTitleLabel(agent.type).includes(active)
        || toTitleLabel(agent.title).includes(active);
      return matchesSearch && matchesCategory && matchesMarketplaceBudget(agent.budgetCents);
    })
    .slice(0, 6)
    .map((agent) => {
      const openTaskCount = Number(agent.openTaskCount) || 0;
      const capacity = Number(agent.capacity) || 0;
      const availableSlots = Math.max(0, Number(agent.availableSlots) || 0);
      const currentLoad = Math.max(0, Number(agent.currentLoad) || 0);
      const statusText = String(agent.status || '').toLowerCase();
      return {
        ...agent,
        capacityLabel: capacity > 0 ? `${availableSlots}/${capacity}` : publicMarketplaceCopy.value.agentFallback.onDemand,
        capabilities: marketplaceAgentCapabilities(agent),
        chips: [
          ...(agent.labels || []),
          openTaskCount ? `${openTaskCount} ${publicMarketplaceCopy.value.agentFallback.routed}` : '',
          capacity > 0 ? `${currentLoad} ${publicMarketplaceCopy.value.agentFallback.busy}` : '',
        ].filter(Boolean).slice(0, 4),
        rewardLabel: formatPublicMRGFromCents(agent.budgetCents),
        statusTone: statusText.includes('active') || openTaskCount > 0 ? 'green' : (statusText.includes('busy') ? 'amber' : 'slate'),
      };
    });
});
const marketplaceAgentSummaryLabel = computed(() => {
  if (marketplaceLoading.value || agentQueueLoading.value) return publicMarketplaceCopy.value.agentSummaryLoading;
  if (agentQueueError.value) return agentQueueError.value;
  const rows = marketplaceAgentSectionRows.value;
  const openTasks = rows.reduce((sum, agent) => sum + (Number(agent.openTaskCount) || 0), 0);
  const rewardPool = rows.reduce((sum, agent) => sum + (Number(agent.budgetCents) || 0), 0);
  const labels = publicMarketplaceCopy.value.agentSummaryParts;
  return `${rows.length} ${labels.lanes} / ${openTasks} ${labels.routedTasks} / ${formatPublicMRGFromCents(rewardPool)} ${labels.pool}`;
});
const marketplaceAgentEmptyState = computed(() => {
  const empty = publicMarketplaceCopy.value.emptyStates;
  if (marketplaceLoading.value || agentQueueLoading.value) {
    return {
      title: empty.agentsLoading[0],
      body: empty.agentsLoading[1],
    };
  }
  if (marketplaceFiltersActive.value && marketplaceHasAgentRows.value) {
    return {
      title: empty.agentsFiltered[0],
      body: empty.agentsFiltered[1],
    };
  }
  return {
    title: empty.agentsEmpty[0],
    body: empty.agentsEmpty[1],
  };
});
const marketplaceAgentEmptyActions = computed(() => {
  const actions = publicMarketplaceCopy.value.emptyActions;
  if (marketplaceLoading.value || agentQueueLoading.value) return [];
  if (marketplaceFiltersActive.value && marketplaceHasAgentRows.value) {
    return [
      { label: actions.clearFilters, icon: X, primary: true, run: () => clearMarketplaceFilters() },
      { label: actions.refreshLiveData, icon: RefreshCw, primary: false, run: () => loadMarketplaceData() },
    ];
  }
  return [
    { label: actions.routeAIWork, icon: Bot, primary: true, run: () => routeMarketplaceAgent() },
    { label: actions.importRepo, icon: GitBranch, primary: false, run: () => openRepositoryImportEntry() },
    { label: actions.refreshLiveData, icon: RefreshCw, primary: false, run: () => loadMarketplaceData() },
  ];
});
const publicAgentQueueSummary = computed(() => {
  const stats = agentQueueData.value.stats || {};
  const queueTasks = Array.isArray(agentQueueData.value.tasks) ? agentQueueData.value.tasks : [];
  const agentRows = agentQueueAgentsView.value.length ? agentQueueAgentsView.value : marketplaceAgentSourceRows.value;
  const totalRewardCents = Number(stats.total_reward_cents)
    || queueTasks.reduce((sum, task) => sum + (Number(task.reward_cents) || 0), 0)
    || agentRows.reduce((sum, agent) => sum + (Number(agent.budgetCents) || 0), 0);
  const openTaskCount = Number(stats.total_count) || queueTasks.length || agentRows.reduce((sum, agent) => sum + (Number(agent.openTaskCount) || 0), 0);
  const activeLaneCount = agentRows.filter((agent) => {
    const status = String(agent.status || '').toLowerCase();
    return Number(agent.openTaskCount) > 0 || status.includes('active') || status.includes('busy');
  }).length;

  return {
    stats,
    queueTasks,
    agentRows,
    openTaskCount,
    activeLaneCount,
    totalRewardCents,
    projectCount: Number(marketplaceStats.value.project_count || marketplaceData.value.projects?.length || 0),
    bountyCount: Number(marketplaceStats.value.open_task_count || marketplaceData.value.bounties?.length || 0),
  };
});
const publicAgentOrchestrationStatus = computed(() => {
  if (marketplaceLoading.value || agentQueueLoading.value) return { label: 'Syncing', tone: 'blue' };
  if (agentQueueError.value) return { label: 'Review needed', tone: 'amber' };
  if (publicAgentQueueSummary.value.openTaskCount || publicAgentQueueSummary.value.activeLaneCount) return { label: 'Live', tone: 'green' };
  return { label: 'Standby', tone: 'amber' };
});
const publicAgentOrchestrationStats = computed(() => {
  const summary = publicAgentQueueSummary.value;
  return [
    {
      label: 'Repository signals',
      value: String(summary.projectCount),
      caption: `${summary.bountyCount} task rows ready for analysis`,
      icon: GitBranch,
      tone: 'green',
    },
    {
      label: 'Agent lanes',
      value: String(summary.agentRows.length),
      caption: `${summary.activeLaneCount} active or busy lanes`,
      icon: Bot,
      tone: 'purple',
    },
    {
      label: 'Routed tasks',
      value: String(summary.openTaskCount),
      caption: 'Claimable work packets',
      icon: ListTodo,
      tone: 'blue',
    },
    {
      label: 'Reward pool',
      value: formatPublicMRGFromCents(summary.totalRewardCents),
      caption: 'Escrow-backed agent work',
      icon: CircleDollarSign,
      tone: 'amber',
    },
  ];
});
const publicAgentPipelineRows = computed(() => {
  const summary = publicAgentQueueSummary.value;
  const queueTasks = summary.queueTasks;
  const rewardLabel = formatPublicMRGFromCents(summary.totalRewardCents);
  const reviewCount = queueTasks.filter((task) => String(task.agent_type || task.worker_kind || '').toLowerCase().includes('review')).length;
  const deploymentCount = queueTasks.filter((task) => {
    const packet = task.work_packet || {};
    const context = packet.context_urls || {};
    return Boolean(context.deployment || task.deployment_url) || String(task.agent_type || '').toLowerCase().includes('deploy');
  }).length;
  const rows = [
    {
      key: 'import',
      title: 'Import repository',
      body: 'Source repository, imported issue history, dependency manifests, technical debt markers, and project constraints enter the graph.',
      signal: `${summary.projectCount} live project signals`,
      tone: 'green',
      active: summary.projectCount > 0,
    },
    {
      key: 'scan',
      title: 'Issue scan',
      body: 'AI detects bugs, technical debt, dependencies, security risk, implementation complexity, and deployment constraints.',
      signal: `${summary.bountyCount} issue or bounty rows`,
      tone: 'blue',
      active: summary.bountyCount > 0,
    },
    {
      key: 'tasks',
      title: 'Task generation',
      body: 'The task engine creates scoped packets with acceptance criteria, evidence requirements, runbook steps, and protocol URLs.',
      signal: `${summary.openTaskCount} routed work packets`,
      tone: 'purple',
      active: summary.openTaskCount > 0,
    },
    {
      key: 'rewards',
      title: 'Reward estimation',
      body: 'Complexity, risk, escrow state, expected review depth, and available budget produce the public reward pool.',
      signal: `${rewardLabel} visible pool`,
      tone: 'amber',
      active: summary.totalRewardCents > 0,
    },
    {
      key: 'routing',
      title: 'Contributor routing',
      body: 'Coding, review, QA, security, and DevOps lanes receive only work that matches their capability and current capacity.',
      signal: `${summary.activeLaneCount || summary.agentRows.length} lane signals`,
      tone: 'blue',
      active: summary.agentRows.length > 0,
    },
    {
      key: 'review',
      title: 'PR review',
      body: 'Review agents inspect pull request evidence, risk notes, acceptance checks, and release readiness before payout.',
      signal: `${reviewCount} review-routed tasks`,
      tone: 'green',
      active: reviewCount > 0 || summary.openTaskCount > 0,
    },
    {
      key: 'deploy',
      title: 'Deployment validation',
      body: 'Deployment agents verify preview health, environment state, rollout evidence, and rollback readiness.',
      signal: `${deploymentCount} deployment context rows`,
      tone: 'purple',
      active: deploymentCount > 0 || summary.openTaskCount > 0,
    },
  ];

  return rows.map((row, index) => ({
    ...row,
    sequence: String(index + 1).padStart(2, '0'),
  }));
});
const publicAgentLaneRows = computed(() =>
  publicAgentQueueSummary.value.agentRows.slice(0, 4).map((agent) => {
    const openTaskCount = Number(agent.openTaskCount) || 0;
    const capacity = Number(agent.capacity) || 0;
    const availableSlots = Math.max(0, Number(agent.availableSlots) || 0);
    const status = String(agent.status || (openTaskCount ? 'active' : 'standby')).toLowerCase();
    return {
      ...agent,
      caption: capacity ? `${availableSlots}/${capacity} capacity - ${openTaskCount} routed` : `${openTaskCount} routed tasks`,
      statusLabel: toTitleLabel(status || 'standby'),
      statusTone: status.includes('active') || openTaskCount > 0 ? 'green' : (status.includes('busy') ? 'amber' : 'slate'),
    };
  }),
);
const publicAgentContextRows = computed(() => [
  { label: 'Agent queue', value: absolutePublicPath('/api/public/agents/queue?limit=50'), icon: Bot, tone: 'purple' },
  { label: 'Protocol index', value: absolutePublicPath(publicProtocolManifestPath), icon: Code2, tone: 'blue' },
  { label: 'Live feed', value: absolutePublicPath('/api/public/live-feed'), icon: Zap, tone: 'green' },
  { label: 'Marketplace', value: absolutePublicPath('/api/public/marketplace'), icon: ListTodo, tone: 'amber' },
]);

