const publicRepoFactoryCopy = computed(() =>
  publicRepoFactoryTranslations[activeLocale.value] || publicRepoFactoryTranslations['en-US'],
);

const publicRepoFactoryLoading = computed(() =>
  marketplaceLoading.value || agentQueueLoading.value || liveFeedLoading.value || ledgerLoading.value || protocolLoading.value,
);

const publicRepoFactorySummary = computed(() => {
  const stats = marketplaceStats.value || {};
  const bountyRows = Array.isArray(marketplaceData.value.bounties) ? marketplaceData.value.bounties : [];
  const projectRows = Array.isArray(marketplaceData.value.projects) ? marketplaceData.value.projects : [];
  const summary = publicAgentQueueSummary.value;
  const projectCount = Number(stats.project_count) || projectRows.length || 0;
  const bountyCount = Number(stats.open_task_count) || bountyRows.length || summary.bountyCount || 0;
  const taskPacketCount = Math.max(summary.openTaskCount || 0, bountyCount, marketplaceAgentWorkPacketRows.value.length);
  const rewardCents = Number(stats.total_budget_cents)
    || summary.totalRewardCents
    || bountyRows.reduce((sum, bounty) => sum + (Number(bounty.reward_cents) || 0), 0);
  const routeLaneCount = Math.max(summary.agentRows.length, marketplaceData.value.contributors?.length || 0);
  const proofCount = ledgerEventItems.value.length || liveFeedAllItemsView.value.length;
  return {
    projectCount,
    bountyCount,
    taskPacketCount,
    rewardCents,
    routeLaneCount,
    proofCount,
  };
});

const publicRepoFactoryStatus = computed(() => {
  const copy = publicRepoFactoryCopy.value.status;
  if (publicRepoFactoryLoading.value) return { label: copy.syncing, tone: 'blue' };
  if (marketplaceError.value || agentQueueError.value || liveFeedError.value || ledgerError.value || protocolError.value) {
    return { label: copy.review, tone: 'amber' };
  }
  const summary = publicRepoFactorySummary.value;
  if (summary.taskPacketCount || summary.proofCount || summary.rewardCents) return { label: copy.live, tone: 'green' };
  return { label: copy.standby, tone: 'amber' };
});

