  tone: 'green',
});
function agentPresenceCaption(agent = {}) {
  const capacity = Number(agent.capacity) || 0;
  if (capacity <= 0) return '';
  const availableSlots = Math.max(0, Number(agent.available_slots) || 0);
  const currentLoad = Math.max(0, Number(agent.current_load) || 0);
  const labels = publicMarketplaceCopy.value.agentFallback;
  const slotsLabel = availableSlots > 0 ? `${availableSlots}/${capacity} ${labels.slotsFree}` : `${currentLoad}/${capacity} ${labels.slotsBusy}`;
  const heartbeatLabel = agent.last_heartbeat_at ? ` - ${labels.heartbeat} ${formatLedgerDateTime(agent.last_heartbeat_at).time}` : '';
  return `${slotsLabel}${heartbeatLabel}`;
}

function marketplaceAgentCapabilities(agent = {}) {
  const labels = publicMarketplaceCopy.value.agentCapabilities || publicMarketplaceTranslations['en-US'].agentCapabilities;
  const haystack = [
    agent.type,
    agent.title,
    agent.body,
    agent.displayBody,
    agent.capability,
    ...(agent.labels || []),
  ].filter(Boolean).join(' ').toLowerCase();
  const definitions = [
    {
      key: 'review',
      icon: Eye,
      keywords: ['review', 'reviews', 'pr', 'pull request', 'acceptance', 'audit'],
    },
    {
      key: 'test',
      icon: CheckCircle2,
      keywords: ['test', 'tests', 'qa', 'smoke', 'validation', 'accessibility'],
    },
    {
      key: 'generate',
      icon: Sparkles,
      keywords: ['generate', 'scans', 'scan', 'groups', 'prepares', 'produces', 'task', 'design-system'],
    },
    {
      key: 'deploy',
      icon: Rocket,
      keywords: ['deploy', 'deployment', 'release', 'environment', 'devops', 'handoff'],
    },
    {
      key: 'secure',
      icon: ShieldCheck,
      keywords: ['security', 'secret', 'auth', 'payment', 'token', 'permission', 'hygiene'],
    },
    {
      key: 'code',
      icon: Code2,
      keywords: ['code', 'api', 'backend', 'frontend', 'vue', 'ui', 'implementation', 'implements', 'builds', 'go'],
    },
  ];
  return definitions.map((definition) => ({
    key: definition.key,
    label: labels[definition.key] || toTitleLabel(definition.key),
    icon: definition.icon,
    active: definition.key === 'generate'
      ? definition.keywords.some((keyword) => haystack.includes(keyword)) || haystack.includes('agent')
      : definition.keywords.some((keyword) => haystack.includes(keyword)),
  }));
}
