const dashboardEscrowProgress = computed(() => {
  const workPool = Number(dashboardEscrow.value?.work_pool_cents) || Number(dashboardSelectedProject.value?.work_pool_cents) || 0;
  if (!workPool) return 0;
  return Math.max(0, Math.min(100, Math.round(((Number(dashboardEscrow.value?.released_cents) || 0) / workPool) * 100)));
});
const dashboardEscrowView = computed(() => {
  const project = dashboardSelectedProject.value;
  if (!project) {
    return {
      status: dashboardEscrowLoading.value ? 'Syncing' : 'Waiting',
      body: 'Escrow control appears after a project is selected.',
      progress: 0,
    };
  }
  if (dashboardEscrowError.value) {
    return {
      status: 'Error',
      body: dashboardEscrowError.value,
      progress: dashboardEscrowProgress.value,
    };
  }
  if (dashboardEscrowLoading.value && !dashboardEscrow.value) {
    return {
      status: 'Syncing',
      body: 'Loading project reserve, task reserves, and release readiness.',
      progress: dashboardEscrowProgress.value,
    };
  }
  if (!dashboardEscrow.value) {
    return {
      status: 'Waiting',
      body: 'No escrow payload loaded yet.',
      progress: dashboardEscrowProgress.value,
    };
  }
  return {
    status: toTitleLabel(dashboardEscrow.value.release_status || 'funded'),
    body: `${formatMRGFromCents(dashboardEscrow.value.released_cents)} released from ${formatMRGFromCents(dashboardEscrow.value.work_pool_cents)} work pool.`,
    progress: dashboardEscrowProgress.value,
  };
});
