    .filter(Boolean);
  const method = packet.method || 'POST';
  const endpoint = packet.release_endpoint || `/api/projects/${dashboardSelectedProject.value?.id || selectedDashboardProjectID.value || 'project'}/auto-release`;
  const policy = packet.policy || packet.payload?.policy || 'mergeos.auto_release.low_risk_agent.v1';
  return {
    count: rows.length,
    policy: shortLedgerReference(policy),
    summary: `${rows.length} low-risk payout${rows.length === 1 ? '' : 's'} ready for ledger-backed release.`,
    command: `${method} ${endpoint}`,
    contextRows: autoReleaseContextRows(packet.context_urls || {}),
    runbookRows: autoReleaseRunbookRows(packet.runbook || []),
    payloadRows: autoReleasePayloadRows(packet, taskIDs),
