    };
  }
  const stats = dashboardRoutingStats.value;
  return {
    status: toTitleLabel(dashboardRouting.value.status || 'routing'),
    body: dashboardRouting.value.summary || `${Number(stats.ready_count) || 0} tasks are ready for contributors or agents.`,
  };
});
