async function handlePostPaymentAction(actionID = '') {
  switch (actionID) {
  case 'details':
    projectPreviewVisible.value = false;
    publicModeVisible.value = true;
    projectWizardVisible.value = true;
    projectWizardStage.value = 'setup';
    projectWizardStep.value = 4;
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    return;
  case 'invite': {
    const url = postPaymentProjectShareURL();
    const copied = await copyTextToClipboard(url);
    showToast(copied ? 'Project invite link copied.' : `Invite link ${shortLedgerReference(url)}`);
    return;
  }
  case 'boost':
    closeProjectWizard({ updatePath: false });
    activeMarketplaceCategory.value = 'All';
    marketplaceSearch.value = fundedProject.value?.title || '';
    openMarketplaceSection('marketplace-projects');
    return;
  case 'dashboard':
    openFundedProjectDashboard('projects');
    return;
  default:
    openFundedProjectDashboard('projects');
  }
}

