  if (!projectSetupForm.techStack.trim()) {
    projectSetupForm.techStack = agent.labels?.length
      ? agent.labels.map((label) => toTitleLabel(label)).join(', ')
      : 'AI orchestration, code review, QA, deployment';
  }
  if (!projectSetupForm.shortDescription.trim()) {
    projectSetupForm.shortDescription = `Route scoped software delivery work to ${agentTitle} with human review, acceptance evidence, and escrow-backed payout gates.`;
  }
  showToast(`${agentTitle} lane selected for the project brief.`);
}

