function liveEventContractPayload(contract = {}) {
  const latest = contract.latestEvent || {};
  return {
    key: contract.key || '',
    title: contract.title || '',
    version: contract.version || '',
    schema: contract.schema || '',
    status: contract.status || '',
    event_count: Number(contract.count) || 0,
    source_url: contract.sourceURL || '',
    protocol_context_url: contract.contextURL || protocolManifestURL.value,
    latest_event: latest.id ? {
      id: latest.id,
      type: latest.typeLabel || '',
      raw_type: latest.rawType || '',
      project: latest.project || '',
      reference: latest.rawReference || '',
      contract_reference: latest.rawContractReference || '',
      created_at: latest.createdAt || '',
