    latest_event: latest.id ? {
      id: latest.id,
      type: latest.typeLabel || '',
      raw_type: latest.rawType || '',
      project: latest.project || '',
      reference: latest.rawReference || '',
      contract_reference: latest.rawContractReference || '',
      created_at: latest.createdAt || '',
    } : null,
  };
}

