    logs: dashboardAILogRows.value.map((row) => ({
      title: row.title,
      source: row.source,
      status: row.status,
      body: row.body,
      meta: row.meta,
      reference: row.reference,
      created_at: row.createdAt,
    })),
  };
  const copied = await copyTextToClipboard(JSON.stringify(payload, null, 2));
  showToast(copied ? 'AI delivery log packet copied.' : 'AI delivery log packet is visible on the page.');
}

function openDashboardSection(section, options = {}) {
  publicModeVisible.value = false;
  dashboardProjectActionsVisible.value = false;
  if (section === 'admin' && !isAdminUser.value) {
    showToast('Admin access is required.');
    section = 'projects';
  }
  if (section === 'tasks') {
    section = 'projects';
    options = { ...options, focus: 'tasks' };
  }
  if (section === 'payments' || section === 'projects' || section === 'worker' || section === 'admin' || dashboardToolDefinitions[section]) {
    dashboardSection.value = section;
    if (section === 'projects') {
      dashboardProjectFocus.value = normalizeDashboardProjectFocus(options.focus);
    }
    if (section === 'worker') {
      void loadWorkerDashboardData({ silent: true });
    }
    if (section === 'admin') {
      void loadAdminConsoleData({ silent: true });
    }
    if (section === 'bounties' || section === 'agents') {
      void loadMarketplaceData({ silent: true });
    }
    if (section === 'repositories' || section === 'issue-scanner' || section === 'analytics') {
      void loadDashboardData({ silent: true });
    }
    if (section === 'issue-scanner') {
      const project = dashboardSelectedProject.value;
      if (project && projectHasScanRepository(project)) {
        void loadDashboardRepositoryIntelligenceData(project.id, { silent: true });
      } else {
        resetDashboardRepositoryIntelligenceState();
      }
    }
    if (section === 'projects') {
      focusDashboardProjectArea(dashboardProjectFocus.value);
      return;
    }
    if (!hasWindow) return;
    window.requestAnimationFrame(() => {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    });
    return;
  }
  dashboardSection.value = 'projects';
  if (section === 'notifications') {
    void loadDashboardNotifications();
    if (!hasWindow) return;
    window.requestAnimationFrame(() => {
      dashboardNotificationCenter.value?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      dashboardNotificationCenter.value?.focus({ preventScroll: true });
    });
  }
}

function openDashboardRoleLane(role = {}, lane = null) {
  if (role.locked) {
    showToast('Admin access is required.');
    return;
  }
  const target = lane || role.primary || {};
  if (!target.section) return;
  openDashboardSection(target.section, { focus: target.focus });
}

function isDashboardNavActive(item = {}) {
  if (item.section === 'projects') {
    return dashboardSection.value === 'projects' && normalizeDashboardProjectFocus(item.focus) === dashboardProjectFocus.value;
  }
  if (item.section) return dashboardSection.value === item.section;
  return false;
}

function dashboardProjectTabCount(tabItem = '') {
  switch (tabItem) {
  case 'Tasks':
    return dashboardTaskRows.value.length;
  case 'AI Logs':
    return dashboardAILogRows.value.length;
  case 'Activity':
    return dashboardActivityRows.value.length;
  default:
    return 0;
  }
}

function dashboardProjectTabFocus(tabItem = '') {
  switch (tabItem) {
  case 'Tasks':
    return 'tasks';
  case 'AI Logs':
    return 'ai-logs';
  case 'Activity':
    return 'activity';
  case 'Settings':
    return 'settings';
  default:
    return 'overview';
  }
}

function isDashboardProjectTabActive(tabItem = '') {
  if (dashboardSection.value !== 'projects') return false;
  if (tabItem === 'Ledger' || tabItem === 'Files') return false;
  return dashboardProjectFocus.value === dashboardProjectTabFocus(tabItem);
}

function handleDashboardProjectTab(tabItem = '') {
  switch (tabItem) {
  case 'Ledger':
    openDashboardProjectLedger();
    return;
  case 'Files':
    openDashboardSection('repositories');
    return;
  case 'Settings':
    dashboardProjectFocus.value = 'settings';
    dashboardProjectActionsVisible.value = true;
    focusDashboardProjectArea('overview');
    return;
  default:
    openDashboardSection('projects', { focus: dashboardProjectTabFocus(tabItem) });
  }
}

function refreshDashboardToolSection() {
  switch (dashboardSection.value) {
  case 'repositories':
  case 'analytics':
    void loadDashboardData({ silent: true });
    break;
  case 'bounties':
  case 'agents':
    void loadMarketplaceData({ silent: true });
    break;
  case 'repo-import':
    void loadRepoIssues();
    break;
  case 'issue-scanner':
    if (dashboardSelectedProject.value && projectHasScanRepository(dashboardSelectedProject.value)) {
      void loadDashboardRepositoryIntelligenceData(dashboardSelectedProject.value.id);
    } else {
      resetDashboardRepositoryIntelligenceState();
      void loadDashboardData({ silent: true });
    }
    break;
  case 'estimate':
    void runProjectPriceEvaluation();
    break;
  default:
    void loadDashboardData({ silent: true });
  }
}

function openMarketplaceSection(id) {
  publicModeVisible.value = true;
  publicPage.value = 'marketplace';
  updatePublicBrowserPath('marketplace');
  loadPublicPageData('marketplace');
  scheduleScrollToSection(id);
}

function scrollProjectFlowTop() {
  if (!hasWindow) return;
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function focusProjectWizardRepoField() {
  if (!hasWindow) return;
  window.requestAnimationFrame(() => {
    const target = document.querySelector('.project-flow-layout .repo-url-field input, .repo-url-field input');
    target?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    target?.focus?.({ preventScroll: true });
  });
}

function applyProjectWizardIntent(intent = '') {
  const nextIntent = String(intent || '').trim();
  if (!nextIntent) return;

  if (nextIntent === 'repo-import' || nextIntent === 'issue-scanner') {
    projectSetupForm.projectType = 'Bug Fix';
    repoImportError.value = '';
    repoImportValidationErrors.value = {};
    repoImportShouldShowErrors.value = false;
    projectWizardStage.value = 'setup';
    projectWizardStep.value = 1;
    void nextTick().then(focusProjectWizardRepoField);
    return;
  }

  if (nextIntent === 'estimate' && !projectSetupForm.projectType) {
    projectSetupForm.projectType = 'New Project';
    projectWizardStage.value = 'setup';
    projectWizardStep.value = 1;
    return;
  }

  if (nextIntent === 'escrow') {
    if (!projectSetupForm.projectType) {
      projectSetupForm.projectType = 'New Project';
    }
    const invalidStep = firstInvalidProjectStep(3);
    projectWizardStage.value = 'setup';
    projectWizardStep.value = invalidStep || 3;
  }
}

function openProjectWizard(options = {}) {
  publicModeVisible.value = true;
  projectWizardVisible.value = true;
  projectPreviewVisible.value = false;
  projectWizardStage.value = 'setup';
  projectWizardStep.value = 1;
  resetProjectValidation();
  errorMessage.value = '';
  projectPaymentSuccessMethod.value = '';
  restoreProjectDraft({ silent: Boolean(options.silentDraft), restoreStep: true });
  applyProjectWizardIntent(options.intent);
  updateProjectWizardBrowserPath(Boolean(options.replace));
  scrollProjectFlowTop();
}

function restartProjectWizard(options = {}) {
  publicModeVisible.value = true;
  projectWizardVisible.value = true;
  projectPreviewVisible.value = false;
  projectWizardStage.value = 'setup';
  projectWizardStep.value = 1;
  resetProjectValidation();
  updateProjectWizardBrowserPath(Boolean(options.replace));
  scrollProjectFlowTop();
}

function closeProjectWizard(options = {}) {
  projectPreviewVisible.value = false;
  projectWizardVisible.value = false;
  projectWizardStage.value = 'setup';
  projectWizardStep.value = 1;
  resetProjectValidation();
  if (options.updatePath !== false) {
    updatePublicBrowserPath(publicPage.value, Boolean(options.replace));
  }
}

async function loadRepoIssues() {
  const repoURL = projectSetupForm.repoUrl.trim();
  repoImportError.value = '';
  repoImportShouldShowErrors.value = true;
  const validationErrors = repoImportValidationErrorsForCurrentInput();
  repoImportValidationErrors.value = validationErrors;
  if (Object.keys(validationErrors).length) {
    repoImportResult.value = null;
    repoImportError.value = validationErrors.repoUrl || 'Fix repository import details before scanning.';
    showToast(repoImportError.value);
    void nextTick().then(focusFirstRepoImportValidationError);
    return;
  }
  const repo = parseRepoDescriptor(repoURL);
  const normalizedRepoURL = `https://github.com/${repo.owner}/${repo.name}`;

  repoImportBusy.value = true;
  try {
    const result = await publicApi('/api/public/repo/issues', {
      method: 'POST',
      body: JSON.stringify({ repo_url: normalizedRepoURL }),
    });
    repoImportResult.value = result;
    projectSetupForm.repoUrl = result.repo_url || normalizedRepoURL;
    repoImportValidationErrors.value = {};
    repoImportShouldShowErrors.value = false;
    if (repoImportedIssues.value.length) {
      projectSetupForm.projectType = 'Bug Fix';
      projectSetupForm.title = `Fix all issues in ${result.owner}/${result.name}`;
      projectSetupForm.shortDescription = `Fix ${repoImportedIssues.value.length} open GitHub issues in ${result.owner}/${result.name}.`;
      projectSetupForm.overview = repoImportedIssues.value
        .map((issue) => `#${issue.number} ${issue.title} - score ${issue.score}, ${issue.complexity}`)
        .join('\n');
      projectDeliverables.value = repoImportedIssues.value.map((issue) => `Fix #${issue.number}: ${issue.title}`);
      showToast(`${repoImportedIssues.value.length} issues loaded and scored.`);
    } else {
      showToast('No open issues found.');
    }
  } catch (error) {
    repoImportResult.value = null;
    repoImportError.value = error.message || 'Could not load repo issues.';
    showToast(repoImportError.value);
  } finally {
    repoImportBusy.value = false;
  }
}

function ensureImportedRepoProjectDraft() {
  if (!repoImportedIssues.value.length) {
    repoImportShouldShowErrors.value = true;
    repoImportError.value = repoImportResult.value
      ? 'No open issues were loaded for this repository.'
      : 'Load repository issues before continuing.';
    showToast(repoImportError.value);
    void nextTick().then(focusFirstRepoImportValidationError);
    return false;
  }

  const parsedRepo = parseRepoDescriptor(projectSetupForm.repoUrl);
  const owner = repoImportResult.value?.owner || parsedRepo?.owner || 'owner';
  const name = repoImportResult.value?.name || parsedRepo?.name || 'repo';
  const repoLabel = `${owner}/${name}`;
  const issueCount = repoImportedIssues.value.length;
  const issueLines = repoImportedIssues.value
    .map((issue) => `#${issue.number} ${issue.title} - score ${issue.score}, ${issue.complexity}`)
    .join('\n');

  projectSetupForm.projectType = 'Bug Fix';
  projectSetupForm.repoUrl = repoImportResult.value?.repo_url || projectSetupForm.repoUrl;
  if (!projectSetupForm.title.trim()) {
    projectSetupForm.title = `Fix all issues in ${repoLabel}`;
  }
  if (!projectSetupForm.shortDescription.trim()) {
    projectSetupForm.shortDescription = `Fix ${issueCount} open GitHub issue${issueCount === 1 ? '' : 's'} in ${repoLabel}.`;
  }
  if (!projectSetupForm.overview.trim()) {
    projectSetupForm.overview = issueLines;
  }
  if (!visibleDeliverables.value.length) {
    projectDeliverables.value = repoImportedIssues.value.map((issue) => `Fix #${issue.number}: ${issue.title}`);
  }
  if (!projectSetupForm.requirements.trim()) {
    projectSetupForm.requirements = [
      'Each imported issue must be resolved with reproducible evidence.',
      'Every fix needs a PR, test notes, or deployment proof before payout release.',
      'Accepted work must keep the public ledger, task state, and review notes in sync.',
    ].join('\n');
  }
  if (!projectSetupForm.skills.trim()) {
    projectSetupForm.skills = inferSkillList();
  }
  if (!projectSetupForm.startDate) {
    projectSetupForm.startDate = todayDateInput();
  }
  if (!projectSetupForm.deadline) {
    projectSetupForm.deadline = dateInputDaysFromNow(Math.min(45, Math.max(14, issueCount * 3)));
  }
  if (!projectBudgetAmount.value) {
    projectSetupForm.budgetAmount = Math.max(minimumProjectBudgetMRG, tokenAmountFromCents(repoImportedEstimateCents.value));
    projectSetupForm.budgetType = 'Range';
  }
  projectFundingAmount.value = Math.max(minimumProjectFundingUSD, Math.ceil(projectBudgetAmount.value / TOKEN_RATE_PER_USD) || minimumProjectFundingUSD);
  return true;
}

function openImportedRepoWizardStep(stepNumber = 2) {
  publicModeVisible.value = true;
  projectWizardVisible.value = true;
  projectPreviewVisible.value = false;
  projectWizardStage.value = 'setup';
  projectWizardStep.value = normalizeProjectWizardStep(stepNumber);
  resetProjectValidation();
  updateProjectWizardBrowserPath();
  scrollProjectFlowTop();
}

function continueImportedRepoProject(destination = 'scope') {
  if (!ensureImportedRepoProjectDraft()) return;

  if (destination === 'estimate') {
    openDashboardSection('estimate');
    void nextTick().then(() => runProjectPriceEvaluation());
    return;
  }

  if (destination === 'funding') {
    const invalidStep = firstInvalidProjectStep(4);
    if (invalidStep) {
      markProjectStepValidationAttempted(invalidStep);
      openImportedRepoWizardStep(invalidStep);
      showProjectValidationToast(invalidStep);
      void nextTick().then(focusFirstProjectValidationError);
      return;
    }
    publicModeVisible.value = true;
    projectWizardVisible.value = true;
    projectPreviewVisible.value = false;
    projectWizardStage.value = 'funding';
    projectWizardStep.value = 4;
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    showToast('Scored repository plan is ready for escrow funding.');
    return;
  }

  openImportedRepoWizardStep(2);
  showToast('Scored repository issues added to the project scope.');
}

function parseRepoDescriptor(value = '') {
  const raw = String(value || '').trim();
  if (!raw) return null;
  const sshMatch = raw.match(/^git@github\.com:([\w.-]+)\/([\w.-]+?)(?:\.git)?$/i);
  if (sshMatch) {
    return { owner: sshMatch[1], name: sshMatch[2], label: `${sshMatch[1]}/${sshMatch[2]}` };
  }
  try {
    const url = new URL(raw);
    const hostname = url.hostname.toLowerCase();
    if (hostname === 'github.com' || hostname === 'www.github.com') {
      const [owner, repo] = url.pathname.split('/').filter(Boolean);
      if (owner && repo) {
        return { owner, name: repo.replace(/\.git$/i, ''), label: `${owner}/${repo.replace(/\.git$/i, '')}` };
      }
    }
  } catch {
    // Fall through to owner/repo shorthand parsing.
  }
  const shorthand = raw.match(/^([\w.-]+)\/([\w.-]+)$/);
  if (!shorthand) return null;
  return { owner: shorthand[1], name: shorthand[2].replace(/\.git$/i, ''), label: `${shorthand[1]}/${shorthand[2].replace(/\.git$/i, '')}` };
}

function repoDescriptorIsGitHubSafe(repo = {}) {
  const owner = String(repo.owner || '').trim();
  const name = String(repo.name || '').trim();
  return /^[A-Za-z0-9](?:[A-Za-z0-9-]{0,37}[A-Za-z0-9])?$/.test(owner)
    && /^[A-Za-z0-9._-]{1,100}$/.test(name)
    && !name.startsWith('.')
    && !name.endsWith('.');
}

function projectRepoImportMatches(repo = {}) {
  if (!repo?.owner || !repo?.name || !repoImportResult.value) return false;
  const imported = parseRepoDescriptor(repoImportResult.value.repo_url || `${repoImportResult.value.owner || ''}/${repoImportResult.value.name || ''}`);
  if (!imported) return false;
  return imported.owner.toLowerCase() === repo.owner.toLowerCase()
    && imported.name.toLowerCase() === repo.name.toLowerCase();
}

function isValidDateInput(value = '') {
  const raw = String(value || '').trim();
  const match = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return false;
  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);
  const date = new Date(Date.UTC(year, month - 1, day));
  return date.getUTCFullYear() === year
    && date.getUTCMonth() === month - 1
    && date.getUTCDate() === day;
}

function projectDateDiffDays(startDate = '', endDate = '') {
  if (!isValidDateInput(startDate) || !isValidDateInput(endDate)) return 0;
  const start = Date.parse(`${startDate}T00:00:00Z`);
  const end = Date.parse(`${endDate}T00:00:00Z`);
  if (!Number.isFinite(start) || !Number.isFinite(end)) return 0;
  return Math.round((end - start) / 86400000);
}

function repoImportValidationErrorsForCurrentInput() {
  const errors = {};
  const raw = projectSetupForm.repoUrl.trim();
  if (!raw) {
    errors.repoUrl = 'Enter a GitHub repository URL before scanning.';
    return errors;
  }
  const repo = parseRepoDescriptor(raw);
  if (!repo || !repo.owner || !repo.name) {
    errors.repoUrl = 'Use a GitHub repo URL, SSH URL, or owner/repo shorthand.';
    return errors;
  }
  if (repo.owner.length > 100 || repo.name.length > 100) {
    errors.repoUrl = 'Repository owner and name must be shorter than 100 characters.';
  } else if (!repoDescriptorIsGitHubSafe(repo)) {
    errors.repoUrl = 'Use a real GitHub owner and repository name.';
  }
  return errors;
}

function repoImportFieldError(field = '') {
  if (!repoImportShouldShowErrors.value) return '';
  return repoImportValidationErrors.value[field] || '';
}

function clearRepoImportFieldError(field = '') {
  if (!field || !repoImportValidationErrors.value[field]) return;
  repoImportValidationErrors.value = {
    ...repoImportValidationErrors.value,
    [field]: '',
  };
  for (const [key, message] of Object.entries(repoImportValidationErrors.value)) {
    if (!message) delete repoImportValidationErrors.value[key];
  }
  if (!Object.keys(repoImportValidationErrors.value).length) {
    repoImportError.value = '';
  }
}

function focusFirstRepoImportValidationError() {
  if (!hasWindow) return;
  document.querySelector('.dashboard-tool-form label.invalid input')?.focus();
}

function todayDateInput() {
  const now = new Date();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  return `${now.getFullYear()}-${month}-${day}`;
}

function dateInputDaysFromNow(days = 0) {
  const next = new Date();
  next.setDate(next.getDate() + (Number(days) || 0));
  const month = String(next.getMonth() + 1).padStart(2, '0');
  const day = String(next.getDate()).padStart(2, '0');
  return `${next.getFullYear()}-${month}-${day}`;
}

function projectValidationErrorsForStep(stepNumber = projectWizardStep.value) {
  const step = normalizeProjectWizardStep(stepNumber);
  const errors = {};
  const title = projectSetupForm.title.trim();
  const shortDescription = projectSetupForm.shortDescription.trim();
  const overview = projectSetupForm.overview.trim();
  const deliverables = visibleDeliverables.value;
  const requirements = projectSetupForm.requirements.trim();
  const today = todayDateInput();

  if (step === 1) {
    if (title.length < projectTitleMinLength) {
      errors.title = `Enter a clear title with at least ${projectTitleMinLength} characters.`;
    } else if (title.length > projectTitleMaxLength) {
      errors.title = `Keep the title under ${projectTitleMaxLength} characters.`;
    } else if (/^https?:\/\//i.test(title)) {
      errors.title = 'Use a project title, not a URL.';
    }
    if (shortDescription.length < projectShortDescriptionMinLength) {
      errors.shortDescription = `Describe the work in at least ${projectShortDescriptionMinLength} characters.`;
    } else if (shortDescription.length > projectShortDescriptionMaxLength) {
      errors.shortDescription = `Keep the short description under ${projectShortDescriptionMaxLength} characters.`;
    } else if (title && shortDescription.toLowerCase() === title.toLowerCase()) {
      errors.shortDescription = 'Add context beyond the project title.';
    }
    if (!projectSetupForm.projectType) {
      errors.projectType = 'Choose New Project or Bug Fix.';
    }
    if (projectSetupForm.projectType === 'Bug Fix') {
      const repo = parseRepoDescriptor(projectSetupForm.repoUrl);
      if (!projectSetupForm.repoUrl.trim()) {
        errors.repoUrl = 'Attach the GitHub repository for this bug fix.';
      } else if (!repo) {
        errors.repoUrl = 'Use a valid GitHub URL or owner/repo shorthand.';
      } else if (!repoDescriptorIsGitHubSafe(repo)) {
        errors.repoUrl = 'Use a real GitHub owner and repository name.';
      } else if (!projectRepoImportMatches(repo) || !repoImportedIssues.value.length) {
        errors.repoImport = 'Load issues for this repository before continuing.';
      }
    }
    return errors;
  }

  if (step === 2) {
    if (overview.length < projectOverviewMinLength) {
      errors.overview = `Add at least ${projectOverviewMinLength} characters of goal, context, and expected behavior.`;
    } else if (overview.length > projectOverviewMaxLength) {
      errors.overview = `Keep the overview under ${projectOverviewMaxLength} characters.`;
    }
    if (deliverables.length < 2) {
      errors.deliverables = 'Add at least 2 concrete deliverables.';
    } else if (deliverables.some((item) => item.length < projectDeliverableMinLength)) {
      errors.deliverables = `Each deliverable should be at least ${projectDeliverableMinLength} characters.`;
    } else if (deliverables.some((item) => item.length > projectDeliverableMaxLength)) {
      errors.deliverables = `Keep each deliverable under ${projectDeliverableMaxLength} characters.`;
    } else if (new Set(deliverables.map((item) => item.toLowerCase())).size !== deliverables.length) {
      errors.deliverables = 'Remove duplicate deliverables.';
    }
    if (requirements.length > projectRequirementsMaxLength) {
      errors.requirements = `Keep requirements under ${projectRequirementsMaxLength} characters.`;
    }
    return errors;
  }

  if (step === 3) {
    const rawBudget = projectSetupForm.budgetAmount;
    const budgetValue = Number(rawBudget);
    if (rawBudget === '' || rawBudget === null || rawBudget === undefined) {
      errors.budgetAmount = 'Enter a budget amount.';
    } else if (!Number.isFinite(budgetValue)) {
      errors.budgetAmount = 'Budget must be a valid number.';
    } else if (budgetValue < minimumProjectBudgetMRG) {
      errors.budgetAmount = `Budget must be at least ${formatMRG(minimumProjectBudgetMRG)}.`;
    } else if (budgetValue > maximumProjectBudgetMRG) {
      errors.budgetAmount = `Budget must be ${formatMRG(maximumProjectBudgetMRG)} or less.`;
    }
    if (!budgetTypeOptions.some((item) => item.label === projectSetupForm.budgetType)) {
      errors.budgetAmount = 'Choose a valid budget type.';
    }
    if (!projectSetupForm.startDate) {
      errors.startDate = 'Choose a start date.';
    } else if (!isValidDateInput(projectSetupForm.startDate)) {
      errors.startDate = 'Use a valid start date.';
    } else if (projectSetupForm.startDate < today) {
      errors.startDate = 'Start date cannot be in the past.';
    }
    if (!projectSetupForm.deadline) {
      errors.deadline = 'Choose a deadline.';
    } else if (!isValidDateInput(projectSetupForm.deadline)) {
      errors.deadline = 'Use a valid deadline.';
    } else if (projectSetupForm.startDate && projectSetupForm.deadline < projectSetupForm.startDate) {
      errors.timeline = 'Deadline must be on or after the start date.';
    } else if (projectDurationDays.value > 365) {
      errors.timeline = 'Timeline should be 365 days or less.';
    }
    if (!fundingMethodOptions.some((item) => item.label === projectSetupForm.fundingMethod)) {
      errors.budget = 'Choose a valid funding method.';
    }
    if (!projectSetupForm.skills.trim() && !projectSetupForm.techStack.trim()) {
      errors.skills = 'Add skills required or a tech stack so routing can match talent.';
    } else if (projectSetupForm.skills.trim() && projectSetupForm.skills.trim().length < 3) {
      errors.skills = 'Add at least one recognizable skill.';
    }
    return errors;
  }

  if (step === 4) {
    if (!projectStepIsValid(1)) errors.details = 'Project details are incomplete.';
    if (!projectStepIsValid(2)) errors.scope = 'Scope and deliverables are incomplete.';
    if (!projectStepIsValid(3)) errors.budget = 'Budget, timeline, or skills are incomplete.';
  }
  return errors;
}

function projectValidationList(errors = {}) {
  return Object.entries(errors).map(([field, message]) => ({
    field,
    label: projectValidationLabels[field] || toTitleLabel(field),
    message,
  }));
}

function projectStepNavDone(stepNumber) {
  const step = normalizeProjectWizardStep(stepNumber);
  if (projectWizardStage.value !== 'setup') {
    return step < 4 ? projectStepIsValid(step) : projectAllSetupStepsValid();
  }
  return projectWizardStep.value > step && projectStepIsValid(step);
}

function projectStepNavInvalid(stepNumber) {
  const step = normalizeProjectWizardStep(stepNumber);
  return Boolean(projectStepValidationAttempted[step] && !projectStepIsValid(step));
}

function projectStepNavClass(stepNumber) {
  const step = normalizeProjectWizardStep(stepNumber);
  return {
    active: projectWizardStage.value === 'setup' && projectWizardStep.value === step,
    done: projectStepNavDone(step),
    invalid: projectStepNavInvalid(step),
  };
}

function markProjectFieldTouched(field) {
  if (!field) return;
  projectTouchedFields[field] = true;
  if (field === 'deadline') {
    projectTouchedFields.timeline = true;
  }
}

function projectFieldError(field) {
  if (!projectShouldShowStepErrors.value && !projectTouchedFields[field]) return '';
  return currentProjectValidationErrors.value[field] || '';
}

function projectStepErrorCount(stepNumber) {
  return Object.keys(projectValidationErrorsForStep(stepNumber)).length;
}

function projectStepIsValid(stepNumber) {
  return projectStepErrorCount(stepNumber) === 0;
}

function projectAllSetupStepsValid() {
  return [1, 2, 3].every((step) => projectStepIsValid(step));
}

function markProjectStepValidationAttempted(stepNumber) {
  projectStepValidationAttempted[normalizeProjectWizardStep(stepNumber)] = true;
}

function resetProjectValidation() {
  for (const step of [1, 2, 3, 4]) {
    projectStepValidationAttempted[step] = false;
  }
  for (const key of Object.keys(projectTouchedFields)) {
    delete projectTouchedFields[key];
  }
  projectFundingValidationAttempted.value = false;
  projectPaymentError.value = '';
  priceEvaluationValidationErrors.value = {};
  priceEvaluationShouldShowErrors.value = false;
}

function firstInvalidProjectStep(upToStep = 4) {
  const limit = normalizeProjectWizardStep(upToStep);
  for (const step of [1, 2, 3]) {
    if (step > limit) break;
    if (!projectStepIsValid(step)) return step;
  }
  if (limit === 4 && !projectStepIsValid(4)) return 4;
  return 0;
}

function focusFirstProjectValidationError() {
  if (!hasWindow) return;
  const focusTarget = () => {
    const selectors = [
      '.wizard-field.invalid input',
      '.wizard-field.invalid textarea',
      '.wizard-field.invalid select',
      '.wizard-section.invalid .rich-editor textarea',
      '.wizard-section.invalid .deliverable-row input',
      '.wizard-section.invalid .select-tile',
      '.wizard-validation-banner',
    ];
    const target = selectors
      .map((selector) => document.querySelector(selector))
      .find((element) => element && element.offsetParent !== null);
    if (!target) return false;
    target.scrollIntoView({ behavior: 'smooth', block: 'center' });
    if (typeof target?.focus === 'function') {
      target.focus({ preventScroll: true });
    }
    return document.activeElement === target || !['INPUT', 'TEXTAREA', 'SELECT', 'BUTTON'].includes(target.tagName);
  };
  window.requestAnimationFrame(() => {
    if (!focusTarget()) {
      window.setTimeout(focusTarget, 120);
    }
  });
}

function showProjectValidationToast(stepNumber) {
  const count = projectStepErrorCount(stepNumber);
  showToast(count === 1 ? 'Fix 1 required item before continuing.' : `Fix ${count} required items before continuing.`);
}

function openNextProjectQualityIssue() {
  const invalidStep = firstInvalidProjectStep(4);
  if (!invalidStep) {
    goProjectStep(4);
    return;
  }
  markProjectStepValidationAttempted(invalidStep);
  goProjectStep(invalidStep, { skipValidation: true });
  showProjectValidationToast(invalidStep);
  void nextTick().then(focusFirstProjectValidationError);
}

function projectQualityStepForItem(item = {}) {
  if (item.key === 'details') return 1;
  if (item.key === 'scope') return 2;
  if (item.key === 'budget') return 3;
  return 4;
}

function openProjectQualityItem(item = {}) {
  const step = projectQualityStepForItem(item);
  markProjectStepValidationAttempted(step);
  goProjectStep(step, { skipValidation: true });
  showProjectValidationToast(step);
  void nextTick().then(focusFirstProjectValidationError);
}

function guardProjectWizardRouteValidation(options = {}) {
  if (projectWizardStage.value !== 'setup' || projectWizardStep.value <= 1) return false;
  const invalidStep = firstInvalidProjectStep(projectWizardStep.value - 1);
  if (!invalidStep) return false;
  markProjectStepValidationAttempted(invalidStep);
  projectPreviewVisible.value = false;
  projectWizardStep.value = invalidStep;
  updateProjectWizardBrowserPath(Boolean(options.replace));
  scrollProjectFlowTop();
  if (!options.silent) {
    showProjectValidationToast(invalidStep);
  }
  void nextTick().then(focusFirstProjectValidationError);
  return true;
}

function projectFundingFieldError(field) {
  if (!projectFundingShouldShowErrors.value) return '';
  return projectFundingValidationErrors.value[field] || '';
}

function projectFundingErrorCount() {
  return Object.keys(projectFundingValidationErrors.value).length;
}

function showProjectFundingValidationToast() {
  const count = projectFundingErrorCount();
  showToast(count === 1 ? 'Fix 1 payment item before funding.' : `Fix ${count} payment items before funding.`);
}

function focusFirstProjectFundingValidationError() {
  if (!hasWindow) return;
  window.requestAnimationFrame(() => {
    const target = document.querySelector('.project-funding-validation, .funding-panel .wizard-field.invalid input, .funding-panel .wizard-section.invalid button');
    target?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    if (typeof target?.focus === 'function') {
      target.focus({ preventScroll: true });
    }
  });
}

function cardDigitsFrom(value = '') {
  return String(value || '').replace(/\D/g, '');
}

function cardCvcDigitsFrom(value = '') {
  return String(value || '').trim();
}

function projectCardDigits() {
  return cardDigitsFrom(projectCardForm.cardNumber);
}

function projectCardCvcDigits() {
  return cardCvcDigitsFrom(projectCardForm.cvc);
}

function projectCardExpiryDetails(value = projectCardForm.expiry) {
  const raw = String(value || '').trim();
  if (!raw) {
    return { error: 'Enter expiry date in MM/YY.' };
  }

  const normalized = raw.replace(/[\s.-]+/g, '/').replace(/\/+/g, '/');
  let parts = normalized.split('/').filter(Boolean);
  if (parts.length === 1) {
    const digits = normalized.replace(/\D/g, '');
    if (digits.length === 4 || digits.length === 6) {
      parts = [digits.slice(0, 2), digits.slice(2)];
    }
  }
  if (parts.length !== 2 || !/^\d+$/.test(parts[0]) || !/^\d+$/.test(parts[1])) {
    return { error: 'Use MM/YY for the expiry date.' };
  }

  const month = Number(parts[0]);
  if (!Number.isInteger(month) || month < 1 || month > 12) {
    return { error: 'Expiry month must be between 01 and 12.' };
  }

  const yearPart = parts[1];
  if (yearPart.length !== 2 && yearPart.length !== 4) {
    return { error: 'Use a 2 or 4 digit expiry year.' };
  }
  let year = Number(yearPart);
  if (!Number.isInteger(year)) {
    return { error: 'Expiry year is invalid.' };
  }
  if (year < 100) {
    year += 2000;
  }

  const expiresAt = new Date(Date.UTC(year, month, 1));
  if (!expiresAt.getTime() || expiresAt <= new Date()) {
    return { error: 'Card is expired.' };
  }

  const normalizedYear = yearPart.length === 2 ? String(yearPart).padStart(2, '0') : String(year);
  return { normalized: `${String(month).padStart(2, '0')}/${normalizedYear}` };
}

function projectCardExpiryForPayload() {
  return projectCardExpiryDetails().normalized || projectCardForm.expiry;
}

function repoTaskCardDigits() {
  return cardDigitsFrom(repoTaskFundingCardForm.cardNumber);
}

function repoTaskCardCvcDigits() {
  return cardCvcDigitsFrom(repoTaskFundingCardForm.cvc);
}

function repoTaskCardExpiryForPayload() {
  return projectCardExpiryDetails(repoTaskFundingCardForm.expiry).normalized || repoTaskFundingCardForm.expiry;
}

function luhnValid(value = '') {
  let sum = 0;
  let doubleDigit = false;
  for (let index = value.length - 1; index >= 0; index -= 1) {
    let digit = Number(value[index]);
    if (!Number.isInteger(digit)) return false;
    if (doubleDigit) {
      digit *= 2;
      if (digit > 9) digit -= 9;
    }
    sum += digit;
    doubleDigit = !doubleDigit;
  }
  return sum > 0 && sum % 10 === 0;
}

function projectDevPaymentReference() {
  return runtimeConfig.value?.dev_payment_enabled && runtimeConfig.value?.dev_payment_code
    ? runtimeConfig.value.dev_payment_code
    : '';
}

function projectFundingValidationErrorsForCurrentSelection() {
  const errors = {};
  const amount = Number(projectFundingAmount.value);
  const paymentMethod = paymentMethodForProject();
  const config = runtimeConfig.value;
  const devPaymentReference = projectDevPaymentReference();

  if (!Number.isFinite(amount) || amount <= 0) {
    errors.amount = 'Choose an escrow amount before funding.';
  } else if (amount < minimumProjectFundingUSD) {
    errors.amount = `Escrow funding must be at least ${formatMoney(minimumProjectFundingUSD)} USD.`;
  }

  if (config) {
    if (paymentMethod === 'card' && !config.card_ready) {
      errors.paymentMethod = 'Card checkout is not configured for this environment.';
    }
    if (paymentMethod === 'paypal' && !config.paypal_ready && !devPaymentReference) {
      errors.paymentMethod = 'PayPal checkout is not configured. Choose card or enable PayPal.';
    }
    if (paymentMethod === 'crypto' && !config.crypto_ready && !devPaymentReference) {
      errors.paymentMethod = 'USDC verification is not configured. Choose another method or enable crypto verification.';
    }
  }

  if (paymentMethod === 'card') {
    const digits = projectCardDigits();
    if (!digits) {
      errors.cardNumber = 'Enter the card number.';
    } else if (digits.length < 12 || digits.length > 19 || !luhnValid(digits)) {
      errors.cardNumber = 'Card number is invalid.';
    }

    const expiry = projectCardExpiryDetails();
    if (expiry.error) {
      errors.cardExpiry = expiry.error;
    }

    const cvc = projectCardCvcDigits();
    if (!/^\d{3,4}$/.test(cvc)) {
      errors.cardCvc = 'CVC must be 3 or 4 digits.';
    }

    if (String(projectCardForm.cardholderName || '').trim().length < 2) {
      errors.cardholderName = 'Enter the cardholder name shown on the card.';
    }
  }

  if (paymentMethod === 'crypto' && !devPaymentReference) {
    const reference = String(projectCryptoReference.value || '').trim();
    if (!reference) {
      errors.cryptoReference = 'Paste the confirmed Solana transaction signature.';
    } else if (!/^[1-9A-HJ-NP-Za-km-z]{80,100}$/.test(reference)) {
      errors.cryptoReference = 'Signature must be a Solana base58 transaction signature.';
    }
  }

  return errors;
}

function repoTaskFundingFieldError(field) {
  if (!repoTaskFundingShouldShowErrors.value) return '';
  return repoTaskFundingValidationErrors.value[field] || '';
}

function repoTaskFundingErrorCount() {
  return Object.keys(repoTaskFundingValidationErrors.value).length;
}

function paymentMethodForRepoTaskFunding() {
  if (repoTaskFundingMethod.value === 'Credit / Debit card') return 'card';
  if (repoTaskFundingMethod.value === 'USDC') return 'crypto';
  return 'paypal';
}

function repoTaskFundingValidationErrorsForCurrentSelection() {
  const errors = {};
  const paymentMethod = paymentMethodForRepoTaskFunding();
  const config = runtimeConfig.value;
  const devPaymentReference = projectDevPaymentReference();

  if (!repoTaskFundingTask.value?.id) {
    errors.details = 'Choose a suggested task to fund.';
  }
  if (repoTaskFundingAmountCents.value < minimumProjectFundingUSD * 100) {
    errors.amount = `Escrow funding must be at least ${formatMoney(minimumProjectFundingUSD)} USD.`;
  }

  if (config) {
    if (paymentMethod === 'card' && !config.card_ready) {
      errors.paymentMethod = 'Card checkout is not configured for this environment.';
    }
    if (paymentMethod === 'paypal' && !config.paypal_ready && !devPaymentReference) {
      errors.paymentMethod = 'PayPal checkout is not configured. Choose card or enable PayPal.';
    }
    if (paymentMethod === 'crypto' && !config.crypto_ready && !devPaymentReference) {
      errors.paymentMethod = 'USDC verification is not configured. Choose another method or enable crypto verification.';
    }
  }

  if (paymentMethod === 'card') {
    const digits = repoTaskCardDigits();
    if (!digits) {
      errors.cardNumber = 'Enter the card number.';
    } else if (digits.length < 12 || digits.length > 19 || !luhnValid(digits)) {
      errors.cardNumber = 'Card number is invalid.';
    }

    const expiry = projectCardExpiryDetails(repoTaskFundingCardForm.expiry);
    if (expiry.error) {
      errors.cardExpiry = expiry.error;
    }

    if (!/^\d{3,4}$/.test(repoTaskCardCvcDigits())) {
      errors.cardCvc = 'CVC must be 3 or 4 digits.';
    }

    if (String(repoTaskFundingCardForm.cardholderName || '').trim().length < 2) {
      errors.cardholderName = 'Enter the cardholder name shown on the card.';
    }
  }

  if (paymentMethod === 'crypto' && !devPaymentReference) {
    const reference = String(repoTaskFundingCryptoReference.value || '').trim();
    if (!reference) {
      errors.cryptoReference = 'Paste the confirmed Solana transaction signature.';
    } else if (!/^[1-9A-HJ-NP-Za-km-z]{80,100}$/.test(reference)) {
      errors.cryptoReference = 'Signature must be a Solana base58 transaction signature.';
    }
  }

  return errors;
}

function displayNameFromRepo(repo) {
  if (!repo?.name) return 'software delivery workflow';
  return repo.name
    .replace(/[-_]+/g, ' ')
    .replace(/\b\w/g, (char) => char.toUpperCase());
}

function mergeDeliverableSuggestions(suggestions = []) {
  const existing = visibleDeliverables.value;
  const seen = new Set(existing.map((item) => item.toLowerCase()));
  const next = [...existing];
  for (const suggestion of suggestions) {
    const clean = String(suggestion || '').trim();
    if (!clean || seen.has(clean.toLowerCase())) continue;
    seen.add(clean.toLowerCase());
    next.push(clean);
  }
  projectDeliverables.value = next.length ? next : [''];
}

function inferSkillList() {
  const stack = projectSetupForm.techStack.trim();
  const base = stack
    ? stack.split(/[,;/|]+/).map((item) => item.trim()).filter(Boolean)
    : ['Frontend', 'Backend', 'QA', 'DevOps'];
  const merged = new Set([...base, projectSetupForm.allowAgents ? 'AI orchestration' : '', 'Code review'].filter(Boolean));
  return Array.from(merged).slice(0, 8).join(', ');
}

function runProjectBriefAssistant() {
  if (briefAssistantBusy.value) return;
  briefAssistantBusy.value = true;
  try {
    const repo = parseRepoDescriptor(projectSetupForm.repoUrl);
    const repoLabel = repo?.label || '';
    const projectName = displayNameFromRepo(repo);
    const isBugFix = projectSetupForm.projectType === 'Bug Fix' || Boolean(repoLabel);

    if (!projectSetupForm.projectType) {
      projectSetupForm.projectType = isBugFix ? 'Bug Fix' : 'New Project';
    }
    if (!projectSetupForm.title.trim()) {
      projectSetupForm.title = isBugFix
        ? `Stabilize and ship ${projectName}`
        : 'Build an AI-orchestrated software delivery workflow';
    }
    if (!projectSetupForm.shortDescription.trim()) {
      projectSetupForm.shortDescription = isBugFix
        ? `Import ${repoLabel || 'the repository'}, scan technical debt, generate payable tasks, and validate fixes through review and deployment gates.`
        : 'Design and build a production-ready workflow with task generation, contributor routing, escrow-backed delivery, and public ledger proof.';
    }
    if (!projectSetupForm.overview.trim()) {
      projectSetupForm.overview = [
        `Goal: ${projectSetupForm.shortDescription.trim()}`,
        repoLabel ? `Repository: ${repoLabel}` : '',
        'Workflow: scan the scope, split the work into reviewable tasks, route tasks to human or AI workers, then verify PRs before release.',
        'Definition of done: accepted tasks have evidence, review notes, deployment validation, and ledger references.',
      ].filter(Boolean).join('\n\n');
    }
    mergeDeliverableSuggestions(isBugFix ? [
      'Repository scan with bugs, dependency risk, and technical debt findings',
      'Prioritized task graph with reward estimates and worker lane routing',
      'Implementation PRs with tests, screenshots, or deployment evidence',
      'AI review and QA validation report before payment release',
    ] : [
      'Product workflow map from repository import to payment release',
      'Customer dashboard with projects, tasks, escrow, AI logs, and deployments',
      'Marketplace views for live projects, public bounties, contributors, and AI agents',
      'Ledger-backed release flow with audit-ready payout records',
    ]);
    if (!projectSetupForm.requirements.trim()) {
      projectSetupForm.requirements = [
        'All work must include clear acceptance criteria and evidence.',
        'Task status, escrow state, AI actions, and deployment progress must stay visible in the dashboard.',
        'Contributor and AI-agent actions must be traceable through ledger or live-feed events.',
        'Implementation must include loading, empty, retry, and error states for user-facing flows.',
      ].join('\n');
    }
    if (!projectSetupForm.skills.trim()) {
      projectSetupForm.skills = inferSkillList();
    }
    if (!projectSetupForm.complexity) {
      projectSetupForm.complexity = isBugFix ? 'Medium' : 'High';
    }
    showToast('AI assistant structured the project brief.');
    if (projectWizardStep.value === 1) {
      goProjectStep(2);
    }
  } finally {
    briefAssistantBusy.value = false;
  }
}

function openReferenceFilePicker() {
  referenceUploadError.value = '';
  referenceFileInput.value?.click();
}

async function handleReferenceFilesSelected(event) {
  await uploadReferenceFiles(event?.target?.files);
  if (event?.target) {
    event.target.value = '';
  }
}

async function handleReferenceDrop(event) {
  await uploadReferenceFiles(event?.dataTransfer?.files);
}

async function uploadReferenceFiles(filesLike) {
  const files = Array.from(filesLike || []).filter((file) => file && file.size > 0);
  referenceUploadError.value = '';
  if (!files.length) return;

  if (!user.value || !token.value) {
    authReturnToProjectWizard.value = true;
    projectWizardVisible.value = false;
    openAuth('login');
    showToast('Log in to upload reference files.');
    return;
  }

  const oversized = files.find((file) => file.size > MAX_REFERENCE_UPLOAD_BYTES);
  if (oversized) {
    referenceUploadError.value = `${oversized.name} is larger than 15MB.`;
    showToast(referenceUploadError.value);
    return;
  }

  const form = new FormData();
  for (const file of files) {
    form.append('files', file);
  }

  referenceUploadBusy.value = true;
  try {
    const response = await fetch('/api/uploads', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${token.value}`,
      },
      body: form,
    });
    const text = await response.text();
    let payload = [];
    try {
      payload = text ? JSON.parse(text) : [];
    } catch {
      payload = { error: text || 'Upload failed' };
    }
    if (!response.ok) {
      if (response.status === 401) clearSession();
      throw createRequestError(response, payload);
    }
    const uploaded = Array.isArray(payload) ? payload : [payload];
    const byID = new Map(referenceAttachments.value.map((attachment) => [attachment.id, attachment]));
    for (const attachment of uploaded) {
      if (attachment?.id) byID.set(attachment.id, attachment);
    }
    referenceAttachments.value = Array.from(byID.values());
    showToast(`${uploaded.length} reference file${uploaded.length === 1 ? '' : 's'} uploaded.`);
  } catch (error) {
    referenceUploadError.value = error.message || 'Could not upload files.';
    showToast(referenceUploadError.value);
  } finally {
    referenceUploadBusy.value = false;
  }
}

function removeReferenceAttachment(id) {
  referenceAttachments.value = referenceAttachments.value.filter((attachment) => attachment.id !== id);
}

function projectDraftAttachment(attachment = {}) {
  return {
    id: attachment.id || '',
    original_name: attachment.original_name || '',
    stored_name: attachment.stored_name || '',
    content_type: attachment.content_type || '',
    size_bytes: Number(attachment.size_bytes) || 0,
    url: attachment.url || '',
    is_image: Boolean(attachment.is_image),
    created_at: attachment.created_at || '',
  };
}

function buildProjectDraft() {
  const setup = {};
  for (const key of Object.keys(projectSetupDefaults)) {
    setup[key] = projectSetupForm[key];
  }
  return {
    version: 1,
    saved_at: new Date().toISOString(),
    wizard_stage: projectWizardStage.value === 'funding' ? 'funding' : 'setup',
    wizard_step: normalizeProjectWizardStep(projectWizardStep.value),
    setup,
    deliverables: projectDeliverables.value.map((item) => String(item || '')),
    funding_amount: Number(projectFundingAmount.value) || '',
    payment_method: supportedProjectPaymentMethod(projectPaymentMethod.value),
    crypto_reference: String(projectCryptoReference.value || '').trim(),
    reference_attachments: referenceAttachments.value.map(projectDraftAttachment).filter((attachment) => attachment.id),
  };
}

function projectDraftHasContent(draft = {}) {
  const setup = draft.setup || {};
  return Object.keys(projectSetupDefaults).some((key) => {
    const value = setup[key];
    const fallback = projectSetupDefaults[key];
    return typeof value === 'boolean' ? value !== fallback : String(value || '').trim() !== String(fallback || '').trim();
  }) || (Array.isArray(draft.deliverables) && draft.deliverables.some((item) => String(item || '').trim()))
    || Number(draft.funding_amount) > 0
    || String(draft.crypto_reference || '').trim() !== ''
    || (Array.isArray(draft.reference_attachments) && draft.reference_attachments.length > 0);
}

function currentProjectDraftHasContent() {
  return projectDraftHasContent(buildProjectDraft());
}

function supportedProjectPaymentMethod(value = '') {
  const label = String(value || '').trim();
  const labels = paymentMethodOptions.map((method) => method.label);
  return labels.includes(label) ? label : 'Credit / Debit card';
}

function normalizeProjectDraft(raw = {}) {
  if (!raw || typeof raw !== 'object') return null;
  const setup = {};
  const rawSetup = raw.setup && typeof raw.setup === 'object' ? raw.setup : {};
  for (const [key, fallback] of Object.entries(projectSetupDefaults)) {
    if (typeof fallback === 'boolean') {
      setup[key] = typeof rawSetup[key] === 'boolean' ? rawSetup[key] : fallback;
    } else {
      setup[key] = rawSetup[key] === undefined || rawSetup[key] === null ? fallback : String(rawSetup[key]);
    }
  }
  const deliverables = Array.isArray(raw.deliverables)
    ? raw.deliverables.map((item) => String(item || '')).slice(0, 20)
    : [''];
  const attachments = Array.isArray(raw.reference_attachments)
    ? raw.reference_attachments.map(projectDraftAttachment).filter((attachment) => attachment.id).slice(0, 20)
    : [];
  return {
    version: 1,
    saved_at: String(raw.saved_at || ''),
    wizard_stage: raw.wizard_stage === 'funding' ? 'funding' : 'setup',
    wizard_step: normalizeProjectWizardStep(raw.wizard_step),
    setup,
    deliverables: deliverables.length ? deliverables : [''],
    funding_amount: Number(raw.funding_amount) > 0 ? Number(raw.funding_amount) : '',
    payment_method: supportedProjectPaymentMethod(raw.payment_method),
    crypto_reference: String(raw.crypto_reference || '').trim(),
    reference_attachments: attachments,
  };
}

function readProjectDraft() {
  try {
    const raw = browserStorage?.getItem(projectDraftStorageKey);
    if (!raw) return null;
    return normalizeProjectDraft(JSON.parse(raw));
  } catch {
    return null;
  }
}

function applyProjectDraft(draft = {}, options = {}) {
  Object.assign(projectSetupForm, draft.setup || projectSetupDefaults);
  projectDeliverables.value = Array.isArray(draft.deliverables) && draft.deliverables.length ? draft.deliverables : [''];
  projectFundingAmount.value = draft.funding_amount || '';
  projectPaymentMethod.value = supportedProjectPaymentMethod(draft.payment_method);
  projectCryptoReference.value = draft.crypto_reference || '';
  referenceAttachments.value = Array.isArray(draft.reference_attachments) ? draft.reference_attachments : [];
  priceEvaluation.value = null;
  priceEvaluationError.value = '';
  repoImportError.value = '';
  if (options.restoreStep) {
    projectWizardStage.value = draft.wizard_stage === 'funding' ? 'funding' : 'setup';
    projectWizardStep.value = normalizeProjectWizardStep(draft.wizard_step);
  }
}

function restoreProjectDraft(options = {}) {
  const draft = readProjectDraft();
  if (!draft || !projectDraftHasContent(draft)) return false;
  if (!options.force && currentProjectDraftHasContent()) return false;
  applyProjectDraft(draft, options);
  if (!options.silent) {
    showToast(draft.saved_at ? 'Project draft restored.' : 'Project draft loaded.');
  }
  return true;
}

function saveProjectDraft() {
  if (!browserStorage) {
    showToast('Local draft storage is not available in this browser.');
    return false;
  }
  const draft = buildProjectDraft();
  if (!projectDraftHasContent(draft)) {
    showToast('Add project details before saving a draft.');
    return false;
  }
  try {
    browserStorage.setItem(projectDraftStorageKey, JSON.stringify(draft));
    showToast('Project draft saved locally.');
    return true;
  } catch {
    showToast('Could not save the project draft locally.');
    return false;
  }
}

function clearProjectDraft() {
  try {
    browserStorage?.removeItem(projectDraftStorageKey);
  } catch {
    // Draft cleanup is best-effort and should not block checkout completion.
  }
}

function openAuthFromProjectWizard(mode = 'login') {
  closeProjectWizard();
  openAuth(mode);
}

async function openProjectPreview() {
  const invalidStep = firstInvalidProjectStep(4);
  if (invalidStep) {
    markProjectStepValidationAttempted(invalidStep);
    goProjectStep(invalidStep, { skipValidation: true });
    showProjectValidationToast(invalidStep);
    await nextTick();
    focusFirstProjectValidationError();
    return;
  }
  projectWizardStage.value = 'setup';
  projectWizardStep.value = 4;
  projectPreviewVisible.value = true;
  updateProjectWizardBrowserPath();
  await nextTick();
  projectPreviewDialog.value?.focus({ preventScroll: true });
}

function closeProjectPreview() {
  projectPreviewVisible.value = false;
}

function editProjectPreviewStep(stepNumber = 1) {
  closeProjectPreview();
  goProjectStep(stepNumber);
}

function publishProjectFromPreview() {
  closeProjectPreview();
  nextProjectStep();
}

function goProjectStep(stepNumber, options = {}) {
  const targetStep = normalizeProjectWizardStep(stepNumber);
  if (!options.skipValidation && projectWizardStage.value === 'setup' && targetStep > projectWizardStep.value) {
    const invalidStep = firstInvalidProjectStep(targetStep - 1);
    if (invalidStep) {
      markProjectStepValidationAttempted(invalidStep);
      projectPreviewVisible.value = false;
      projectWizardStage.value = 'setup';
      projectWizardStep.value = invalidStep;
      updateProjectWizardBrowserPath();
      scrollProjectFlowTop();
      showProjectValidationToast(invalidStep);
      void nextTick().then(focusFirstProjectValidationError);
      return;
    }
  }
  clearToast();
  projectPreviewVisible.value = false;
  projectWizardStage.value = 'setup';
  projectWizardStep.value = targetStep;
  updateProjectWizardBrowserPath();
  scrollProjectFlowTop();
}

function nextProjectStep() {
  projectPreviewVisible.value = false;
  const invalidStep = firstInvalidProjectStep(projectWizardStep.value);
  if (invalidStep) {
    markProjectStepValidationAttempted(invalidStep);
    if (invalidStep !== projectWizardStep.value) {
      projectWizardStep.value = invalidStep;
      updateProjectWizardBrowserPath();
      scrollProjectFlowTop();
    }
    showProjectValidationToast(invalidStep);
    void nextTick().then(focusFirstProjectValidationError);
    return;
  }

  if (projectWizardStep.value < 4) {
    clearToast();
    projectWizardStep.value += 1;
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    return;
  }

  if (projectBudgetAmount.value > 0 && projectBudgetAmount.value < TOKEN_RATE_PER_USD * 100) {
    projectSetupForm.budgetAmount = TOKEN_RATE_PER_USD * 100;
  }
  projectFundingAmount.value = Math.max(100, Math.ceil(projectBudgetAmount.value / TOKEN_RATE_PER_USD) || projectFundingAmount.value);
  projectWizardStage.value = 'funding';
  updateProjectWizardBrowserPath();
  scrollProjectFlowTop();
  showToast('Project published. Add funds to start receiving proposals.');
}

function buildPriceEvaluationPayload() {
  return {
    title: projectSetupForm.title,
    description: [projectSetupForm.shortDescription, projectSetupForm.overview].filter(Boolean).join('\n\n'),
    project_type: projectSetupForm.projectType,
    requirements: projectSetupForm.requirements,
    deliverables: visibleDeliverables.value,
    timeline: projectTimelineLabel.value,
    tech_stack: projectSetupForm.techStack,
    complexity: projectSetupForm.allowAgents ? 'moderate' : 'high',
    constraints: projectSetupForm.skills,
    reference_budget_cents: centsFromMRG(projectSetupForm.budgetAmount),
  };
}

function priceEvaluationValidationErrorsForCurrentInput() {
  const errors = {};
  const title = projectSetupForm.title.trim();
  const scope = [
    projectSetupForm.shortDescription,
    projectSetupForm.overview,
    projectSetupForm.requirements,
  ].filter(Boolean).join(' ').replace(/\s+/g, ' ').trim();

  if (title.length < 8) {
    errors.title = 'Enter a project title with at least 8 characters.';
  }
  if (scope.length < 40) {
    errors.scope = 'Describe the scope in at least 40 characters before estimating.';
  }
  return errors;
}

function firstPriceEvaluationError(errors = priceEvaluationValidationErrors.value) {
  return errors.title || errors.scope || Object.values(errors)[0] || '';
}

function priceEvaluationFieldError(field = '') {
  if (!priceEvaluationShouldShowErrors.value) return '';
  return priceEvaluationValidationErrors.value[field] || '';
}

function clearPriceEvaluationFieldError(field = '') {
  if (!field || !priceEvaluationValidationErrors.value[field]) return;
  priceEvaluationValidationErrors.value = {
    ...priceEvaluationValidationErrors.value,
    [field]: '',
  };
  for (const [key, message] of Object.entries(priceEvaluationValidationErrors.value)) {
    if (!message) delete priceEvaluationValidationErrors.value[key];
  }
  if (!Object.keys(priceEvaluationValidationErrors.value).length) {
    priceEvaluationError.value = '';
  }
}

function focusFirstPriceEvaluationValidationError() {
  if (!hasWindow) return;
  window.requestAnimationFrame(() => {
    const target = document.querySelector('.dashboard-tool-form label.invalid input, .dashboard-tool-form label.invalid textarea');
    target?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    target?.focus?.({ preventScroll: true });
  });
}

async function runProjectPriceEvaluation() {
  priceEvaluationError.value = '';
  priceEvaluationShouldShowErrors.value = true;
  const validationErrors = priceEvaluationValidationErrorsForCurrentInput();
  priceEvaluationValidationErrors.value = validationErrors;
  if (Object.keys(validationErrors).length) {
    priceEvaluation.value = null;
    priceEvaluationError.value = firstPriceEvaluationError(validationErrors);
    showToast(priceEvaluationError.value);
    if (projectWizardVisible.value) {
      const invalidStep = validationErrors.title ? 1 : 2;
      markProjectStepValidationAttempted(invalidStep);
      projectWizardStep.value = invalidStep;
      updateProjectWizardBrowserPath();
      void nextTick().then(focusFirstProjectValidationError);
    } else {
      void nextTick().then(focusFirstPriceEvaluationValidationError);
    }
    return;
  }
  if (!user.value) {
    authReturnToProjectWizard.value = projectWizardVisible.value;
    if (projectWizardVisible.value) {
      projectWizardVisible.value = false;
    }
    openAuth('login');
    showToast('Log in to estimate this project.');
    return;
  }
  if (priceEvaluationBusy.value) return;
  priceEvaluationBusy.value = true;
  try {
    priceEvaluation.value = await api('/api/projects/evaluate-price', {
      method: 'POST',
      body: JSON.stringify(buildPriceEvaluationPayload()),
    });
    priceEvaluationValidationErrors.value = {};
    priceEvaluationShouldShowErrors.value = false;
    applyPriceEvaluation();
    showToast('Budget estimate generated.');
  } catch (error) {
    priceEvaluationError.value = error.message;
    showToast(error.message);
  } finally {
    priceEvaluationBusy.value = false;
  }
}

function applyPriceEvaluation() {
  if (!priceEvaluation.value?.suggested_price_cents) return;
  projectSetupForm.budgetAmount = Math.max(TOKEN_RATE_PER_USD * 100, tokenAmountFromCents(priceEvaluation.value.suggested_price_cents));
  projectSetupForm.budgetType = 'Range';
}

function projectWizardBack() {
  if (projectWizardStage.value === 'success') {
    projectWizardStage.value = 'funding';
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    return;
  }

  if (projectWizardStage.value === 'funding') {
    projectWizardStage.value = 'setup';
    projectWizardStep.value = 4;
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    return;
  }

  if (projectWizardStep.value > 1) {
    projectWizardStep.value -= 1;
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    return;
  }

  closeProjectWizard();
}

function requireLoginForProjectPayment() {
  pendingProjectPaymentAfterAuth.value = true;
  authReturnToProjectWizard.value = true;
  projectPaymentError.value = '';
  projectWizardVisible.value = false;
  openAuth('login');
  showToast('Log in to continue payment.');
}

async function completeProjectFunding() {
  projectFundingValidationAttempted.value = true;
  projectPaymentError.value = '';

  const invalidStep = firstInvalidProjectStep(4);
  if (invalidStep) {
    projectWizardStage.value = 'setup';
    projectWizardStep.value = invalidStep;
    markProjectStepValidationAttempted(invalidStep);
    updateProjectWizardBrowserPath();
    scrollProjectFlowTop();
    showProjectValidationToast(invalidStep);
    void nextTick().then(focusFirstProjectValidationError);
    return;
  }

  try {
    await loadRuntimeConfig();
  } catch (error) {
    projectPaymentError.value = error.message || 'Could not load payment configuration.';
    showToast(projectPaymentError.value);
    return;
  }

  if (projectFundingErrorCount()) {
    showProjectFundingValidationToast();
    void nextTick().then(focusFirstProjectFundingValidationError);
    return;
  }

  if (!user.value) {
    requireLoginForProjectPayment();
    return;
  }

  if (projectPaymentBusy.value) return;
  projectPaymentBusy.value = true;
  try {
    const paymentMethod = paymentMethodForProject();
    if (paymentMethod === 'card') {
      const intent = await createProjectCardPaymentIntent();
      await submitProjectFunding(buildCreateProjectPayload({
        payment_method: 'card',
        payment_reference: intent.payment_reference,
      }), {
        paymentMethodLabel: cardPaymentLabel(intent),
      });
      return;
    }
    const devPaymentReference = projectDevPaymentReference();
    if (devPaymentReference) {
      await submitProjectFunding(buildCreateProjectPayload({
        payment_method: paymentMethod,
        payment_reference: devPaymentReference,
      }));
      return;
    }
    if (paymentMethod === 'paypal' && runtimeConfig.value?.paypal_ready) {
      await startProjectPayPalFunding();
      return;
    }
    if (paymentMethod === 'crypto') {
      if (!projectCryptoReference.value) {
        throw new Error('Paste the confirmed Solana transaction signature before funding.');
      }
      await submitProjectFunding(buildCreateProjectPayload({
        payment_method: 'crypto',
        payment_reference: projectCryptoReference.value,
      }), {
        paymentMethodLabel: 'USDC',
      });
      return;
    }
    throw new Error(paymentMethod === 'crypto'
      ? 'Crypto checkout needs a Solana signature before project funding can be verified.'
      : 'PayPal checkout is not configured. Enable PayPal credentials or local dev payments.');
  } catch (error) {
    if (error.status === 401 || /login is required/i.test(error.message || '')) {
      requireLoginForProjectPayment();
      return;
    }
    projectPaymentError.value = error.message;
    showToast(error.message);
  } finally {
    projectPaymentBusy.value = false;
  }
}

async function createProjectCardPaymentIntent() {
  return createCardPaymentIntent({
    amount_cents: projectPaymentAmountCents.value,
    card_number: projectCardDigits(),
    expiry: projectCardExpiryForPayload(),
    cvc: projectCardCvcDigits(),
    cardholder_name: projectCardForm.cardholderName || user.value?.name || '',
  });
}

async function createCardPaymentIntent(payload = {}) {
  const intent = await api('/api/payments/card/intents', {
    method: 'POST',
    body: JSON.stringify(payload),
  });
  if (!intent?.payment_reference) {
    throw new Error('Card processor did not return a payment reference.');
  }
  return intent;
}

function cardPaymentLabel(intent = {}) {
  const brand = toTitleLabel(intent.brand || 'card');
  return intent.last4 ? `${brand} ending ${intent.last4}` : 'Credit / Debit card';
}

async function startProjectPayPalFunding() {
  if (!hasWindow) {
    throw new Error('PayPal checkout requires a browser session.');
  }
  const payload = buildCreateProjectPayload({
    payment_method: 'paypal',
    payment_reference: '',
  });
  const returnURL = absolutePublicPath('/paypal/return?flow=project_funding');
  const cancelURL = absolutePublicPath('/paypal/cancel?flow=project_funding');
  const order = await api('/api/payments/paypal/orders', {
    method: 'POST',
    body: JSON.stringify({
      amount_cents: payload.budget_cents,
      description: projectPayPalDescription(payload),
      return_url: returnURL,
      cancel_url: cancelURL,
    }),
  });
  if (!order?.approval_url || !order?.order_id) {
    throw new Error('PayPal did not return an approval URL.');
  }
  writePendingProjectFunding({
    flow: 'project_funding',
    payload,
    fundingAmount: Number(projectFundingAmount.value) || Math.round(payload.budget_cents / 100),
    paymentMethodLabel: projectPaymentMethod.value,
    orderID: order.order_id,
    createdAt: Date.now(),
  });
  showToast('Redirecting to PayPal checkout...');
  window.location.href = order.approval_url;
}

async function submitProjectFunding(payload = {}, options = {}) {
  const project = await api('/api/projects', {
    method: 'POST',
    body: JSON.stringify(payload),
  });
  fundedProject.value = project;
  if (Number(options.fundingAmount) > 0) {
    projectFundingAmount.value = Number(options.fundingAmount);
  } else if (Number(payload.budget_cents) > 0) {
    projectFundingAmount.value = Math.max(100, Math.round(Number(payload.budget_cents) / 100));
  }
  projectPaymentSuccessMethod.value = options.paymentMethodLabel || projectPaymentMethod.value;
  projectWizardVisible.value = true;
  projectWizardStage.value = 'success';
  projectWizardStep.value = 4;
  updateProjectWizardBrowserPath(Boolean(options.replacePath));
  pendingProjectPaymentAfterAuth.value = false;
  authReturnToProjectWizard.value = false;
  await loadLedgerData({ silent: true });
  await loadMarketplaceData({ silent: true });
  await loadDashboardData({ silent: true, selectProjectID: project.id });
  referenceAttachments.value = [];
  referenceUploadError.value = '';
  clearProjectDraft();
  resetProjectPaymentInputs();
  scrollProjectFlowTop();
  showToast('Payment recorded and tokens minted.');
  return project;
}

function resetProjectPaymentInputs() {
  projectFundingValidationAttempted.value = false;
  projectPaymentError.value = '';
  projectCryptoReference.value = '';
  Object.assign(projectCardForm, {
    cardNumber: '',
    expiry: '',
    cvc: '',
    cardholderName: '',
  });
}

function projectPayPalDescription(payload = {}) {
  const title = String(payload.title || projectTitleLabel.value || 'MergeOS project').trim();
  const runes = Array.from(`MergeOS project funding: ${title}`);
  return runes.length <= 120 ? runes.join('') : `${runes.slice(0, 117).join('').trim()}...`;
}

function addDeliverable() {
  projectDeliverables.value.push('');
}

function removeDeliverable(index) {
  if (projectDeliverables.value.length <= 1) {
    projectDeliverables.value = [''];
    return;
  }

  projectDeliverables.value.splice(index, 1);
}

function loginWithSocial(provider) {
  const ready = provider === 'google' ? googleOAuthReady.value : githubOAuthReady.value;
  if (!ready) {
    const label = provider === 'google' ? 'Google OAuth' : 'GitHub App login';
    errorMessage.value = `${label} is not configured yet.`;
    showToast(errorMessage.value);
    return;
  }
  showToast(`Redirecting to ${provider === 'google' ? 'Google' : 'GitHub'}...`);
  window.location.href = `/api/auth/${provider}/login`;
}

async function triggerAiEvaluation() {
  aiEvaluationLoading.value = true;
  aiEvaluationError.value = '';
  aiEvaluationResult.value = null;
  try {
    const payload = {
      description: projectSetupForm.overview || projectSetupForm.shortDescription || '',
      requirements: projectSetupForm.requirements
        ? projectSetupForm.requirements.split('\n').map(r => r.trim()).filter(Boolean)
        : [],
      deliverables: visibleDeliverables.value,
      timeline: projectTimelineLabel.value,
      tech_stack: projectSetupForm.techStack || '',
      complexity: projectSetupForm.complexity || 'Medium',
      constraints: projectSetupForm.constraints || '',
      reference_budget: Math.round(usdFromMRG(projectSetupForm.budgetAmount))
    };

    // Try LLM-powered evaluation first, with fallback to rule-based
    try {
      const response = await api('/api/projects/evaluate-llm', {
        method: 'POST',
        body: JSON.stringify(payload)
      });
      aiEvaluationResult.value = response;
    } catch (_llmErr) {
      // LLM endpoint unavailable ظ¤ use rule-based evaluation
      const response = await api('/api/projects/evaluate', {
        method: 'POST',
        body: JSON.stringify(payload)
      });
      aiEvaluationResult.value = response;
    }
  } catch (err) {
    console.error('AI evaluation failed:', err);
    aiEvaluationError.value = err.message || 'AI evaluation failed. Please try again.';
  } finally {
    aiEvaluationLoading.value = false;
  }
}

function applyAiSuggestedPrice() {
  if (aiEvaluationResult.value) {
    const avg = Math.round((aiEvaluationResult.value.suggested_low + aiEvaluationResult.value.suggested_high) / 2);
    projectSetupForm.budgetAmount = mrgFromUSD(avg);
    showToast(`Applied AI suggested budget: ${formatMRGFromUSD(avg)}`);
  }
}

function formatMoney(value) {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0,
  }).format(Number(value) || 0);
}

function formatFileSize(bytes = 0) {
  const value = Number(bytes) || 0;
  if (value < 1024) return `${value} B`;
  if (value < 1024 * 1024) return `${Math.round(value / 1024)} KB`;
  return `${(value / (1024 * 1024)).toFixed(value < 10 * 1024 * 1024 ? 1 : 0)} MB`;
}

function mrgFromUSD(value = 0) {
  return Math.round((Number(value) || 0) * TOKEN_RATE_PER_USD);
}

function usdFromMRG(value = 0) {
  return (Number(value) || 0) / TOKEN_RATE_PER_USD;
}

function centsFromMRG(value = 0) {
  return Math.round(usdFromMRG(value) * 100);
}

function formatMRG(value = 0) {
  return `${formatCompactNumber(value)} ${tokenSymbol.value}`;
}

function formatMRGFromUSD(value = 0) {
  return formatMRG(mrgFromUSD(value));
}

function formatMRGFromCents(cents = 0) {
  return formatMRG(tokenAmountFromCents(cents));
}

function formatLedgerMRGFromCents(cents = 0) {
  return formatMRGFromCents(cents);
}

function formatPublicMRGFromCents(cents = 0) {
  return formatMRGFromCents(cents);
}

function formatPublicTokenAmount(amount = 0) {
  return `${formatCompactNumber(amount)} ${tokenSymbol.value}`;
}

function formatHomeMRGFromCents(cents = 0) {
  return `${formatCompactMetricNumber(tokenAmountFromCents(cents))} ${tokenSymbol.value}`;
}

function formatHomeTokenAmount(amount = 0) {
  return `${formatCompactMetricNumber(amount)} ${tokenSymbol.value}`;
}

function formatCompactNumber(value = 0) {
  return new Intl.NumberFormat('en-US', {
    maximumFractionDigits: value >= 100 ? 0 : 1,
  }).format(Number(value) || 0);
}

function formatCompactMetricNumber(value = 0) {
  const numeric = Number(value) || 0;
  return new Intl.NumberFormat('en-US', {
    notation: 'compact',
    maximumFractionDigits: Math.abs(numeric) >= 1000000 ? 1 : 0,
  }).format(numeric);
}

function tokenAmountFromCents(cents = 0) {
  return Math.round(((Number(cents) || 0) / 100) * TOKEN_RATE_PER_USD);
}

function toTitleLabel(value = '') {
  return String(value)
    .trim()
    .split(/[\s._:-]+/)
    .filter(Boolean)
    .map((word) => {
      const lower = word.toLowerCase();
      if (['ai', 'api', 'qa', 'ui', 'ux', 'go'].includes(lower)) return lower.toUpperCase();
      if (lower === 'devops') return 'DevOps';
      return `${lower.charAt(0).toUpperCase()}${lower.slice(1)}`;
    })
    .join(' ');
}

function dashboardStatusClass(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (!normalized) return 'is-waiting';
  if (/(error|failed|failure|attention)/.test(normalized)) return 'is-error';
  if (/(sync|scan|loading|refresh|fetch|recording)/.test(normalized)) return 'is-syncing';
  if (/(needs|review|finding|warning|blocked|queued|pending)/.test(normalized)) return 'is-warning';
  if (/(waiting|empty|no data|not loaded|not set)/.test(normalized)) return 'is-waiting';
  if (/(clear|live|ready|funded|released|paid|verified|protocol|routed|open|worker)/.test(normalized)) return 'is-live';
  return 'is-neutral';
}

function paymentModeLabel(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  return {
    'live-adapters': 'Live payment adapters',
    'local-dev-verifier': 'MergeOS verifier',
    'not-configured': 'Not configured',
    '': 'Not loaded',
  }[normalized] || toTitleLabel(value);
}

function repoProviderLabel(value = '') {
  const normalized = String(value || '').trim().toLowerCase();
  if (!normalized) return 'Not loaded';
  if (normalized.startsWith('github-private:')) return 'GitHub private repos';
  if (normalized === 'local-git') return 'MergeOS repositories';
  return toTitleLabel(value);
}

function formatMarketplaceDate(value) {
  const date = value ? new Date(value) : null;
  const label = publicMarketplaceCopy.value.projectLabels.funded;
  if (!date || Number.isNaN(date.getTime())) return label;
  return `${label} ${date.toLocaleDateString(activeLocale.value, { month: 'short', day: 'numeric' })}`;
}

function trimMarketplaceText(value = '', fallback = 'Funded MergeOS project with escrow-backed tasks and ledger proof.') {
  const text = String(value || '').replace(/\s+/g, ' ').trim();
  if (!text) return fallback;
  return text.length > 150 ? `${text.slice(0, 147).trim()}...` : text;
}

function shortAgentEndpoint(value = '') {
  const clean = String(value || '').replace(/^https?:\/\/[^/]+/i, '').trim();
  if (!clean) return 'endpoint';
  return clean.length > 42 ? `${clean.slice(0, 39)}...` : clean;
}

function marketplaceProjectIcon(project = {}) {
  const text = [
    project.title,
    project.brief,
    project.site_type,
    ...(project.tags || []),
  ].join(' ').toLowerCase();
  if (text.includes('mobile')) return Phone;
  if (text.includes('ai') || text.includes('agent')) return Bot;
  if (text.includes('analytics') || text.includes('dashboard')) return BarChart3;
  if (text.includes('payment') || text.includes('checkout') || text.includes('ledger')) return CreditCard;
  if (text.includes('api') || text.includes('code')) return Code2;
  return Globe2;
}

function marketplaceAgentIcon(type = '') {
  const text = String(type).toLowerCase();
  if (text.includes('design')) return PenLine;
  if (text.includes('ledger') || text.includes('go')) return CreditCard;
  if (text.includes('devops')) return GitBranch;
  if (text.includes('qa') || text.includes('test')) return CheckCircle2;
  if (text.includes('front')) return Code2;
  return Bot;
}

function mapMarketplaceProject(project = {}, index = 0) {
  const palette = marketplaceProjectPalettes[index % marketplaceProjectPalettes.length];
  const labels = publicMarketplaceCopy.value.projectLabels;
  const rawTags = (project.tags || []).map(toTitleLabel).filter(Boolean);
  const tags = rawTags.length ? rawTags : [toTitleLabel(project.site_type || 'Project')];
  const openTasks = Number(project.open_task_count) || 0;
  const acceptedTasks = Number(project.accepted_task_count) || 0;
  const taskCount = Number(project.task_count) || openTasks + acceptedTasks;
  const client = project.client_display_name || labels.client;
  const badge = openTasks > 0 ? `${openTasks} ${labels.open}` : (acceptedTasks > 0 ? labels.paidOut : toTitleLabel(project.status || labels.live));
  return {
    id: project.id || `project-${index}`,
    icon: marketplaceProjectIcon(project),
    badge,
    badgeTone: openTasks > 0 ? palette.badgeTone : 'green',
    title: project.title || labels.untitled,
    body: trimMarketplaceText(project.brief, labels.bodyFallback),
    tags: tags.slice(0, 3),
    extra: Math.max(0, tags.length - 3),
    budgetCents: Number(project.budget_cents) || 0,
    budget: formatPublicMRGFromCents(project.budget_cents),
    timeline: project.timeline || formatMarketplaceDate(project.created_at),
    client,
    clientInitials: initialsFor(client),
    avatarTone: palette.avatarTone,
    taskLabel: `${taskCount} ${taskCount === 1 ? labels.taskSingular : labels.taskPlural}`,
    verified: project.status === 'funded',
    urgent: openTasks > 0,
    accent: palette.accent,
    soft: palette.soft,
    workflowUrl: absolutePublicPath(`/api/public/projects/${encodeURIComponent(project.id || `project-${index}`)}/workflow/protocol`),
    workflowPulseUrl: absolutePublicPath(`/api/public/projects/${encodeURIComponent(project.id || `project-${index}`)}/workflow-pulse`),
    source_repo_url: project.source_repo_url || '',
    repo_url: project.repo_url || '',
    bounty_repo_name: project.bounty_repo_name || '',
    repo_provider: project.repo_provider || '',
  };
}

function mapMarketplaceBounty(bounty = {}, index = 0) {
  const labels = publicMarketplaceCopy.value.projectLabels;
  const workerKind = bounty.required_worker_kind || 'human';
  const agentType = bounty.suggested_agent_type || '';
  const issueNumber = Number(bounty.issue_number) || 0;
  const id = bounty.id || `${bounty.project_id || 'project'}:${issueNumber || index}`;
  return {
    id,
    icon: agentType ? marketplaceAgentIcon(agentType) : (workerKind === 'human' ? User : Bot),
    title: bounty.title || labels.openBounty,
    acceptance: trimMarketplaceText(bounty.acceptance, labels.acceptanceFallback),
    project: bounty.project_title || labels.projectFallback,
    rewardCents: Number(bounty.reward_cents) || 0,
    reward: formatPublicMRGFromCents(bounty.reward_cents),
    lane: agentType ? toTitleLabel(agentType) : toTitleLabel(workerKind),
    workerKind,
    agentType,
    issue: issueNumber > 0 ? `#${issueNumber}` : labels.waitingTask,
    url: bounty.issue_url || '',
    protocolUrl: absolutePublicPath(`/api/public/bounties/${encodeURIComponent(id)}/protocol`),
    tone: ['green', 'blue', 'purple', 'amber'][index % 4],
  };
}

function absolutePublicPath(path = '') {
  const normalized = String(path || '/');
  if (!hasWindow) return normalized;
  return `${window.location.origin}${normalized.startsWith('/') ? normalized : `/${normalized}`}`;
}

function marketplaceSearchHaystack(project = {}) {
  return [
    project.title,
    project.body,
    project.client,
    project.budget,
    project.timeline,
    project.source_repo_url,
    project.repo_url,
    project.bounty_repo_name,
    ...(project.tags || []),
  ].join(' ').toLowerCase();
}

function marketplaceBountyHaystack(bounty = {}) {
  return [
    bounty.title,
    bounty.acceptance,
    bounty.project,
    bounty.reward,
    bounty.lane,
    bounty.issue,
  ].join(' ').toLowerCase();
}

function marketplaceAgentHaystack(agent = {}) {
  return [
    agent.type,
    agent.title,
    agent.body,
    agent.displayBody,
    agent.capability,
    agent.status,
    agent.rewardLabel,
    agent.capacityLabel,
    ...(agent.labels || []),
  ].join(' ').toLowerCase();
}

function matchesMarketplaceBudget(cents = 0) {
  const tokens = tokenAmountFromCents(cents);
  switch (activeMarketplaceBudget.value) {
  case 'Under 50K MRG':
    return tokens > 0 && tokens < 50000;
  case '50K-250K MRG':
    return tokens >= 50000 && tokens < 250000;
  case '250K+ MRG':
    return tokens >= 250000;
  default:
    return true;
  }
}

function matchesMarketplaceDelivery(project = {}) {
  const filter = activeMarketplaceDelivery.value;
  if (filter === 'Any delivery') return true;
  const timeline = String(project.timeline || '').toLowerCase();
  const dayMatch = timeline.match(/(\d+)\s+days?/);
  const days = dayMatch ? Number(dayMatch[1]) : 0;
  if (filter === 'Urgent') {
    return project.urgent || timeline.includes('urgent') || timeline.includes('asap') || timeline.includes('week');
  }
  if (filter === '30 days') {
    return days > 0 ? days <= 30 : timeline.includes('month');
  }
  if (filter === 'Quarter+') {
    return days >= 90 || timeline.includes('quarter') || timeline.includes('ongoing');
  }
  return true;
}

function nextOption(options = [], current = '') {
  if (!options.length) return current;
  const index = options.indexOf(current);
  return options[(index + 1) % options.length] || options[0];
}

function cycleMarketplaceCategory() {
  activeMarketplaceCategory.value = nextOption(marketplaceCategories.value, activeMarketplaceCategory.value);
}

function cycleMarketplaceBudget() {
  activeMarketplaceBudget.value = nextOption(marketplaceBudgetOptions, activeMarketplaceBudget.value);
}

function cycleMarketplaceDelivery() {
  activeMarketplaceDelivery.value = nextOption(marketplaceDeliveryOptions, activeMarketplaceDelivery.value);
}

function toggleLedgerProjectMenu() {
  ledgerProjectMenuVisible.value = !ledgerProjectMenuVisible.value;
}

function toggleLedgerAdvancedFilters() {
  ledgerAdvancedFiltersVisible.value = !ledgerAdvancedFiltersVisible.value;
}

function setLedgerProjectFilter(value = 'All Projects') {
  activeLedgerProject.value = value;
  ledgerProjectMenuVisible.value = false;
}

function applyLedgerProofLane(lane = {}) {
  activeLedgerTab.value = ledgerTabs.includes(lane.tab) ? lane.tab : 'All Activity';
  activeLedgerProject.value = 'All Projects';
  activeLedgerEventType.value = lane.type || 'All types';
  activeLedgerStatus.value = 'All statuses';
  ledgerSearch.value = typeof lane.search === 'string' ? lane.search : '';
  ledgerAdvancedFiltersVisible.value = true;
  ledgerProjectMenuVisible.value = false;
  if (hasWindow) {
    window.requestAnimationFrame(() => scrollToSection('ledger-events'));
  }
}

function clearLedgerFilters() {
  ledgerSearch.value = '';
  activeLedgerProject.value = 'All Projects';
  activeLedgerEventType.value = 'All types';
  activeLedgerStatus.value = 'All statuses';
}

function clearMarketplaceFilters() {
  marketplaceSearch.value = '';
  activeMarketplaceCategory.value = 'All';
  activeMarketplaceBudget.value = 'Any budget';
  activeMarketplaceDelivery.value = 'Any delivery';
}

function claimPayloadForBounty(bounty = {}) {
  const packetPayload = bounty.claimPayload && typeof bounty.claimPayload === 'object' ? bounty.claimPayload : {};
  const workerKind = packetPayload.worker_kind || bounty.workerKind || bounty.required_worker_kind || 'human';
  const agentType = packetPayload.agent_type || bounty.agentType || bounty.suggested_agent_type || '';
  return {
    ...packetPayload,
    worker_kind: workerKind,
    worker_id: claimWorkerIDForProfile() || packetPayload.worker_id || 'current-user',
    agent_type: workerKind === 'human' ? '' : (agentType || 'mergeos-agent'),
  };
}

async function claimMarketplaceBounty(bounty = {}, options = {}) {
  if (!bounty?.id || claimingBountyID.value) return;
  if (bounty.canClaim === false) {
    showToast('This proposal is no longer available.');
    return;
  }
  if (!token.value || !user.value) {
    pendingClaimBounty.value = bounty;
    openAuth('login');
    showToast('Log in to claim this bounty.');
    return;
  }

  claimingBountyID.value = bounty.id;
  try {
    const endpoint = bounty.claimEndpoint || `/api/tasks/${encodeURIComponent(bounty.id)}/claim`;
    const claimed = await api(endpoint, {
      method: 'POST',
      body: JSON.stringify(claimPayloadForBounty(bounty)),
    });
    pendingClaimBounty.value = null;
    await Promise.all([
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
      loadWorkerDashboardData({ silent: true }),
      loadDashboardData({ silent: true }),
    ]);
    if (dashboardSection.value !== 'worker' && options.openWorker !== false) {
      dashboardSection.value = 'worker';
    }
    showToast(`Claimed task #${claimed.issue_number || ''}. Payout stays locked until review.`);
  } catch (error) {
    showToast(error.message || 'Could not claim bounty.');
  } finally {
    claimingBountyID.value = '';
  }
}

async function recordAgentQueueAction(task = {}, actionRow = {}) {
  const body = actionRow.body || {};
  const action = body.action || actionRow.action || '';
  if (!action) {
    showToast('Agent action payload is missing.');
    return;
  }
  if (!token.value || !user.value) {
    openAuth('login');
    showToast('Log in to record agent action evidence.');
    return;
  }
  const key = actionRow.key || `${task.id || 'agent'}:${action}`;
  if (recordingAgentActionKey.value) return;
  recordingAgentActionKey.value = key;
  try {
    const payload = {
      ...body,
      bounty_id: body.bounty_id || task.bountyID || task.id,
      project_id: body.project_id || task.projectID,
      agent_type: body.agent_type || task.agentType,
      action,
      status: body.status && body.status !== 'queued' ? body.status : 'processed',
    };
    const endpoint = actionRow.endpoint || task.actionEndpoint || '/api/agents/actions';
    await api(endpoint, {
      method: 'POST',
      body: JSON.stringify(payload),
    });
    await Promise.all([
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
      loadDashboardData({ silent: true, selectProjectID: selectedDashboardProjectID.value }),
    ]);
    showToast(`Agent ${toTitleLabel(action)} recorded.`);
  } catch (error) {
    showToast(error.message || 'Could not record agent action.');
  } finally {
    recordingAgentActionKey.value = '';
  }
}

async function openRepositorySuggestedTaskFunding(task = {}) {
  if (!dashboardSelectedProject.value?.id || !task?.id || fundingSuggestedTaskID.value) return;
  if (!token.value) {
    showToast('Log in to fund this repository task.');
    return;
  }
  if (task.canFund === false) {
    showToast(task.status === 'already_funded' ? 'This repository task is already funded.' : 'This repository task is not ready for funding.');
    return;
  }
  try {
    await loadRuntimeConfig();
  } catch (error) {
    showToast(error.message || 'Could not load payment configuration.');
    return;
  }
  repoTaskFundingTask.value = task;
  repoTaskFundingMethod.value = runtimeConfig.value?.paypal_ready || projectDevPaymentReference() ? 'PayPal' : 'Credit / Debit card';
  repoTaskFundingError.value = '';
  repoTaskFundingValidationAttempted.value = false;
  repoTaskFundingVisible.value = true;
}

function closeRepositoryTaskFunding(options = {}) {
  if (repoTaskFundingBusy.value && !options.force) return;
  repoTaskFundingVisible.value = false;
  resetRepositoryTaskFundingInputs();
}

function resetRepositoryTaskFundingInputs() {
  repoTaskFundingTask.value = null;
  repoTaskFundingError.value = '';
  repoTaskFundingValidationAttempted.value = false;
  repoTaskFundingCryptoReference.value = '';
  Object.assign(repoTaskFundingCardForm, {
    cardNumber: '',
    expiry: '',
    cvc: '',
    cardholderName: '',
  });
}

async function submitRepositorySuggestedTaskFunding() {
  const task = repoTaskFundingTask.value || {};
  if (!dashboardSelectedProject.value?.id || !task?.id || fundingSuggestedTaskID.value) return;
  repoTaskFundingValidationAttempted.value = true;
  repoTaskFundingError.value = '';
  try {
    await loadRuntimeConfig();
  } catch (error) {
    repoTaskFundingError.value = error.message || 'Could not load payment configuration.';
    showToast(repoTaskFundingError.value);
    return;
  }
  if (repoTaskFundingErrorCount()) {
    showToast(repoTaskFundingErrorCount() === 1 ? 'Fix 1 funding item before continuing.' : `Fix ${repoTaskFundingErrorCount()} funding items before continuing.`);
    return;
  }

  const projectID = dashboardSelectedProject.value.id;
  const rewardCents = Number(task.fundingPayload?.reward_cents || task.reward_cents) || 0;
  fundingSuggestedTaskID.value = task.id;
  repoTaskFundingBusy.value = true;
  try {
    const paymentMethod = paymentMethodForRepoTaskFunding();
    if (paymentMethod === 'card') {
      const intent = await createCardPaymentIntent({
        amount_cents: repoTaskFundingAmountCents.value,
        card_number: repoTaskCardDigits(),
        expiry: repoTaskCardExpiryForPayload(),
        cvc: repoTaskCardCvcDigits(),
        cardholder_name: repoTaskFundingCardForm.cardholderName || user.value?.name || '',
      });
      await submitRepositorySuggestedTaskFundingRequest(projectID, task.id, rewardCents, 'card', intent.payment_reference, { task });
      closeRepositoryTaskFunding({ force: true });
      return;
    }
    const devPaymentReference = projectDevPaymentReference();
    if (devPaymentReference) {
      await submitRepositorySuggestedTaskFundingRequest(projectID, task.id, rewardCents, paymentMethod, devPaymentReference, { task });
      closeRepositoryTaskFunding({ force: true });
      return;
    }
    if (paymentMethod === 'paypal' && runtimeConfig.value?.paypal_ready) {
      await startRepositorySuggestedTaskPayPalFunding(projectID, task);
      return;
    }
    if (paymentMethod === 'crypto') {
      await submitRepositorySuggestedTaskFundingRequest(projectID, task.id, rewardCents, 'crypto', repoTaskFundingCryptoReference.value, { task });
      closeRepositoryTaskFunding({ force: true });
      return;
    }
    throw new Error(paymentMethod === 'crypto'
      ? 'USDC verification needs a Solana signature before task funding can be verified.'
      : 'PayPal checkout is not configured for repository task funding.');
  } catch (error) {
    repoTaskFundingError.value = error.message || 'Could not fund repository task.';
    showToast(repoTaskFundingError.value);
  } finally {
    fundingSuggestedTaskID.value = '';
    repoTaskFundingBusy.value = false;
  }
}

async function startRepositorySuggestedTaskPayPalFunding(projectID, task = {}) {
  if (!hasWindow) {
    throw new Error('PayPal checkout requires a browser session.');
  }
  const paypalPayload = task.paypalPayload || {};
  const rewardCents = Number(paypalPayload.reward_cents || task.fundingPayload?.reward_cents || task.reward_cents) || 0;
  const returnURL = absolutePublicPath('/paypal/return?flow=repo_task_funding');
  const cancelURL = absolutePublicPath('/paypal/cancel?flow=repo_task_funding');
  const endpoint = task.paypalOrderEndpoint || `/api/projects/${encodeURIComponent(projectID)}/repo-scan/suggested-tasks/${encodeURIComponent(task.id)}/paypal-order`;
  const order = await api(endpoint, {
    method: 'POST',
    body: JSON.stringify({
      suggested_task_id: paypalPayload.suggested_task_id || task.id,
      reward_cents: rewardCents,
      return_url: returnURL,
      cancel_url: cancelURL,
    }),
  });
  if (!order?.approval_url || !order?.order_id) {
    throw new Error('PayPal did not return an approval URL.');
  }
  writePendingRepositoryTaskFunding({
    flow: 'repo_task_funding',
    projectID,
    taskID: task.id,
    rewardCents,
    orderID: order.order_id,
    createdAt: Date.now(),
  });
  showToast('Redirecting to PayPal checkout...');
  window.location.href = order.approval_url;
}

function repositoryTaskFundEndpoint(projectID, taskID, task = {}) {
  if (task?.fundEndpoint) return task.fundEndpoint;
  return `/api/projects/${encodeURIComponent(projectID)}/repo-scan/suggested-tasks/${encodeURIComponent(taskID)}/fund`;
}

async function submitRepositorySuggestedTaskFundingRequest(projectID, taskID, rewardCents, paymentMethod, paymentReference, options = {}) {
  const endpoint = repositoryTaskFundEndpoint(projectID, taskID, options.task || {});
  const payload = await api(endpoint, {
    method: 'POST',
    body: JSON.stringify({
      reward_cents: Number(rewardCents) || 0,
      payment_method: paymentMethod,
      payment_reference: paymentReference,
    }),
  });
  showToast(payload?.task?.issue_number ? `Funded task #${payload.task.issue_number}.` : 'Repository task funded.');
  await loadDashboardData({ silent: true, selectProjectID: projectID });
  await Promise.allSettled([
    loadDashboardRepositoryIntelligenceData(projectID, { silent: true }),
    loadDashboardEscrowData(projectID, { silent: true }),
    loadMarketplaceData({ silent: true }),
    loadLiveFeedData({ silent: true }),
  ]);
  return payload;
}

function reviewDraftForTask(task = {}) {
  const id = task.id || `${task.project_id || 'task'}-${task.issue_number || 'review'}`;
  if (!taskReviewDrafts[id]) {
    taskReviewDrafts[id] = {
      pullRequestURL: task.pullRequestURL || task.pull_request_url || '',
      evidenceURL: task.reviewEvidenceURL || task.review_evidence_url || '',
      notes: task.reviewNotes || task.review_notes || '',
    };
  }
  return taskReviewDrafts[id];
}

function taskReviewKey(task = {}) {
  return task.id || `${task.project_id || 'task'}-${task.issue_number || 'review'}`;
}

function isHttpURL(value = '') {
  const raw = String(value || '').trim();
  if (!raw) return false;
  try {
    const url = new URL(raw);
    return url.protocol === 'http:' || url.protocol === 'https:';
  } catch {
    return false;
  }
}

function isGitHubPullRequestURL(value = '') {
  const raw = String(value || '').trim();
  if (!raw) return false;
  try {
    const url = new URL(raw);
    if (url.hostname.toLowerCase() !== 'github.com') return false;
    return /^\/[^/]+\/[^/]+\/pull\/\d+\/?$/i.test(url.pathname);
  } catch {
    return false;
  }
}

function validateTaskReviewDraft(draft = {}) {
  const errors = {};
  const pullRequestURL = String(draft.pullRequestURL || '').trim();
  const evidenceURL = String(draft.evidenceURL || '').trim();
  const notes = String(draft.notes || '').trim();
  if (pullRequestURL && !isGitHubPullRequestURL(pullRequestURL)) {
    errors.pullRequestURL = 'Use a GitHub pull request URL like https://github.com/org/repo/pull/12.';
  }
  if (evidenceURL && !isHttpURL(evidenceURL)) {
    errors.evidenceURL = 'Use an http or https evidence URL.';
  }
  if (!pullRequestURL && !evidenceURL && notes.length < 12) {
    errors.notes = 'Add review notes, a pull request URL, or an evidence URL before submitting.';
  } else if (notes && notes.length < 12) {
    errors.notes = 'Review notes should be at least 12 characters.';
  }
  return errors;
}

function setTaskReviewErrors(task = {}, errors = {}) {
  const key = taskReviewKey(task);
  if (!key) return;
  taskReviewErrors[key] = errors;
}

function taskReviewFieldError(task = {}, field = '') {
  return taskReviewErrors[taskReviewKey(task)]?.[field] || '';
}

function clearTaskReviewFieldError(task = {}, field = '') {
  const key = taskReviewKey(task);
  if (!field || !taskReviewErrors[key]?.[field]) return;
  taskReviewErrors[key] = {
    ...taskReviewErrors[key],
    [field]: '',
  };
  for (const [errorField, message] of Object.entries(taskReviewErrors[key])) {
    if (!message) delete taskReviewErrors[key][errorField];
  }
}

function taskReviewErrorList(task = {}) {
  const errors = taskReviewErrors[taskReviewKey(task)] || {};
  return Object.entries(errors).map(([field, message]) => ({ field, message }));
}

function toggleTaskReviewSubmission(task = {}) {
  if (!task?.id) return;
  reviewDraftForTask(task);
  setTaskReviewErrors(task, {});
  expandedReviewTaskID.value = expandedReviewTaskID.value === task.id ? '' : task.id;
}

async function submitTaskReview(task = {}) {
  if (!task?.id || reviewSubmittingTaskID.value) return;
  const draft = reviewDraftForTask(task);
  const validationErrors = validateTaskReviewDraft(draft);
  setTaskReviewErrors(task, validationErrors);
  const errorCount = Object.keys(validationErrors).length;
  if (errorCount) {
    showToast(errorCount === 1 ? 'Fix 1 review item before submitting.' : `Fix ${errorCount} review items before submitting.`);
    return;
  }
  reviewSubmittingTaskID.value = task.id;
  try {
    const submitted = await api(`/api/tasks/${encodeURIComponent(task.id)}/submit`, {
      method: 'POST',
      body: JSON.stringify({
        pull_request_url: draft.pullRequestURL,
        evidence_url: draft.evidenceURL,
        notes: draft.notes,
      }),
    });
    setTaskReviewErrors(task, {});
    taskReviewDrafts[task.id] = {
      pullRequestURL: submitted.pull_request_url || draft.pullRequestURL,
      evidenceURL: submitted.review_evidence_url || draft.evidenceURL,
      notes: submitted.review_notes || draft.notes,
    };
    expandedReviewTaskID.value = '';
    await Promise.all([
      loadWorkerDashboardData({ silent: true }),
      loadDashboardData({ silent: true }),
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
    ]);
    showToast(`Task #${submitted.issue_number || task.issueNumber || ''} submitted for review. Payout remains locked.`);
  } catch (error) {
    showToast(error.message || 'Could not submit review evidence.');
  } finally {
    reviewSubmittingTaskID.value = '';
  }
}

async function releaseTaskPayment(task = {}) {
  if (!task?.id || releasingTaskID.value) return;
  const releasePacket = task.releasePacket || {};
  if (task.releasePacket && !releasePacket.can_release) {
    showToast(releasePacket.blockers?.[0] || 'This payout is not ready to release.');
    return;
  }
  releasingTaskID.value = task.id;
  try {
    const endpoint = releasePacket.release_endpoint || `/api/tasks/${encodeURIComponent(task.id)}/accept`;
    const payload = releasePacket.payload || {
      worker_kind: task.workerKind,
      worker_id: task.workerID,
      agent_type: task.agentType,
    };
    const accepted = await api(endpoint, {
      method: 'POST',
      body: JSON.stringify(payload),
    });
    await Promise.all([
      loadDashboardData({ silent: true }),
      loadDashboardEscrowData(selectedDashboardProjectID.value, { silent: true }),
      loadWorkerDashboardData({ silent: true }),
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
    ]);
    showToast(`Released payout for task #${accepted.issue_number || task.issueNumber || ''}.`);
  } catch (error) {
    showToast(error.message || 'Could not release payout.');
  } finally {
    releasingTaskID.value = '';
  }
}

async function runProjectAutoRelease() {
  const projectID = dashboardSelectedProject.value?.id || selectedDashboardProjectID.value;
  const readyRows = dashboardAutoReleaseReadyRows.value;
  if (!projectID || !readyRows.length || autoReleasingProjectID.value) return;
  const packet = readyRows[0].autoReleasePacket || {};
  const endpoint = packet.release_endpoint || `/api/projects/${encodeURIComponent(projectID)}/auto-release`;
  const taskIDs = readyRows
    .flatMap((row) => row.autoReleasePacket?.payload?.task_ids || [row.id])
    .filter(Boolean);
  autoReleasingProjectID.value = projectID;
  try {
    const payload = await api(endpoint, {
      method: packet.method || 'POST',
      body: JSON.stringify({
        ...(packet.payload || {}),
        task_ids: taskIDs,
        policy: packet.policy || packet.payload?.policy,
      }),
    });
    await Promise.all([
      loadDashboardData({ silent: true, selectProjectID: projectID }),
      loadDashboardPullRequestsData(projectID, { silent: true }),
      loadDashboardEscrowData(projectID, { silent: true }),
      loadWorkerDashboardData({ silent: true }),
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
    ]);
    const released = Number(payload?.released_count) || 0;
    const skipped = Number(payload?.skipped_count) || 0;
    showToast(released ? `Auto-released ${released} payout${released === 1 ? '' : 's'}.` : skipped ? 'No eligible payouts auto-released.' : 'Auto-release queue is empty.');
  } catch (error) {
    showToast(error.message || 'Could not run auto-release.');
  } finally {
    autoReleasingProjectID.value = '';
  }
}

async function executeAdminOpsAction(item = {}) {
  if (!item?.id || releasingTaskID.value) return;
  const packet = item.actionPacket || {};
  if (!packet.can_execute || !packet.action_endpoint) {
    showToast(packet.next_action || 'This admin item requires manual review.');
    return;
  }
  releasingTaskID.value = item.id;
  try {
    const actionPayload = packet.payload || packet.resolution_payload || packet.resolutionPayload || {};
    const response = await api(packet.action_endpoint, {
      method: packet.method || 'POST',
      body: JSON.stringify(actionPayload),
    });
    await Promise.all([
      loadAdminConsoleData({ silent: true }),
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
      loadDashboardData({ silent: true }),
    ]);
    if (response?.ok && (packet.resolution_payload || packet.resolutionPayload)) {
      showToast(`${item.actionLabel} recorded for admin ops item.`);
    } else {
      showToast(`Released payout for task #${response?.issue_number || item.task || ''}.`);
    }
  } catch (error) {
    showToast(error.message || 'Could not execute admin action.');
  } finally {
    releasingTaskID.value = '';
  }
}

function deploymentValidationActionID(projectID = '') {
  return `deployment-validation:${projectID || 'project'}`;
}

async function recordDeploymentValidationAction() {
  const deployment = dashboardDeployment.value || {};
  const packet = deployment.validation_packet || {};
  const projectID = deployment.project_id || selectedDashboardProjectID.value || '';
  if (!packet.can_record || !packet.action_endpoint) {
    showToast(packet.next_action || 'Deployment validation is not ready to record.');
    return;
  }
  if (releasingTaskID.value) return;
  releasingTaskID.value = deploymentValidationActionID(projectID);
  try {
    const response = await api(packet.action_endpoint, {
      method: packet.method || 'POST',
      body: JSON.stringify(packet.payload || {}),
    });
    await Promise.allSettled([
      loadDashboardDeploymentData(projectID, { silent: true }),
      loadDashboardAIWorkflowData(projectID, { silent: true }),
      loadDashboardWorkflowPulseData(projectID, { silent: true }),
      loadDashboardData({ silent: true, selectProjectID: projectID }),
      loadMarketplaceData({ silent: true }),
      loadLiveFeedData({ silent: true }),
    ]);
    showToast(response?.item?.title || 'Deployment validation recorded.');
  } catch (error) {
    showToast(error.message || 'Could not record deployment validation.');
  } finally {
    releasingTaskID.value = '';
  }
}

function formatDashboardDate(value) {
  const date = value ? new Date(value) : null;
  if (!date || Number.isNaN(date.getTime())) return '-';
  return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

function formatDateInputLabel(value = '') {
  if (!value) return '';
  const date = new Date(`${value}T00:00:00Z`);
  if (Number.isNaN(date.getTime())) return '';
  return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric', timeZone: 'UTC' });
}

function shortRepoLabel(project = {}) {
  const repo = String(project.source_repo_url || project.bounty_repo_name || project.repo_url || project.repo_provider || '').trim();
  if (!repo) return 'No repo yet';
  return repo.replace(/^https?:\/\/github\.com\//, '').replace(/^mergeos-bounties\//, '');
}

function projectHasScanRepository(project = {}) {
  return Boolean(String(project?.source_repo_url || project?.repo_url || project?.bounty_repo_name || '').trim());
}

function repositoryScanTargetLabel(target = '') {
  switch (String(target || '').toLowerCase()) {
  case 'source_repository':
    return 'Source repo';
  case 'bounty_workspace':
    return 'Bounty workspace';
  case 'unavailable':
    return 'No checkout';
  default:
    return '';
  }
}

function emptyCustomerDashboardSnapshot() {
  return {
    protocol_version: 'mergeos.customer.dashboard.v1',
    kind: 'customer_dashboard',
    profile: {},
    stats: {},
    projects: [],
    tasks: [],
    ledger: [],
    notifications: [],
    signals: [],
  };
}

function normalizeCustomerDashboardPayload(payload = {}) {
  return {
    protocol_version: payload.protocol_version || 'mergeos.customer.dashboard.v1',
    kind: payload.kind || 'customer_dashboard',
    profile: payload.profile || {},
    stats: payload.stats || {},
    projects: Array.isArray(payload.projects) ? payload.projects : [],
    tasks: Array.isArray(payload.tasks) ? payload.tasks : [],
    ledger: Array.isArray(payload.ledger) ? payload.ledger : [],
    notifications: Array.isArray(payload.notifications) ? payload.notifications : [],
    signals: Array.isArray(payload.signals) ? payload.signals : [],
  };
}

function customerTaskKey(task = {}) {
  const projectID = task.project_id || task.projectId || '';
  const issueNumber = Number(task.issue_number || task.issueNumber) || 0;
  return `${projectID}:${issueNumber}`;
}

function customerDashboardTaskToDashboardTask(row = {}, legacyTask = null) {
  const source = legacyTask ? { ...row, ...legacyTask } : row;
  const bountyID = row.id || source.bounty_id || (source.project_id && source.issue_number ? `${source.project_id}:${source.issue_number}` : '');
  return {
    ...source,
    id: legacyTask?.id || source.task_id || source.internal_task_id || source.id || bountyID,
    bounty_id: bountyID,
    project_id: source.project_id || row.project_id || '',
    project_title: source.project_title || row.project_title || '',
    issue_number: Number(source.issue_number || row.issue_number) || 0,
    title: source.title || row.title || 'Untitled task',
    acceptance: source.acceptance || row.acceptance || '',
    reward_cents: Number(source.reward_cents ?? row.reward_cents) || 0,
    required_worker_kind: source.required_worker_kind || row.required_worker_kind || 'human',
    suggested_agent_type: source.suggested_agent_type || row.suggested_agent_type || '',
    status: source.status || row.status || 'open',
    worker_kind: source.worker_kind || row.worker_kind || '',
    worker_id: source.worker_id || row.worker_id || '',
    agent_type: source.agent_type || row.agent_type || '',
    issue_url: source.issue_url || row.issue_url || '',
    pull_request_url: source.pull_request_url || row.pull_request_url || '',
    review_evidence_url: source.review_evidence_url || row.review_evidence_url || '',
    review_notes: source.review_notes || row.review_notes || '',
    release_packet: source.release_packet || row.release_packet || null,
    auto_release_packet: source.auto_release_packet || row.auto_release_packet || null,
    created_at: source.created_at || row.created_at,
    claimed_at: source.claimed_at || row.claimed_at,
    submitted_at: source.submitted_at || row.submitted_at,
    accepted_at: source.accepted_at || row.accepted_at,
  };
}

function customerDashboardReferenceAttachment(row = {}) {
  return {
    id: row.id || row.url || row.original_name || 'reference-file',
    original_name: row.original_name || row.filename || 'Reference file',
    content_type: row.content_type || 'file',
    size_bytes: Number(row.size_bytes) || 0,
    url: row.url || '',
    is_image: row.is_image === true,
    created_at: row.created_at || '',
  };
}

function customerDashboardProjectToDashboardProject(row = {}, tasks = []) {
  const id = row.project_id || row.id || '';
  const projectTasks = tasks.filter((task) => task.project_id === id);
  return {
    id,
    title: row.title || 'Untitled project',
    brief: `${toTitleLabel(row.ai_workflow_status || 'workflow')} - ${Number(row.ai_action_count) || 0} AI actions - ${toTitleLabel(row.deployment_status || 'deployment')}`,
    status: row.status || 'funded',
    bounty_repo_name: row.bounty_repo_name || '',
    repo_provider: row.repo_provider || '',
    repo_url: row.repo_url || '',
    source_repo_url: row.source_repo_url || '',
    reference_attachments: Array.isArray(row.reference_attachments) ? row.reference_attachments.map(customerDashboardReferenceAttachment) : [],
    budget_cents: Number(row.budget_cents) || 0,
    work_pool_cents: Number(row.work_pool_cents) || 0,
    released_cents: Number(row.released_cents) || 0,
    remaining_escrow_cents: Number(row.remaining_escrow_cents) || 0,
    release_ready_task_count: Number(row.release_ready_task_count) || 0,
    deployment_status: row.deployment_status || 'queued',
    deployment_progress: Number(row.deployment_progress) || 0,
    ai_workflow_status: row.ai_workflow_status || 'queued',
    ai_action_count: Number(row.ai_action_count) || 0,
    created_at: row.created_at,
    updated_at: row.updated_at,
    tasks: projectTasks,
  };
}

function customerDashboardLedgerToDashboardEntry(row = {}) {
  return {
    sequence: Number(row.sequence) || 0,
    type: row.type || 'ledger',
    amount_cents: Number(row.amount_cents) || 0,
    reference: row.reference || '',
    entry_hash: row.entry_hash || '',
    contract_reference: contractReferenceFromRecord(row),
    created_at: row.created_at,
    from_account: row.from_account || '',
    to_account: row.to_account || '',
  };
}

function customerDashboardSignalTone(type = '', status = '') {
  const normalized = String(`${type} ${status}`).toLowerCase();
  if (normalized.includes('accepted') || normalized.includes('ready') || normalized.includes('passed') || normalized.includes('complete')) return 'green';
  if (normalized.includes('failed') || normalized.includes('error') || normalized.includes('blocked')) return 'red';
  if (normalized.includes('submitted') || normalized.includes('review') || normalized.includes('validating')) return 'amber';
  if (normalized.includes('agent') || normalized.includes('ai')) return 'purple';
  return 'blue';
}

function mapCustomerDashboardSignal(signal = {}) {
  const type = signal.type || 'signal';
  const status = signal.status || 'live';
  const when = formatLedgerDateTime(signal.created_at);
  return {
    id: signal.id || `${type}-${signal.created_at || signal.title}`,
    title: signal.title || toTitleLabel(type),
    body: trimMarketplaceText(signal.body, 'Customer dashboard protocol signal.'),
    type,
    status: toTitleLabel(status),
    project: signal.project_title || (signal.project_id ? shortLedgerReference(signal.project_id) : 'MergeOS'),
    reference: shortLedgerReference(signal.reference || signal.url || ''),
    url: signal.url || '',
    tone: customerDashboardSignalTone(type, status),
    meta: `${toTitleLabel(type)} - ${when.full}`,
    createdAt: signal.created_at,
    isAI: String(type).includes('ai') || String(type).includes('agent'),
  };
}

function mapCustomerDashboardSignalActivity(signal = {}) {
  const icon = signal.isAI ? Bot : signal.type.includes('deployment') ? Rocket : signal.type.includes('task') ? ListTodo : Zap;
  return {
    key: signal.id,
    title: signal.title,
    icon,
    color: signal.tone === 'amber' ? 'yellow' : signal.tone,
    time: formatLedgerDateTime(signal.createdAt).full,
    createdAt: signal.createdAt,
  };
}

function applyCustomerDashboardSnapshot(payload = {}, legacyTasks = []) {
  const snapshot = normalizeCustomerDashboardPayload(payload);
  const legacyTaskIndex = new Map((Array.isArray(legacyTasks) ? legacyTasks : []).map((task) => [customerTaskKey(task), task]));
  const tasks = snapshot.tasks.map((task) => customerDashboardTaskToDashboardTask(task, legacyTaskIndex.get(customerTaskKey(task))));
  customerDashboardSnapshot.value = snapshot;
  dashboardTasks.value = tasks;
  dashboardProjects.value = snapshot.projects.map((project) => customerDashboardProjectToDashboardProject(project, tasks));
  dashboardLedgerEntries.value = snapshot.ledger.map(customerDashboardLedgerToDashboardEntry);
  dashboardNotifications.value = snapshot.notifications;
}

function dashboardLedgerEntryMatchesProject(entry = {}, project = {}, tasks = []) {
  const haystack = [
    entry.reference,
    entry.from_account,
    entry.to_account,
  ].filter(Boolean).join('|');
  if (project.id && haystack.includes(project.id)) return true;
  if (project.bounty_repo_name && haystack.includes(project.bounty_repo_name)) return true;
  return tasks.some((task) =>
    (task.id && haystack.includes(task.id))
    || (task.bounty_id && haystack.includes(task.bounty_id))
    || (task.pull_request_url && haystack.includes(task.pull_request_url))
    || (task.review_evidence_url && haystack.includes(task.review_evidence_url))
    || (task.issue_url && haystack.includes(task.issue_url))
  );
}

const financialLedgerTypes = new Set([
  'payment_verified',
  'platform_fee',
  'project_reserve',
  'task_reserve',
  'task_payment',
  'token_mint',
]);

function taskForLedgerEntry(entry = {}, tasks = []) {
  const haystack = [
    entry.reference,
    entry.from_account,
    entry.to_account,
  ].filter(Boolean).join('|');
  return tasks.find((task) =>
    (task.id && haystack.includes(task.id))
    || (task.bounty_id && haystack.includes(task.bounty_id))
    || (task.pull_request_url && haystack.includes(task.pull_request_url))
    || (task.review_evidence_url && haystack.includes(task.review_evidence_url))
    || (task.issue_url && haystack.includes(task.issue_url))
  ) || null;
}

function paymentProviderLabel(value = '') {
  const normalized = String(value || '').trim().replace(/^payment:/, '');
  if (!normalized) return 'MergeOS';
  if (normalized === 'local-dev-verifier') return 'Local Verifier';
  return toTitleLabel(normalized.replaceAll('-', ' '));
}

function ledgerAccountLabel(value = '') {
  const text = String(value || '').trim();
  if (!text) return 'MergeOS';
  if (text.startsWith('payment:')) return `${paymentProviderLabel(text)} gateway`;
  if (text.startsWith('wallet:')) return shortWallet(text.slice('wallet:'.length));
  if (text.startsWith('github:')) return text;
  if (text.startsWith('task:')) return shortLedgerReference(text.slice('task:'.length));
  if (text.startsWith('project:')) return shortLedgerReference(text.slice('project:'.length));
  return shortLedgerReference(text);
}

function paymentStatusForEntry(entry = {}, project = {}) {
  if (entry.type === 'payment_verified') return project.payment_status ? toTitleLabel(project.payment_status) : 'Verified';
  if (entry.type === 'task_payment') return 'Released';
  if (entry.type === 'token_mint') return 'Minted';
  if (entry.type === 'platform_fee') return 'Charged';
  return 'Held';
}

function paymentMethodForEntry(entry = {}, project = {}, task = null) {
  if (entry.type === 'payment_verified') {
    return `${toTitleLabel(project.payment_method || 'payment')} / ${paymentProviderLabel(project.payment_provider || entry.from_account)}`;
  }
  if (entry.type === 'task_payment') {
    return task ? `Task payout / #${task.issue_number || '-'}` : 'Task payout / wallet';
  }
  if (entry.type === 'token_mint') return `${tokenSymbol.value} mint / ledger`;
  if (entry.type === 'platform_fee') return `Platform fee / ${paymentProviderLabel(project.payment_provider || entry.from_account)}`;
  if (entry.type === 'project_reserve') return 'Escrow reserve / project';
  return task ? `Task reserve / #${task.issue_number || '-'}` : 'Task reserve / delivery';
}

function paymentBodyForEntry(entry = {}, project = {}, task = null) {
  if (entry.type === 'payment_verified') {
    return `${project.title || 'This project'} was funded and verified for escrow-backed delivery.`;
  }
  if (entry.type === 'task_payment') {
    return task
      ? `Released for #${task.issue_number || '-'} ${task.title || 'project task'}.`
      : `Released to ${ledgerAccountLabel(entry.to_account)} from the task reserve.`;
  }
  if (entry.type === 'token_mint') return `${tokenSymbol.value} mint recorded for the payer after funding verification.`;
  if (entry.type === 'platform_fee') return 'Platform fee logged as part of the verified payment flow.';
  if (entry.type === 'project_reserve') return 'Escrow reserve created to protect the full project budget.';
  return task
    ? `Budget reserved for #${task.issue_number || '-'} ${task.title || 'project task'}.`
    : 'Budget reserved for task delivery.';
}

function mapDashboardPaymentRow(entry = {}, project = {}, tasks = []) {
  const meta = ledgerMetaFor(entry.type);
  const when = formatLedgerDateTime(entry.created_at);
  const task = taskForLedgerEntry(entry, tasks);
  const amount = formatMRGFromCents(entry.amount_cents);
  const contractReference = contractReferenceFromRecord(entry);
  return {
    key: `${entry.sequence}-${entry.entry_hash || entry.reference}`,
    type: meta.type,
    tone: meta.tone,
    title: project.title || 'MergeOS payment history',
    body: paymentBodyForEntry(entry, project, task),
    method: paymentMethodForEntry(entry, project, task),
    status: paymentStatusForEntry(entry, project),
    counterparty: entry.type === 'task_payment' ? ledgerAccountLabel(entry.to_account) : paymentProviderLabel(project.payment_provider || entry.from_account),
    amount: meta.amountTone === 'negative' ? `- ${amount}` : meta.amountTone === 'positive' ? `+ ${amount}` : amount,
    amountClass: meta.amountTone,
    when: when.full,
    reference: shortLedgerReference(entry.reference || entry.entry_hash || `#${entry.sequence}`),
    rawReference: entry.reference || entry.entry_hash || `#${entry.sequence}`,
    contractReference: shortLedgerHash(contractReference),
    rawContractReference: contractReference,
  };
}

function adminReadinessLabel(summary = {}) {
  const ready = [summary.github_ready, summary.smtp_ready, summary.paypal_ready || summary.crypto_ready || summary.dev_payment_enabled]
    .filter(Boolean).length;
  return `${ready} / 3 ready`;
}

function adminOpsTone(severity = '') {
  const normalized = String(severity || '').toLowerCase();
  if (normalized === 'critical') return 'red';
  if (normalized === 'high') return 'amber';
  if (normalized === 'low') return 'green';
  return 'blue';
}

function mapAdminDisputeLane(lane = {}, query = '') {
  const items = (lane.items || []).map(mapAdminOpsItem);
  const visibleItems = query
    ? items.filter((item) => [
      item.type,
      item.title,
      item.body,
      item.project,
      item.reference,
      item.auditLabel,
      item.policy,
      item.status,
      item.severity,
    ].filter(Boolean).join(' ').toLowerCase().includes(query))
    : items;
  return {
    id: lane.id || lane.title || 'lane',
    title: lane.title || 'Operations lane',
    body: trimMarketplaceText(lane.body, 'Admin review lane.'),
    tone: lane.tone || 'blue',
    count: Number(lane.count) || items.length,
    critical: Number(lane.critical_count) || 0,
    high: Number(lane.high_count) || 0,
    reward: formatMRGFromCents(lane.reward_cents || 0),
    items: visibleItems.slice(0, 3),
  };
}

function mapAdminOpsItem(item = {}) {
  const when = formatLedgerDateTime(item.created_at);
  const actionPacket = item.action_packet || {};
  const actionLabel = adminOpsActionLabel(actionPacket);
  const auditLabel = ledgerAuditLabel(item);
  return {
    id: item.id || `${item.type || 'ops'}-${item.created_at || item.title}`,
    type: toTitleLabel(item.type || 'ops item'),
    severity: toTitleLabel(item.severity || 'medium'),
    tone: adminOpsTone(item.severity),
    title: item.title || 'Admin ops item',
    body: trimMarketplaceText(item.body, 'Review this operational signal.'),
    project: item.project_title || (item.project_id ? shortLedgerReference(item.project_id) : 'MergeOS'),
    task: item.issue_number ? `#${item.issue_number}` : shortLedgerReference(item.task_id || ''),
    reference: shortLedgerReference(item.reference || item.url || ''),
    rawReference: item.reference || item.url || '',
    url: item.url || '',
    automation: item.automation || '',
    policy: item.policy || '',
    proofType: item.proof_type || '',
    amount: item.amount_cents ? formatMRGFromCents(item.amount_cents) : '',
    auditLabel,
    status: toTitleLabel(item.status || 'needs review'),
    canExecute: actionPacket.can_execute === true,
    actionLabel,
    busyLabel: (actionPacket.resolution_payload || actionPacket.resolutionPayload) ? 'Recording' : 'Releasing',
    actionPacket,
    nextAction: actionPacket.next_action || '',
    when: when.full,
  };
}

function adminOpsActionLabel(packet = {}) {
  const resolutionPayload = packet.resolution_payload || packet.resolutionPayload || {};
  const resolution = resolutionPayload.resolution || '';
  switch (resolution) {
  case 'dismissed':
    return 'Dismiss';
  case 'escalated':
    return 'Escalate';
  case 'blocked':
    return 'Block';
  case 'approved':
    return 'Approve';
  case 'resolved':
    return 'Resolve';
  default:
    return packet.status === 'ready' ? 'Release' : 'Inspect';
  }
}

function adminTaskIDFromReference(reference = '') {
  const match = String(reference || '').match(/(?:^|;)task:([^;]+)/);
  return match ? match[1] : '';
}

function mapAdminPayoutEntry(entry = {}, taskIndex = new Map()) {
  const when = formatLedgerDateTime(entry.created_at);
  const taskID = adminTaskIDFromReference(entry.reference);
  const task = taskIndex.get(taskID) || {};
  const automation = entry.automation || (ledgerReferenceField(entry.reference, 'auto_release') ? 'auto_release' : '');
  const policy = entry.policy || ledgerReferenceField(entry.reference, 'auto_release');
  const proofType = entry.proof_type || (automation === 'auto_release' ? 'auto_release_policy' : '');
  const auditLabel = ledgerAuditLabel({ automation, policy, proof_type: proofType });
  return {
    key: `${entry.sequence}-${entry.entry_hash || entry.reference}`,
    type: entry.type === 'manual_credit' ? 'Manual credit' : 'Task payout',
    amount: formatMRGFromCents(entry.amount_cents),
    account: ledgerAccountLabel(entry.to_account),
    reference: shortLedgerReference(entry.reference || entry.entry_hash || `#${entry.sequence}`),
    project: task.project_id ? shortLedgerReference(task.project_id) : 'Ledger',
    task: task.issue_number ? `#${task.issue_number} ${task.title || 'task'}` : shortLedgerReference(taskID || 'manual'),
    automation,
    policy,
    proofType,
    auditLabel,
    status: automation === 'auto_release' ? 'Auto-release' : entry.type === 'manual_credit' ? 'Audit' : 'Released',
    when: when.full,
  };
}

function mapAdminUserRow(row = {}) {
  const audit = row.worker_audit || {};
  return {
    id: row.id || row.email || row.name,
    name: row.name || row.email || 'MergeOS user',
    email: row.email || '-',
    role: toTitleLabel(row.role || 'client'),
    roleTone: row.role === 'admin' ? 'purple' : 'blue',
    wallet: row.wallet_address ? shortWallet(row.wallet_address) : 'No wallet',
    github: row.github_username ? `github:${row.github_username}` : 'No GitHub',
    projects: String(Number(row.project_count) || 0),
    budget: formatMRGFromCents(row.total_budget_cents),
    risk: toTitleLabel(audit.risk_level || 'new'),
    score: Number(audit.score) || 0,
  };
}

function mapAdminReputationRow(row = {}) {
  return {
    id: row.worker_id || row.user_id || row.name,
    worker: row.worker_id || row.name || 'worker',
    risk: toTitleLabel(row.risk_level || 'new'),
    score: Number(row.score) || 0,
    paid: formatMRGFromCents(row.reward_cents),
    tasks: String(Number(row.claimed_task_count || row.completed_task_count) || 0),
    flags: Array.isArray(row.flags) && row.flags.length ? row.flags.map(toTitleLabel).join(', ') : 'No flags',
  };
}

function taskIssueReference(task = {}) {
  if (task.issue_url) {
    const parts = String(task.issue_url).split(/[\\/]/).filter(Boolean);
    return parts.slice(-2).join('/');
  }
  return task.suggested_agent_type ? toTitleLabel(task.suggested_agent_type) : toTitleLabel(task.required_worker_kind || 'task');
}

function escrowStatusTone(status = '') {
  const normalized = String(status || '').toLowerCase();
  if (normalized === 'released') return 'accepted';
  if (normalized === 'partial' || normalized === 'overpaid') return 'submitted';
  return 'open';
}

function mapDashboardEscrowTask(row = {}) {
  const status = String(row.status || 'open').toLowerCase();
  const releaseStatus = String(row.release_status || 'reserved').toLowerCase();
  const releasePacket = row.release_packet || {};
  const releasePayload = releasePacket.payload || {};
  return {
    id: row.task_id || `${row.issue_number || 'task'}-${row.title || 'escrow'}`,
    issueNumber: row.issue_number || '-',
    title: row.title || 'Escrow task',
    reward: formatMRGFromCents(row.reward_cents),
    paid: formatMRGFromCents(row.paid_cents),
    remaining: formatMRGFromCents(row.remaining_cents),
    worker: row.worker_id ? shortLedgerReference(row.worker_id) : 'Unassigned',
    status: toTitleLabel(releaseStatus),
    statusClass: escrowStatusTone(releaseStatus),
    taskStatus: toTitleLabel(status),
    canRelease: releasePacket.can_release === true,
    releaseCommand: releasePacket.release_endpoint
      ? `${releasePacket.method || 'POST'} ${releasePacket.release_endpoint}`
      : releasePacket.status ? `Release ${toTitleLabel(releasePacket.status)}` : '',
    releasePacket,
    workerKind: releasePayload.worker_kind || row.worker_kind || '',
    workerID: releasePayload.worker_id || row.worker_id || '',
    agentType: releasePayload.agent_type || row.agent_type || '',
  };
}

function mapDashboardTask(task = {}) {
  const rawStatus = task.status || 'open';
  const releasePacket = task.release_packet || task.releasePacket || {};
  const autoReleasePacket = task.auto_release_packet || task.autoReleasePacket || {};
  const status = rawStatus === 'accepted'
    ? 'Accepted'
    : rawStatus === 'submitted'
      ? 'In review'
      : rawStatus === 'claimed'
        ? 'Claimed'
        : 'Open';
  const reviewURL = task.pull_request_url || task.review_evidence_url || '';
  const workerKind = task.worker_kind || task.required_worker_kind || 'human';
  const workerID = task.worker_id || '';
  const agentType = task.agent_type || task.suggested_agent_type || '';
  return {
    id: task.id || `${task.project_id}-${task.issue_number}`,
    initials: String(task.issue_number || 'T').padStart(2, '0').slice(-2),
    issueNumber: task.issue_number || '-',
    title: task.title || 'Untitled task',
    acceptance: trimMarketplaceText(task.acceptance, 'Acceptance criteria not provided.'),
    reference: reviewURL ? shortLedgerReference(reviewURL) : taskIssueReference(task),
    reward: formatMRGFromCents(task.reward_cents),
    kind: toTitleLabel(workerKind || 'task'),
    agent: agentType ? toTitleLabel(agentType) : '-',
    status,
    statusClass: rawStatus === 'accepted' ? 'accepted' : rawStatus === 'submitted' ? 'submitted' : rawStatus === 'claimed' ? 'claimed' : 'open',
    reviewURL,
    canRelease: releasePacket.can_release === true || (!task.release_packet && rawStatus === 'submitted' && Boolean(workerID)),
    releasePacket,
    autoReleasePacket,
    canAutoRelease: autoReleasePacket.can_auto_release === true,
    workerKind,
    workerID,
    agentType,
  };
}

function mapDashboardPullRequest(row = {}) {
  const reviewStatus = row.review_status || row.status || 'open';
  const readiness = row.readiness || {};
  const liveStatus = row.live_status || null;
  const pullRequestURL = row.pull_request_url || '';
  const evidenceURL = row.evidence_url || row.review_evidence_url || '';
  const issueURL = row.issue_url || '';
  const workerKind = row.worker_kind || row.required_worker_kind || 'human';
  const workerID = row.worker_id || '';
  const agentType = row.agent_type || row.suggested_agent_type || '';
  const when = formatLedgerDateTime(row.accepted_at || row.submitted_at || row.updated_at || row.created_at);
  const statusClass = reviewStatus === 'paid'
    ? 'accepted'
    : reviewStatus === 'needs_review'
      ? 'submitted'
      : reviewStatus === 'claimed'
        ? 'claimed'
        : 'open';
  const status = reviewStatus === 'paid'
    ? 'Paid'
    : reviewStatus === 'needs_review'
      ? 'Needs review'
      : reviewStatus === 'claimed'
        ? 'Claimed'
        : toTitleLabel(reviewStatus);
  const signals = Array.isArray(readiness.signals) ? readiness.signals.slice(0, 3) : [];
  if (liveStatus?.status) {
    signals.unshift(`GitHub: ${toTitleLabel(liveStatus.status)}`);
  }
  if (liveStatus?.mergeable_state) {
    signals.push(`Merge: ${toTitleLabel(liveStatus.mergeable_state)}`);
  }
  if (liveStatus?.error) {
    signals.push('GitHub sync unavailable');
  }
  const primaryURL = pullRequestURL || evidenceURL || issueURL;
  const releasePacket = row.release_packet || {};
  const autoReleasePacket = row.auto_release_packet || {};
  const contractReference = contractReferenceFromRecord(row);
  const releaseCommand = releasePacket.release_endpoint
    ? `${releasePacket.method || 'POST'} ${releasePacket.release_endpoint}`
    : releasePacket.status ? `Release ${toTitleLabel(releasePacket.status)}` : '';
  const autoReleaseCommand = autoReleasePacket.release_endpoint
    ? `${autoReleasePacket.method || 'POST'} ${autoReleasePacket.release_endpoint}`
    : autoReleasePacket.status ? `Auto ${toTitleLabel(autoReleasePacket.status)}` : '';
  return {
    id: row.task_id || row.id || `${row.project_id}-${row.issue_number}`,
    initials: String(row.issue_number || 'PR').padStart(2, '0').slice(-2),
    issueNumber: row.issue_number || '-',
    title: liveStatus?.title || row.title || 'Submitted work',
    acceptance: trimMarketplaceText(row.acceptance, 'Review submitted for this task.'),
    reward: formatMRGFromCents(row.reward_cents),
    worker: liveStatus?.author ? `@${liveStatus.author}` : workerID ? shortLedgerReference(workerID) : 'Unassigned',
    lane: agentType ? toTitleLabel(agentType) : toTitleLabel(workerKind),
    status,
    statusClass,
    readiness: toTitleLabel(liveStatus?.readiness || readiness.status || reviewStatus),
    risk: liveStatus?.error ? 'Sync issue' : toTitleLabel(readiness.risk_level || liveStatus?.risk_level || 'medium'),
    when: when.date === '-' ? '-' : when.date,
    whenLabel: reviewStatus === 'paid' ? 'Paid' : 'Submitted',
    primaryURL,
    primaryLabel: pullRequestURL ? 'PR' : evidenceURL ? 'Evidence' : 'Issue',
    pullRequestURL,
    evidenceURL,
    reference: row.repository && row.pull_number
      ? `${row.repository}#${row.pull_number}`
      : shortLedgerReference(pullRequestURL || evidenceURL || issueURL || `issue:${row.issue_number || '-'}`),
    contractReference: shortLedgerHash(contractReference),
    rawContractReference: contractReference,
    signals: signals.slice(0, 5),
    canRelease: releasePacket.can_release === true || (!row.release_packet && (readiness.can_release === true || (!readiness.status && row.status === 'submitted' && Boolean(workerID)))),
    releaseCommand,
    releasePacket,
    canAutoRelease: autoReleasePacket.can_auto_release === true,
    autoReleaseCommand,
    autoReleasePacket,
    workerKind,
    workerID,
    agentType,
  };
}

function mapDashboardRoutingLane(row = {}) {
  return {
    id: row.id || `${row.worker_kind || 'lane'}-${row.agent_type || 'human'}`,
    title: row.title || toTitleLabel(row.agent_type || row.worker_kind || 'lane'),
    kind: toTitleLabel(row.worker_kind || 'worker'),
    recommendedFor: toTitleLabel(row.recommended_for || 'delivery'),
    taskCount: Number(row.task_count) || 0,
    readyCount: Number(row.ready_count) || 0,
    blockedCount: Number(row.blocked_count) || 0,
    reward: formatMRGFromCents(row.reward_cents),
    status: toTitleLabel(row.status || 'routing'),
    tone: row.status === 'ready' ? 'green' : row.status === 'blocked' ? 'amber' : 'blue',
  };
}

function routingActionLabel(value = '') {
  const normalized = String(value || '').toLowerCase();
  return {
    route_to_agent: 'Route agent',
    route_hybrid_pair: 'Pair hybrid',
    invite_contributor: 'Invite contributor',
    publish_bounty: 'Publish bounty',
    wait_for_dependencies: 'Wait dependencies',
    wait_for_evidence: 'Await evidence',
    review_submission: 'Review',
    paid: 'Paid',
  }[normalized] || toTitleLabel(normalized || 'Route');
}

function mapDashboardRoutingRoute(row = {}) {
  const worker = row.recommended_worker || null;
  const agent = row.recommended_agent || null;
  const nextAction = row.recommended_next_action || '';
  const status = row.status || 'open';
  const candidate = worker?.name || agent?.title || (row.suggested_agent_type ? toTitleLabel(row.suggested_agent_type) : 'Open bounty');
  return {
    id: row.id || row.task_id || `${row.issue_number}-${row.title}`,
    issueNumber: row.issue_number || '-',
    title: row.title || 'Routed task',
    lane: toTitleLabel(row.lane || row.required_worker_kind || 'delivery'),
    workerKind: toTitleLabel(row.required_worker_kind || 'worker'),
    reward: formatMRGFromCents(row.reward_cents),
    score: Math.max(0, Math.min(100, Number(row.match_score) || 0)),
    status: status === 'accepted' ? 'Paid' : row.ready ? 'Ready' : 'Blocked',
    statusClass: status === 'accepted' ? 'accepted' : row.ready ? 'open' : 'submitted',
    candidate,
    candidateMeta: worker
      ? `${worker.reputation_score || 0} rep - ${toTitleLabel(worker.risk_level || 'new')} risk`
      : agent
        ? `${toTitleLabel(agent.status || 'standby')} - ${toTitleLabel(agent.type || 'agent')}`
        : `${Number(row.blocked_by?.length) || 0} blockers`,
    action: routingActionLabel(nextAction),
    reason: Array.isArray(row.routing_reason) && row.routing_reason.length
      ? row.routing_reason.slice(0, 2).join(' - ')
      : 'Routing reason pending.',
  };
}

function repoSeverityTone(value = '') {
  const normalized = String(value || '').toLowerCase();
  if (normalized === 'high' || normalized === 'critical') return 'red';
  if (normalized === 'medium') return 'amber';
  if (normalized === 'low') return 'blue';
  return 'green';
}

function repoFindingLocation(path = '', line = 0) {
  const cleanPath = String(path || '').trim();
  if (!cleanPath) return 'Repository';
  const lineNumber = Number(line) || 0;
  return lineNumber > 0 ? `${cleanPath}:${lineNumber}` : cleanPath;
}

function mapDashboardRepositoryFinding(row = {}) {
  const severity = row.severity || 'info';
  return {
    id: row.id || `${row.path || 'repo'}-${row.line || 0}-${row.signal || row.title || 'finding'}`,
    title: row.title || 'Repository finding',
    body: trimMarketplaceText(row.body, 'Repository scan signal.'),
    severity: toTitleLabel(severity),
    category: toTitleLabel(row.category || row.signal || 'scan'),
    tone: repoSeverityTone(severity),
    location: repoFindingLocation(row.path, row.line),
  };
}

function mapDashboardRepositoryDependency(row = {}) {
  return {
    key: `${row.ecosystem || 'dependency'}-${row.path || 'root'}`,
    path: row.path || 'Repository root',
    ecosystem: toTitleLabel(row.ecosystem || 'dependency'),
    packages: `${Number(row.package_count) || 0} packages`,
    lockfile: row.has_lockfile ? 'Lockfile found' : 'No lockfile',
    tone: row.has_lockfile ? 'green' : 'amber',
  };
}

function mapDashboardRepositorySuggestedTask(row = {}) {
  const severity = row.severity || 'low';
  const worker = row.suggested_agent_type || row.worker_kind || 'worker';
  const packet = row.funding_packet || {};
  const fundingPayload = packet.fund_payload || {};
  const paypalPayload = packet.paypal_order_payload || {};
  const rewardCents = Number(packet.recommended_reward_cents || fundingPayload.reward_cents || row.estimated_reward_cents) || 0;
  const recommendedFundingCents = Number(packet.recommended_funding_cents) || 0;
  const status = packet.status || (row.ready_for_bounty ? 'ready' : 'needs_review');
  const canFund = packet.can_fund !== false && row.ready_for_bounty !== false && status !== 'already_funded';
  const fundingHint = recommendedFundingCents
    ? `${formatMRGFromCents(recommendedFundingCents)} funding packet - ${toTitleLabel(status)}`
    : `${toTitleLabel(status)} funding packet`;
  return {
    id: row.id || `${row.source_finding_id || row.signal || 'repo-task'}-${row.title || ''}`,
    title: row.title || 'Suggested repository task',
    lane: toTitleLabel(row.lane || 'implementation'),
    agent: toTitleLabel(worker),
    location: repoFindingLocation(row.path, 0),
    reward: formatMRGFromCents(rewardCents),
    reward_cents: rewardCents,
    recommendedFundingCents,
    status,
    statusClass: canFund ? 'open' : status === 'already_funded' ? 'accepted' : repoSeverityTone(severity),
    canFund,
    actionLabel: status === 'already_funded' ? 'Funded' : canFund ? 'Fund' : 'Review',
    fundingHint,
    fundEndpoint: packet.fund_endpoint || '',
    paypalOrderEndpoint: packet.paypal_order_endpoint || '',
    fundingPayload,
    paypalPayload,
    evidenceChecklist: Array.isArray(packet.evidence_checklist) ? packet.evidence_checklist : [],
  };
}

function mapDashboardTaskGraphNode(node = {}) {
  const status = String(node.status || 'open').toLowerCase();
  const ready = node.ready === true;
  const blockedBy = Array.isArray(node.blocked_by) ? node.blocked_by : [];
  return {
    id: node.task_id || node.id || `${node.issue_number || 'task'}-${node.title || 'node'}`,
    issueNumber: node.issue_number || '-',
    title: node.title || 'Task graph node',
    lane: toTitleLabel(node.lane || node.required_worker_kind || 'work'),
    reward: formatMRGFromCents(node.reward_cents),
    status: status === 'accepted' ? 'Accepted' : ready ? 'Ready' : 'Blocked',
    statusClass: status === 'accepted' ? 'accepted' : ready ? 'open' : 'submitted',
    agent: node.suggested_agent_type ? toTitleLabel(node.suggested_agent_type) : toTitleLabel(node.required_worker_kind || 'worker'),
    blockedBy: blockedBy.length ? `${blockedBy.length} dependencies` : 'No blockers',
  };
}

function mapDashboardDeploymentStage(stage = {}) {
  const reference = stage.reference || (stage.source_task_issue_number ? `issue:${stage.source_task_issue_number}` : '');
  return {
    id: stage.id || stage.title || reference,
    title: stage.title || 'Deployment stage',
    body: trimMarketplaceText(stage.body, 'Deployment validation stage.'),
    status: toTitleLabel(stage.status || 'pending'),
    tone: stage.tone || (stage.status === 'complete' ? 'green' : stage.status === 'in_progress' ? 'blue' : 'amber'),
    reference: shortLedgerReference(reference),
  };
}

function mapDashboardDeploymentSignal(signal = {}) {
  return {
    id: signal.id || `${signal.type || 'signal'}-${signal.created_at || signal.reference || signal.title}`,
    title: signal.title || toTitleLabel(signal.type || 'Signal'),
    reference: shortLedgerReference(signal.reference || ''),
    status: toTitleLabel(signal.status || 'live'),
  };
}

function mapDashboardAIWorkflowStage(stage = {}) {
  return {
    id: stage.id || stage.title || stage.reference,
    title: stage.title || 'AI workflow stage',
    body: trimMarketplaceText(stage.body, 'AI orchestration stage.'),
    status: toTitleLabel(stage.status || 'pending'),
    tone: stage.tone || (stage.status === 'complete' ? 'green' : stage.status === 'in_progress' ? 'blue' : 'amber'),
  };
}

function mapDashboardWorkflowPulseStage(stage = {}) {
  const status = String(stage.status || 'pending');
  return {
    id: stage.id || stage.title || stage.reference,
    title: stage.title || 'Workflow pulse stage',
    body: trimMarketplaceText(stage.body, 'Delivery pulse stage.'),
    status: toTitleLabel(status),
    progress: Math.max(0, Math.min(100, Number(stage.progress) || 0)),
    tone: stage.tone || (status === 'complete' ? 'green' : status === 'active' || status === 'in_progress' ? 'blue' : 'amber'),
  };
}

function mapWorkerClaimedTask(task = {}) {
  const status = task.status || (task.accepted_at ? 'accepted' : 'claimed');
  const when = formatLedgerDateTime(task.accepted_at || task.submitted_at || task.claimed_at);
  const pullRequestURL = task.pull_request_url || '';
  const reviewEvidenceURL = task.review_evidence_url || '';
  return {
    id: task.id || `${task.project_id}-${task.issue_number}`,
    initials: String(task.issue_number || 'W').padStart(2, '0').slice(-2),
    issueNumber: task.issue_number || '-',
    title: task.title || 'Accepted task',
    acceptance: trimMarketplaceText(task.acceptance, 'Acceptance criteria not provided.'),
    project: task.project_title || 'MergeOS project',
    reward: formatMRGFromCents(task.reward_cents),
    kind: task.agent_type ? toTitleLabel(task.agent_type) : toTitleLabel(task.worker_kind || 'worker'),
    when: when.date === '-' ? '-' : when.date,
    whenLabel: status === 'accepted' ? 'Accepted' : status === 'submitted' ? 'Submitted' : 'Claimed',
    status: status === 'accepted' ? 'Paid' : status === 'submitted' ? 'In review' : 'Claimed',
    statusTone: status === 'accepted' ? 'accepted' : status === 'submitted' ? 'submitted' : 'claimed',
    pullRequestURL,
    reviewEvidenceURL,
    reviewNotes: task.review_notes || '',
    submittedAt: task.submitted_at || '',
    reviewURL: pullRequestURL || reviewEvidenceURL || '',
    canSubmitReview: status !== 'accepted',
  };
}

function mapWorkerReward(entry = {}) {
  const when = formatLedgerDateTime(entry.created_at);
  return {
    key: `${entry.sequence}-${entry.entry_hash || entry.reference}`,
    type: entry.type === 'manual_credit' ? 'Manual credit' : 'Task payout',
    amount: formatMRGFromCents(entry.amount_cents),
    ref: shortLedgerReference(entry.reference || entry.entry_hash || `#${entry.sequence}`),
    when: when.full,
  };
}

function workerProposalContextRows(context = {}) {
  const labels = {
    task_protocol: 'Task protocol',
    workflow_protocol: 'Workflow',
    workflow_pulse: 'Pulse',
    delivery_snapshot: 'Snapshot',
    deployment: 'Deploy',
    marketplace: 'Market',
    claim: 'Claim',
    submit: 'Submit',
  };
  return Object.entries(labels)
    .map(([key, label]) => ({ key, label, url: context[key] || '' }))
    .filter((row) => row.url);
}

function workerProposalRunbookRows(runbook = []) {
  return (Array.isArray(runbook) ? runbook : []).slice(0, 4).map((step, index) => {
    const endpoint = step.endpoint || (Array.isArray(step.context_urls) ? `${step.context_urls.length} context URLs` : '');
    return {
      key: `${step.action || 'step'}-${step.step || index + 1}`,
      step: step.step || index + 1,
      label: trimMarketplaceText(step.label || toTitleLabel(step.action || 'Runbook step'), 'Runbook step.'),
      meta: [step.method, endpoint || step.expected_status].filter(Boolean).join(' '),
    };
  });
}

function workerProposalPayloadRows(payload = {}, bounty = {}) {
  const resolvedPayload = claimPayloadForBounty({ ...bounty, claimPayload: payload });
  return [
    { label: 'Worker', value: formatClaimWorkerID(resolvedPayload.worker_id) },
    { label: 'Kind', value: toTitleLabel(resolvedPayload.worker_kind || 'human') },
    resolvedPayload.agent_type ? { label: 'Agent', value: toTitleLabel(resolvedPayload.agent_type) } : null,
  ].filter(Boolean);
}

function autoReleaseContextRows(context = {}) {
  const labels = {
    pr_monitor: 'PR monitor',
    workflow_pulse: 'Pulse',
    delivery_snapshot: 'Snapshot',
    deployment: 'Deploy',
    escrow: 'Escrow',
    ledger_events: 'Ledger',
    admin_ops: 'Admin ops',
    release: 'Release',
    manual_release: 'Manual',
  };
  return Object.entries(labels)
    .map(([key, label]) => ({ key, label, url: context[key] || '' }))
    .filter((row) => row.url);
}

function autoReleaseRunbookRows(runbook = []) {
  return (Array.isArray(runbook) ? runbook : []).slice(0, 4).map((step, index) => {
    const contextCount = Array.isArray(step.context_urls) ? step.context_urls.length : 0;
    const endpoint = step.endpoint || (contextCount ? `${contextCount} context URLs` : '');
    return {
      key: `${step.action || 'auto-release'}-${step.step || index + 1}`,
      step: step.step || index + 1,
      label: trimMarketplaceText(step.label || toTitleLabel(step.action || 'Auto-release step'), 'Auto-release step.'),
      meta: [step.method, endpoint, step.expected_status].filter(Boolean).join(' '),
      purpose: trimMarketplaceText(step.purpose, 'Verify release evidence.'),
      required: step.required !== false,
    };
  });
}

function autoReleasePayloadRows(packet = {}, taskIDs = []) {
  const payload = packet.payload || {};
  const policy = packet.policy || payload.policy || '';
  return [
    { label: 'Tasks', value: String(taskIDs.length || (Array.isArray(payload.task_ids) ? payload.task_ids.length : 0)) },
    policy ? { label: 'Policy', value: shortLedgerReference(policy) } : null,
    packet.release_endpoint ? { label: 'Endpoint', value: `${packet.method || 'POST'} ${shortLedgerReference(packet.release_endpoint)}` } : null,
  ].filter(Boolean);
}

function mapWorkerProposal(proposal = {}) {
  const agentType = proposal.suggested_agent_type || '';
  const packet = proposal.claim_packet || {};
  const payload = packet.payload || {};
  const claimPayload = claimPayloadForBounty({
    ...proposal,
    workerKind: payload.worker_kind || proposal.required_worker_kind || 'human',
    agentType: payload.agent_type || agentType,
    claimPayload: payload,
  });
  const canClaim = packet.can_claim !== false && (packet.status || 'ready') === 'ready';
  const issue = proposal.issue_number ? `#${proposal.issue_number}` : '';
  return {
    id: proposal.id || `${proposal.project_id}-${proposal.issue_number}`,
    issue,
    title: proposal.title || 'Open bounty',
    acceptance: trimMarketplaceText(proposal.acceptance, 'Acceptance criteria will appear after task generation.'),
    project: proposal.project_title || 'MergeOS project',
    lane: agentType ? toTitleLabel(agentType) : toTitleLabel(proposal.required_worker_kind || 'worker'),
    reward: formatMRGFromCents(proposal.reward_cents),
    rewardCents: Number(proposal.reward_cents) || 0,
    workerKind: claimPayload.worker_kind || proposal.required_worker_kind || 'human',
    agentType: claimPayload.agent_type || agentType,
    matchScore: Number(proposal.match_score) || 0,
    canClaim,
    actionLabel: canClaim ? 'Claim' : 'Unavailable',
    claimHint: packet.submit_endpoint ? `${toTitleLabel(packet.status || 'ready')} - review handoff ready` : '',
    claimEndpoint: packet.claim_endpoint || '',
    claimPayload,
    submitEndpoint: packet.submit_endpoint || '',
    contextRows: workerProposalContextRows(packet.context_urls || {}),
    runbookRows: workerProposalRunbookRows(packet.runbook),
    payloadRows: workerProposalPayloadRows(claimPayload, proposal),
    evidenceRows: (Array.isArray(packet.evidence_checklist) ? packet.evidence_checklist : []).map(toTitleLabel),
    warningRows: Array.isArray(packet.warnings) ? packet.warnings : [],
  };
}

function mapDashboardActivity(entry = {}) {
  const meta = ledgerMetaFor(entry.type);
  return {
    key: `${entry.sequence}-${entry.entry_hash || entry.reference}`,
    title: meta.type,
    icon: meta.icon,
    color: meta.tone === 'amber' ? 'yellow' : meta.tone,
    time: formatLedgerDateTime(entry.created_at).full,
    createdAt: entry.created_at,
  };
}

function mapDashboardNotification(note = {}) {
  const when = formatLedgerDateTime(note.created_at);
  const marker = `${note.subject || ''} ${note.status || ''} ${note.body || ''}`.toLowerCase();
  return {
    id: note.id || `${note.subject}-${note.created_at}`,
    subject: note.subject || 'Notification',
    body: trimMarketplaceText(note.body, 'MergeOS status update.'),
    meta: `${toTitleLabel(note.channel || 'app')} ظت ${toTitleLabel(note.status || 'logged')} ظت ${when.full}`,
    tone: note.status === 'failed' ? 'red' : marker.includes('release') || marker.includes('ready') ? 'green' : note.project_id ? 'green' : 'blue',
    isUnread: !note.read_at,
    rawId: note.id,
  };
}

function formatLedgerDateTime(value) {
  const date = value ? new Date(value) : new Date();
  if (Number.isNaN(date.getTime())) {
    return { date: '-', time: '-', full: '-' };
  }
  return {
    date: date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric', timeZone: 'UTC' }),
    time: date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', timeZone: 'UTC' }),
    full: `${date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric', timeZone: 'UTC' })} ${date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', timeZone: 'UTC' })} UTC`,
  };
}

function projectInitialFor(value = '') {
  return (String(value).trim().charAt(0) || 'M').toUpperCase();
}

function projectToneFor(value = '') {
  const tones = ['green', 'blue', 'purple'];
  const total = String(value).split('').reduce((sum, char) => sum + char.charCodeAt(0), 0);
  return tones[total % tones.length];
}

function extractProjectID(entry = {}) {
  const haystack = [
    entry.reference,
    entry.from_account,
    entry.to_account,
  ].filter(Boolean).join(' ');
  return haystack.match(/prj_[a-z0-9]+/i)?.[0] || '';
}

function ledgerMetaFor(type = '') {
  const normalized = String(type);
  if (normalized === 'token_mint') {
    return { type: 'Token Minted', icon: Box, tone: 'green', amountTone: 'positive' };
  }
  if (normalized === 'payment_verified') {
    return { type: 'Payment Verified', icon: ShieldCheck, tone: 'green', amountTone: 'positive' };
  }
  if (normalized === 'platform_fee') {
    return { type: 'Platform Fee', icon: CircleDollarSign, tone: 'amber', amountTone: 'negative' };
  }
  if (normalized === 'project_reserve') {
    return { type: 'Escrow Reserved', icon: LockKeyhole, tone: 'blue', amountTone: 'neutral' };
  }
  if (normalized === 'task_reserve') {
    return { type: 'Task Reserve', icon: FileCheck2, tone: 'blue', amountTone: 'neutral' };
  }
  if (normalized === 'task_payment') {
    return { type: 'Payout Released', icon: CircleDollarSign, tone: 'green', amountTone: 'negative' };
  }
  return { type: normalized.replaceAll('_', ' '), icon: Compass, tone: 'slate', amountTone: 'neutral' };
}

function ledgerEconomyRoleMeta(role = '') {
  const normalized = String(role || '').trim();
  if (normalized === 'token_supply') return { label: 'Token supply', icon: Box, tone: 'green' };
  if (normalized === 'treasury') return { label: 'Treasury', icon: BarChart3, tone: 'purple' };
  if (normalized === 'escrow_reserve') return { label: 'Escrow reserve', icon: ShieldCheck, tone: 'blue' };
  if (normalized === 'task_reserve') return { label: 'Task reserve', icon: LockKeyhole, tone: 'blue' };
  if (normalized === 'payouts') return { label: 'Payouts', icon: Trophy, tone: 'amber' };
  return { label: toTitleLabel(normalized || 'balance'), icon: Compass, tone: 'slate' };
}

function ledgerEconomyCountLabel(count = 0) {
  const total = Number(count) || 0;
  return `${total} event${total === 1 ? '' : 's'}`;
}

function mapLedgerEconomyBalance(row = {}) {
  const meta = ledgerEconomyRoleMeta(row.role);
  return {
    id: row.id || row.label || row.role,
    label: row.label || meta.label,
    role: meta.label,
    amount: formatLedgerMRGFromCents(Number(row.amount_cents) || 0),
    count: ledgerEconomyCountLabel(row.entry_count),
    icon: meta.icon,
    tone: meta.tone,
  };
}

function mapLedgerEconomyFlow(row = {}) {
  const meta = ledgerMetaFor(row.type);
  return {
    type: row.type || row.label,
    label: row.label || meta.type,
    amount: formatLedgerMRGFromCents(Number(row.amount_cents) || 0),
    count: Number(row.count) || 0,
    countLabel: ledgerEconomyCountLabel(row.count),
    latestSequence: Number(row.latest_sequence) || 0,
    updated: formatLedgerDateTime(row.updated_at).full,
    icon: meta.icon,
    tone: meta.tone,
  };
}

function mapLedgerEconomyRecentEntry(row = {}) {
  const meta = ledgerMetaFor(row.type);
  const hash = row.entry_hash || '';
  return {
    key: `${row.sequence || row.type || 'entry'}-${hash || row.reference || row.created_at || ''}`,
    label: meta.type,
    amount: formatLedgerMRGFromCents(Number(row.amount_cents) || 0),
    reference: shortLedgerReference(row.reference || row.project_id || row.task_id || `#${row.sequence || ''}`),
    hash,
    shortHash: shortLedgerHash(hash),
    when: formatLedgerDateTime(row.created_at).date,
    icon: meta.icon,
    tone: meta.tone,
  };
}

function liveFeedMetaFor(type = '') {
  const normalized = String(type);
  if (normalized.startsWith('ledger_')) {
    return ledgerMetaFor(normalized.replace(/^ledger_/, ''));
  }
  if (normalized === 'project_funded') {
    return { type: 'Project Funded', icon: FolderKanban, tone: 'green', amountTone: 'positive' };
  }
  if (normalized === 'repo_scan') {
    return { type: 'Repository Scan', icon: Search, tone: 'blue', amountTone: 'muted' };
  }
  if (normalized === 'task_opened') {
    return { type: 'Task Opened', icon: ListTodo, tone: 'blue', amountTone: 'neutral' };
  }
  if (normalized === 'task_claimed') {
    return { type: 'Task Claimed', icon: User, tone: 'blue', amountTone: 'neutral' };
  }
  if (normalized === 'task_submitted') {
    return { type: 'Review Submitted', icon: GitPullRequest, tone: 'amber', amountTone: 'neutral' };
  }
  if (normalized === 'task_accepted') {
    return { type: 'PR Accepted', icon: GitPullRequest, tone: 'green', amountTone: 'positive' };
  }
  if (normalized === 'deployment_validation' || normalized === 'deployment_status') {
    return { type: 'Deployment Validation', icon: Rocket, tone: 'blue', amountTone: 'muted' };
  }
  if (normalized === 'ai_review') {
    return { type: 'AI Review', icon: Bot, tone: 'purple', amountTone: 'muted' };
  }
  if (normalized === 'agent_action') {
    return { type: 'Agent Action', icon: Bot, tone: 'purple', amountTone: 'muted' };
  }
  return { type: toTitleLabel(normalized || 'Activity'), icon: Compass, tone: 'slate', amountTone: 'neutral' };
}

function liveFeedLaneMatches(item = {}, lane = {}) {
  const rawTypes = Array.isArray(lane.rawTypes) ? lane.rawTypes : [];
  const rawMatch = rawTypes.includes(item.rawType);
  if (typeof lane.predicate === 'function') return rawMatch || lane.predicate(item);
  return rawMatch;
}

function liveContributorRiskTone(riskLevel = '') {
  const normalized = String(riskLevel || '').trim().toLowerCase();
  if (['high', 'critical', 'blocked'].includes(normalized)) return 'red';
  if (['medium', 'elevated', 'review'].includes(normalized)) return 'amber';
  if (['low', 'none', 'clear', 'trusted'].includes(normalized)) return 'green';
  return 'green';
}

function liveContributorStatusLabel(row = {}) {
  const risk = String(row.riskLevel || '').trim().toLowerCase();
  if (risk && !['low', 'none', 'clear', 'trusted'].includes(risk)) {
    return toTitleLabel(risk);
  }
  if (row.reputationLevel) return toTitleLabel(row.reputationLevel);
  if (row.reputationScore) return `Score ${row.reputationScore}`;
  return 'Verified';
}

function mapLiveFeedContributorRow(row = {}, index = 0) {
  const role = row.agentType ? toTitleLabel(row.agentType) : toTitleLabel(row.kind || 'human contributor');
  const taskLabel = row.taskCount
    ? `${row.taskCount} task${row.taskCount === 1 ? '' : 's'}`
    : (row.activityType || 'Live activity');
  const earnedLabel = row.earnedCents ? formatPublicMRGFromCents(row.earnedCents) : '';
  const activeLabel = row.lastActiveAt ? `Active ${formatLedgerDateTime(row.lastActiveAt).date}` : 'Recently active';
  return {
    key: row.key || row.workerId || row.name || `contributor-${index}`,
    initials: initialsFor(row.name || row.workerId || 'FW'),
    name: row.name || row.workerId || 'Contributor',
    role,
    meta: [taskLabel, earnedLabel, activeLabel].filter(Boolean).join(' - '),
    status: liveContributorStatusLabel(row),
    statusTone: liveContributorRiskTone(row.riskLevel),
    tone: marketplaceAvatarTones[index % marketplaceAvatarTones.length],
  };
}

function mapPublicLiveFeedItem(item = {}) {
  const meta = liveFeedMetaFor(item.type);
  const when = formatLedgerDateTime(item.created_at);
  const amountCents = Number(item.amount_cents) || 0;
  const projectTitle = item.project_title || 'MergeOS';
  const reference = item.reference || '';
  const contractReference = contractReferenceFromRecord(item);
  const auditLabel = ledgerAuditLabel(item);
  return {
    id: item.id || `${item.type || 'activity'}-${item.created_at || reference || item.title || 'row'}`,
    rawType: item.type || '',
    typeLabel: meta.type,
    icon: meta.icon,
    tone: meta.tone,
    amountTone: meta.amountTone,
    title: item.title || meta.type,
    body: trimMarketplaceText(item.body, 'MergeOS live activity recorded.'),
    project: projectTitle,
    actor: item.actor || 'MergeOS',
    amount: amountCents ? formatPublicMRGFromCents(amountCents) : '',
    reference: shortLedgerReference(reference),
    rawReference: reference,
    contractReference: shortLedgerHash(contractReference),
    rawContractReference: contractReference,
    url: item.url || '',
    status: toTitleLabel(item.status || 'live'),
    date: when.date,
    time: when.time,
    auditLabel,
    meta: `${when.full} ظت ${toTitleLabel(item.status || 'live')}`,
    createdAt: item.created_at,
    rawContributor: item.contributor && typeof item.contributor === 'object' ? item.contributor : null,
  };
}

function deploymentRealtimeLiveFeedItem(payload = {}) {
  const deployment = payload.deployment && typeof payload.deployment === 'object' ? payload.deployment : {};
  const item = payload.item && typeof payload.item === 'object' ? payload.item : {};
  if (item.id) {
    return {
      ...item,
      type: item.type || 'deployment_validation',
      created_at: item.created_at || payload.created_at || deployment.updated_at,
    };
  }
  const projectID = payload.project_id || deployment.project_id || '';
  if (!projectID) return null;
  const projectTitle = payload.project_title || deployment.project_title || 'MergeOS project';
  const progress = Math.max(0, Math.min(100, Number(payload.progress ?? deployment.progress) || 0));
  const status = payload.status || deployment.status || payload.validation_status || 'queued';
  const createdAt = payload.created_at || deployment.updated_at || new Date().toISOString();
  return {
    id: payload.event_id || `deployment:${projectID}:${status}:${progress}`,
    type: 'deployment_status',
    title: status === 'ready' ? 'Deployment validation ready' : 'Deployment validation updated',
    body: `${projectTitle} deployment gate is ${progress}% complete across QA, handoff, and release checks.`,
    project_id: projectID,
    project_title: projectTitle,
    actor: payload.actor || 'mergeos-orchestrator',
    reference: `project:${projectID}`,
    status,
    created_at: createdAt,
  };
}

function ledgerEntryToLiveFeedItem(entry = {}) {
