    created_at: entry.created_at,
  };
}

function ledgerProjectFilterValue(item = {}) {
  if (item.project_id) return `project:${item.project_id}`;
  if (item.project_title) return `title:${item.project_title}`;
  return 'MergeOS';
}

function ledgerProjectFilterLabel(item = {}) {
  if (item.project_title) return item.project_title;
  if (item.project_id) return `Project ${String(item.project_id).slice(-6)}`;
  return 'MergeOS';
}

function ledgerEventMatchesProject(item = {}, filter = 'All Projects') {
  return filter === 'All Projects' || ledgerProjectFilterValue(item) === filter;
}

function ledgerEventMatchesType(item = {}, filter = 'All types') {
  return filter === 'All types' || liveFeedMetaFor(item.type).type === filter;
}

function ledgerEventMatchesStatus(item = {}, filter = 'All statuses') {
