}

function ledgerEventSearchHaystack(item = {}) {
  return [
    item.id,
    item.type,
    liveFeedMetaFor(item.type).type,
    item.title,
    item.actor,
    item.status,
    item.reference,
    item.contract_reference,
    item.url,
    item.amount_cents,
  ].filter(Boolean).join(' ').toLowerCase();
}

function ledgerProofItemText(item = {}) {
  return [
    item.id,
    item.type,
    liveFeedMetaFor(item.type).type,
    item.title,
    item.actor,
    item.status,
    item.reference,
    item.contract_reference,
    item.url,
    item.automation,
    item.policy,
    item.proof_type,
    ledgerAuditLabel(item),
    ledgerTransparencySecondary(item.type),
  ].filter(Boolean).join(' ').toLowerCase();
}

function ledgerEventMatchesTab(item = {}, tab = 'All Activity') {
  const type = String(item.type || '');
  switch (tab) {
    case 'Escrow & Payments':
      return type === 'project_funded' || (type.startsWith('ledger_') && !type.includes('token_mint'));
    case 'Tasks & PRs':
      return type.startsWith('task_');
    case 'Milestones':
      return type === 'project_funded' || type === 'repo_scan' || type === 'deployment_validation' || type === 'deployment_status';
    case 'AI Actions':
      return type === 'ai_review' || type === 'agent_action';
    case 'Token Events':
      return type === 'ledger_token_mint';
    default:
      return true;
  }
}

function mapLedgerTransparencyEvent(item = {}) {
  const meta = liveFeedMetaFor(item.type);
  const when = formatLedgerDateTime(item.created_at);
  const amountCents = Number(item.amount_cents) || 0;
  const hasAmount = amountCents !== 0;
  const projectTitle = item.project_title || (item.project_id ? `Project ${String(item.project_id).slice(-6)}` : 'MergeOS');
  const reference = item.reference || item.url || item.id || item.type || 'event';
  const contractReference = contractReferenceFromRecord(item);
  const auditLabel = ledgerAuditLabel(item);
  return {
    key: item.id || `${item.type || 'event'}-${item.created_at || reference}`,
    date: when.date,
    time: when.time,
    createdAt: item.created_at,
    type: meta.type,
    icon: meta.icon,
    tone: meta.tone,
    projectInitial: projectInitialFor(projectTitle),
    projectTone: projectToneFor(item.project_id || projectTitle),
    project: projectTitle,
    company: item.actor || 'MergeOS',
    amount: hasAmount ? `${formatCompactNumber(Math.abs(tokenAmountFromCents(amountCents)))} ${tokenSymbol.value}` : toTitleLabel(item.status || 'event'),
    secondaryAmount: auditLabel || (hasAmount ? ledgerTransparencySecondary(item.type) : shortLedgerReference(item.actor || '')),
    amountTone: hasAmount ? meta.amountTone : 'muted',
    status: toTitleLabel(item.status || 'verified'),
    ref: shortLedgerReference(reference),
    rawReference: reference,
    contractReference: shortLedgerHash(contractReference),
    rawContractReference: contractReference,
    auditLabel,
    url: item.url || '',
  };
}

function ledgerTransparencySecondary(type = '') {
  const normalized = String(type || '');
  if (normalized === 'project_funded' || normalized === 'ledger_payment_verified') return 'funding verified';
  if (normalized === 'ledger_token_mint') return 'mint log';
  if (normalized === 'ledger_task_payment') return 'release proof';
  if (normalized === 'repo_scan') return 'repository intelligence';
  if (normalized.startsWith('task_')) return 'workflow event';
  if (normalized === 'agent_action' || normalized === 'ai_review') return 'agent proof';
  if (normalized === 'deployment_validation' || normalized === 'deployment_status') return 'deployment gate';
  return '';
}

function ledgerAuditLabel(item = {}) {
  if (item.automation === 'auto_release') {
    return item.policy ? `auto-release: ${shortLedgerReference(item.policy)}` : 'auto-release';
  }
  if (item.proof_type) {
    return toTitleLabel(item.proof_type);
  }
  return '';
}

function ledgerReferenceField(reference = '', key = '') {
  const wanted = String(key || '').trim().toLowerCase();
  if (!wanted) return '';
  const parts = String(reference || '').split(';');
  for (const part of parts) {
    const separator = part.indexOf(':');
    if (separator <= 0) continue;
    const fieldKey = part.slice(0, separator).trim().toLowerCase();
    if (fieldKey === wanted) {
      return part.slice(separator + 1).trim();
    }
  }
  return '';
}

function mapLedgerEntry(entry) {
  const projectID = extractProjectID(entry);
  const project = ledgerProjectIndex.value.get(projectID);
  const meta = ledgerMetaFor(entry.type);
  const when = formatLedgerDateTime(entry.created_at);
  const tokenAmount = tokenAmountFromCents(entry.amount_cents);
  const projectTitle = project?.title || (projectID ? `Project ${projectID.slice(-6)}` : 'MergeOS ledger');
  const company = project?.company_name || project?.client_name || 'MergeOS';
  const contractReference = contractReferenceFromRecord(entry);
  return {
    key: `${entry.sequence}-${entry.entry_hash || entry.reference}`,
    date: when.date,
    time: when.time,
    createdAt: entry.created_at,
    type: meta.type,
    icon: meta.icon,
    tone: meta.tone,
    projectInitial: projectInitialFor(projectTitle),
    projectTone: projectToneFor(projectID || projectTitle),
    project: projectTitle,
    company,
    amount: `${formatCompactNumber(Math.abs(tokenAmount))} ${tokenSymbol.value}`,
    secondaryAmount: entry.type === 'payment_verified' ? 'funding verified' : entry.type === 'token_mint' ? 'mint log' : '',
    amountTone: meta.amountTone,
    ref: shortLedgerReference(entry.reference || entry.entry_hash || `#${entry.sequence}`),
    rawReference: entry.reference || entry.entry_hash || `#${entry.sequence}`,
    contractReference: shortLedgerHash(contractReference),
    rawContractReference: contractReference,
  };
}

function shortLedgerReference(value = '') {
  const text = String(value);
  if (text.length <= 18) return text;
  return `${text.slice(0, 8)}...${text.slice(-6)}`;
}

function shortLedgerHash(value = '') {
  const text = String(value || '').trim();
  if (!text) return 'Pending';
  if (text.length <= 18) return text;
  return `${text.slice(0, 10)}...${text.slice(-8)}`;
}

function normalizeContractReference(value = '') {
  const text = String(value || '').trim();
  if (!text) return '';
  const normalized = text.startsWith('0x') ? text.slice(2) : text;
  if (!/^[0-9a-fA-F]{64}$/.test(normalized)) return '';
  return `0x${normalized.toLowerCase()}`;
}

function contractReferenceFromRecord(record = {}) {
  if (typeof record === 'string') return normalizeContractReference(record);
  if (!record || typeof record !== 'object') return '';
  const direct = normalizeContractReference(record.contract_reference || record.contractReference || record.reference_hash || record.referenceHash);
  if (direct) return direct;
  const hash = normalizeContractReference(record.entry_hash || record.entryHash || record.proof_hash || record.proofHash || record.public_hash || record.publicHash || record.root_hash || record.rootHash);
  if (hash) return hash;
  const nestedRecords = [
    record.ledger_proof,
    record.ledgerProof,
    record.release_packet,
    record.releasePacket,
    record.auto_release_packet,
    record.autoReleasePacket,
    record.proof,
    record.item,
  ];
  for (const nested of nestedRecords) {
    if (nested && nested !== record) {
      const nestedReference = contractReferenceFromRecord(nested);
      if (nestedReference) return nestedReference;
    }
  }
  return '';
}

async function copyLedgerProofRoot() {
  const root = ledgerProof.value?.public_root_hash || ledgerProof.value?.root_hash || '';
  if (!root) {
    showToast('No ledger root hash yet.');
    return;
  }
  try {
    await navigator.clipboard?.writeText(root);
    showToast('Ledger root hash copied.');
  } catch {
    showToast(`Ledger root ${shortLedgerHash(root)}`);
  }
}

async function copyLedgerContractReference() {
  const reference = ledgerProofContractReference.value;
  if (!reference) {
    showToast('No contract reference yet.');
    return;
  }
  const copied = await copyTextToClipboard(reference);
  showToast(copied ? 'Contract root reference copied.' : `Contract ref ${shortLedgerHash(reference)}`);
}

function paymentMethodForProject() {
  if (projectPaymentMethod.value === 'Credit / Debit card') return 'card';
  if (projectPaymentMethod.value === 'USDC') return 'crypto';
  return 'paypal';
}

function paymentReferenceForProject() {
  if (runtimeConfig.value?.dev_payment_enabled && runtimeConfig.value?.dev_payment_code) {
    return runtimeConfig.value.dev_payment_code;
  }
  return successPaymentReference.value || '';
}

function buildCreateProjectPayload(overrides = {}) {
  const name = user.value?.name || authForm.name || 'MergeOS Client';
  const email = user.value?.email || authForm.email;
  return {
    title: projectSetupForm.title,
    client_name: name,
    company_name: user.value?.company_name || authForm.company_name || 'MergeOS Customer',
    client_email: email,
    site_type: projectSetupForm.projectType,
    package_tier: projectSetupForm.budgetType,
    timeline: projectTimelineLabel.value,
    brief: buildProjectBrief(),
    budget_cents: Number(overrides.budget_cents) || projectPaymentAmountCents.value,
    payment_method: overrides.payment_method || paymentMethodForProject(),
    payment_reference: overrides.payment_reference ?? paymentReferenceForProject(),
    attachment_ids: referenceAttachments.value.map((attachment) => attachment.id).filter(Boolean),
    source_repo_url: projectSetupForm.repoUrl || '',
  };
}

function buildProjectBrief() {
  return [
    projectSetupForm.repoUrl && `Source repository: ${projectSetupForm.repoUrl}`,
    projectSetupForm.shortDescription,
    projectSetupForm.overview && `Overview:\n${projectSetupForm.overview}`,
    repoImportedIssues.value.length && `Imported issues:\n${repoImportedIssues.value.map((issue) => `- #${issue.number} ${issue.title} (score ${issue.score}, ${issue.complexity})`).join('\n')}`,
    visibleDeliverables.value.length && `Deliverables:\n${visibleDeliverables.value.map((item) => `- ${item}`).join('\n')}`,
    projectSetupForm.requirements && `Requirements:\n${projectSetupForm.requirements}`,
    projectSetupForm.techStack && `Tech stack: ${projectSetupForm.techStack}`,
    referenceAttachments.value.length && `Reference files:\n${referenceAttachments.value.map((attachment) => `- ${attachment.original_name} (${formatFileSize(attachment.size_bytes)})`).join('\n')}`,
    `Visibility: ${projectSetupForm.visibility}`,
    `AI agents: ${projectSetupForm.allowAgents ? 'Allowed' : 'Not allowed'}`,
    projectSetupForm.skills && `Skills: ${projectSetupForm.skills}`,
  ].filter(Boolean).join('\n\n');
}

function resetAuthForm(mode = authMode.value) {
  Object.assign(authForm, mode === 'login' ? defaultLoginAuth : defaultRegisterAuth);
  authTermsAccepted.value = mode === 'register';
  authRememberMe.value = false;
  showPassword.value = false;
  showConfirmPassword.value = false;
  authNotice.value = '';
}

function setAuthMode(mode) {
  authMode.value = mode;
  resetAuthForm(mode);
  errorMessage.value = '';
}

function createRequestError(response, payload = {}) {
  const error = new Error(payload.error || 'Request failed');
  error.status = response.status;
  return error;
}

async function api(path, options = {}) {
  const response = await fetch(path, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      ...(token.value ? { Authorization: `Bearer ${token.value}` } : {}),
      ...(options.headers || {}),
    },
  });
  const payload = await response.json();
  if (!response.ok) {
    if (response.status === 401 && path !== '/api/auth/login' && path !== '/api/auth/register') {
      clearSession();
    }
    throw createRequestError(response, payload);
  }
  return payload;
}

async function publicApi(path, options = {}) {
  const response = await fetch(path, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      ...(options.headers || {}),
    },
  });
  const text = await response.text();
  let payload = {};
  try {
    payload = text ? JSON.parse(text) : {};
  } catch {
    payload = { error: text || 'Request failed' };
  }
  if (!response.ok) {
    throw createRequestError(response, payload);
  }
  return payload;
}

function passwordResetReturnURL() {
  if (!hasWindow) return '';
  return `${window.location.origin}${window.location.pathname}`;
}

async function loadMarketplaceData(options = {}) {
  const silent = Boolean(options.silent);
  if (!silent) marketplaceLoading.value = true;
  marketplaceError.value = '';
  agentQueueError.value = '';
  if (!silent) agentQueueLoading.value = true;
  try {
    const payload = await publicApi('/api/public/marketplace');
    hydrateMarketplaceData(payload);
  } catch (error) {
    marketplaceError.value = error.message || 'Could not load marketplace data';
  } finally {
    marketplaceLoading.value = false;
  }

  try {
    const queue = await publicApi('/api/public/agents/queue?limit=50');
    agentQueueData.value = {
      stats: queue.stats || {},
      agents: Array.isArray(queue.agents) ? queue.agents : [],
      tasks: Array.isArray(queue.tasks) ? queue.tasks : [],
    };
  } catch (error) {
    agentQueueError.value = error.message || 'Could not load agent queue';
  } finally {
    agentQueueLoading.value = false;
  }
}

function hydrateMarketplaceData(payload = {}) {
  if (!payload || typeof payload !== 'object') return;
  marketplaceData.value = {
    stats: payload.stats || {},
    projects: Array.isArray(payload.projects) ? payload.projects : [],
    bounties: Array.isArray(payload.bounties) ? payload.bounties : [],
    contributors: Array.isArray(payload.contributors) ? payload.contributors : [],
    agents: Array.isArray(payload.agents) ? payload.agents : [],
  };
  if (!marketplaceCategories.value.includes(activeMarketplaceCategory.value)) {
    activeMarketplaceCategory.value = 'All';
  }
  marketplaceError.value = '';
  marketplaceLoading.value = false;
}

async function loadLiveFeedData(options = {}) {
  const silent = Boolean(options.silent);
  if (!silent) liveFeedLoading.value = true;
  liveFeedError.value = '';
  try {
    const payload = await publicApi('/api/public/live-feed?limit=80');
    liveFeedData.value = {
      stats: payload.stats || {},
      items: Array.isArray(payload.items) ? payload.items : [],
    };
  } catch (error) {
    liveFeedError.value = error.message || 'Could not load live feed';
  } finally {
    liveFeedLoading.value = false;
  }
}

async function loadProtocolManifest(options = {}) {
  const silent = Boolean(options.silent);
  if (!silent) protocolLoading.value = true;
  protocolError.value = '';
  try {
    const payload = await publicApi(publicProtocolManifestPath);
    protocolManifest.value = payload && typeof payload === 'object' ? payload : null;
  } catch (error) {
    protocolError.value = error.message || 'Could not load protocol index';
  } finally {
    protocolLoading.value = false;
  }
}

async function loadRuntimeConfig() {
  if (runtimeConfig.value) {
    return runtimeConfig.value;
  }
  runtimeConfig.value = await api('/api/config');
  return runtimeConfig.value;
}

async function loadLedgerData(options = {}) {
  ledgerError.value = '';
  if (!options.silent) {
    ledgerLoading.value = true;
  }
  try {
    const [entries, marketplace, proof, events, economy] = await Promise.all([
      publicApi('/api/public/ledger'),
      publicApi('/api/public/marketplace'),
      publicApi('/api/public/ledger/proof'),
      publicApi('/api/public/ledger/events?limit=100'),
      publicApi('/api/public/token-economy'),
    ]);
    ledgerRawEntries.value = Array.isArray(entries) ? entries : [];
    ledgerProjects.value = Array.isArray(marketplace.projects) ? marketplace.projects : [];
    ledgerProof.value = proof && typeof proof === 'object' ? proof : null;
    ledgerEventData.value = {
      stats: events?.stats || {},
      items: Array.isArray(events?.items) ? events.items : [],
    };
    ledgerEconomy.value = economy && typeof economy === 'object'
      ? {
          stats: economy.stats || {},
          totals: economy.totals || {},
          balances: Array.isArray(economy.balances) ? economy.balances : [],
          flows: Array.isArray(economy.flows) ? economy.flows : [],
          recent_entries: Array.isArray(economy.recent_entries) ? economy.recent_entries : [],
        }
      : { stats: {}, totals: {}, balances: [], flows: [], recent_entries: [] };
  } catch (error) {
    ledgerError.value = error.message;
    ledgerProof.value = null;
    ledgerEventData.value = { stats: {}, items: [] };
    ledgerEconomy.value = { stats: {}, totals: {}, balances: [], flows: [], recent_entries: [] };
  } finally {
    ledgerLoading.value = false;
  }
}

async function loadDashboardData(options = {}) {
  if (!token.value) {
    customerDashboardSnapshot.value = emptyCustomerDashboardSnapshot();
    dashboardProjects.value = [];
    dashboardTasks.value = [];
    dashboardLedgerEntries.value = [];
    resetDashboardProjectProtocolState();
    dashboardSection.value = 'projects';
    selectedDashboardProjectID.value = '';
    return;
  }

  const silent = Boolean(options.silent);
  if (!silent) dashboardLoading.value = true;
  dashboardError.value = '';
  try {
    let loadedFromProtocol = false;
    try {
      const [snapshot, legacyTasks] = await Promise.all([
        api('/api/customers/me'),
        api('/api/tasks').catch(() => []),
      ]);
      applyCustomerDashboardSnapshot(snapshot, legacyTasks);
      loadedFromProtocol = true;
    } catch (protocolError) {
      if (protocolError.status && protocolError.status !== 404 && protocolError.status !== 405) {
        throw protocolError;
      }
    }
    if (!loadedFromProtocol) {
      const [projects, tasks, entries] = await Promise.all([
        api('/api/projects'),
        api('/api/tasks'),
        api('/api/ledger'),
      ]);
      customerDashboardSnapshot.value = emptyCustomerDashboardSnapshot();
      dashboardProjects.value = Array.isArray(projects) ? projects : [];
      dashboardTasks.value = Array.isArray(tasks) ? tasks : [];
      dashboardLedgerEntries.value = Array.isArray(entries) ? entries : [];
    }
    const requestedProjectID = options.selectProjectID || selectedDashboardProjectID.value;
    const selectedExists = dashboardProjects.value.some((project) => project.id === requestedProjectID);
    selectedDashboardProjectID.value = selectedExists
      ? requestedProjectID
      : (dashboardSortedProjects.value[0]?.id || '');
    if (selectedDashboardProjectID.value) {
      await loadDashboardDeliverySnapshotData(selectedDashboardProjectID.value, { silent: true });
    } else {
      resetDashboardProjectProtocolState();
    }
  } catch (error) {
    dashboardError.value = error.message || 'Could not load projects';
  } finally {
    dashboardLoading.value = false;
  }
}

