function handleWSDeploymentStatus(payload = {}) {
  const deployment = payload.deployment || {};
  const projectID = payload.project_id || deployment.project_id || '';
  const eventID = payload.event_id || `deployment:${projectID}:${payload.status || deployment.status || ''}:${payload.progress || deployment.progress || ''}:${payload.created_at || deployment.updated_at || ''}`;
  if (rememberWSEvent(eventID)) return;
  if (!projectID) return;
  const liveFeedItem = deploymentRealtimeLiveFeedItem(payload);

  if (user.value) {
    const ownsProject = dashboardProjects.value.some((project) => project.id === projectID);
    const shouldShowProject = isAdminUser.value || ownsProject || projectID === selectedDashboardProjectID.value;
    if (shouldShowProject && projectID === selectedDashboardProjectID.value) {
      dashboardDeployment.value = normalizeDashboardDeploymentPayload(deployment, projectID);
      dashboardDeploymentError.value = '';
      void loadDashboardWorkflowPulseData(projectID, { silent: true });
    }
    if (shouldShowProject && dashboardSection.value === 'admin' && isAdminUser.value) {
      void loadAdminConsoleData({ silent: true });
    }
  }

  if (liveFeedItem?.id) {
    prependRealtimeLiveFeedItem(liveFeedItem);
  } else {
    void loadLiveFeedData({ silent: true });
  }
}

function clearSession() {
  disconnectWebSocket();
  stopDashboardRealtime();
  token.value = null;
  user.value = null;
  authVisible.value = false;
  ledgerError.value = '';
  errorMessage.value = '';
  customerDashboardSnapshot.value = emptyCustomerDashboardSnapshot();
  dashboardProjects.value = [];
  dashboardTasks.value = [];
  dashboardLedgerEntries.value = [];
  resetDashboardProjectProtocolState();
  adminConsole.value = {
    summary: {},
    ops: { stats: {}, items: [] },
    disputes: { stats: {}, lanes: [], items: [] },
    users: [],
    reputation: { stats: {}, workers: [] },
    ledger: [],
    tasks: [],
  };
  adminConsoleLoading.value = false;
  adminConsoleError.value = '';
  dashboardNotifications.value = [];
  dashboardNotificationsError.value = '';
  workerDashboard.value = {
    profile: {},
    stats: {},
    claimed_tasks: [],
    rewards: [],
    reputation: [],
    proposals: [],
    identity_status: [],
  };
  workerDashboardError.value = '';
  dashboardError.value = '';
  dashboardSection.value = 'projects';
  selectedDashboardProjectID.value = '';
  pendingProjectPaymentAfterAuth.value = false;
  authReturnToProjectWizard.value = false;
  pendingClaimBounty.value = null;
  fundingSuggestedTaskID.value = '';
  claimingBountyID.value = '';
  repoTaskFundingVisible.value = false;
  repoTaskFundingBusy.value = false;
  resetRepositoryTaskFundingInputs();
  resetProjectPaymentInputs();
  projectPaymentSuccessMethod.value = '';
  expandedReviewTaskID.value = '';
  reviewSubmittingTaskID.value = '';
  recordingAgentActionKey.value = '';
  releasingTaskID.value = '';
  Object.keys(taskReviewDrafts).forEach((key) => {
    delete taskReviewDrafts[key];
  });
  removeStoredToken();

  if (!publicModeVisible.value || projectWizardVisible.value) {
    projectWizardVisible.value = false;
    openPublicPage('home');
  }
}

async function submitAuth() {
  errorMessage.value = '';
  authNotice.value = '';
  if (authMode.value === 'register') {
    if (!authTermsAccepted.value) {
      errorMessage.value = 'Please accept the terms before creating an account.';
      return;
    }
    if (authForm.password !== authForm.confirm_password) {
      errorMessage.value = 'Passwords do not match.';
      return;
    }
  }
  if (authMode.value === 'reset-confirm' && authForm.password !== authForm.confirm_password) {
    errorMessage.value = 'Passwords do not match.';
    return;
  }

  authBusy.value = true;
  try {
    if (authMode.value === 'reset-request') {
      const response = await publicApi('/api/auth/password-reset/request', {
        method: 'POST',
        body: JSON.stringify({
          email: authForm.email,
          reset_url: passwordResetReturnURL(),
        }),
      });
      if (response.reset_token) {
        authMode.value = 'reset-confirm';
        authForm.reset_token = response.reset_token;
        authForm.password = '';
        authForm.confirm_password = '';
        authNotice.value = 'Local email is not configured, so MergeOS generated a reset token here.';
      } else {
        authNotice.value = 'If that email exists, reset instructions are on the way.';
      }
      showToast('Password reset request received.');
      return;
    }

    if (authMode.value === 'reset-confirm') {
      const auth = await publicApi('/api/auth/password-reset/confirm', {
        method: 'POST',
        body: JSON.stringify({
          token: authForm.reset_token,
          password: authForm.password,
        }),
      });
      setSession(auth);
      showToast('Password reset. You are logged in.');
      return;
    }

    const path = authMode.value === 'register' ? '/api/auth/register' : '/api/auth/login';
    const body = authMode.value === 'register'
      ? {
        name: authForm.name,
        company_name: authForm.company_name,
        email: authForm.email,
        password: authForm.password,
      }
      : { email: authForm.email, password: authForm.password };
    const auth = await api(path, { method: 'POST', body: JSON.stringify(body) });
    setSession(auth);
    showToast(authMode.value === 'register' ? 'Account created.' : 'Logged in.');
  } catch (error) {
    errorMessage.value = error.message;
  } finally {
    authBusy.value = false;
  }
}

async function restoreSession() {
  if (!token.value) return;
  try {
    user.value = await api('/api/auth/me');
    await loadDashboardData({ silent: true });
    await loadWorkerDashboardData({ silent: true });
    if (isAdminUser.value) {
      await loadAdminConsoleData({ silent: true });
    }
    await loadDashboardNotifications();
    startDashboardRealtime();
    if (publicPage.value === 'ledger') {
      void loadLedgerData({ silent: true });
    }
  } catch {
    clearSession();
  }
}

async function logout() {
  const req = api('/api/auth/logout', { method: 'POST', body: JSON.stringify({}) }).catch((err) => {
    console.warn('Backend logout failed gracefully', err);
  });

  publicModeVisible.value = true;
  clearSession();
  publicPage.value = 'home';
  updatePublicBrowserPath('home', true);
  showToast('Logged out.');

  await req;
}

onMounted(async () => {
  clientHydrated.value = true;
  applyLocaleToDocument();
  applySeoToDocument();
  connectWebSocket();
  const paypalCheckoutPath = hasWindow && isPayPalCheckoutPath(window.location.pathname);
  if (hasWindow) {
    const params = new URLSearchParams(window.location.search);
    const oauthToken = params.get('token');
    if (oauthToken && !paypalCheckoutPath) {
      token.value = oauthToken;
      writeStoredToken(oauthToken);
      const cleanUrl = window.location.pathname + window.location.hash;
      window.history.replaceState({}, document.title, cleanUrl);
      showToast('Successfully logged in via OAuth!');
    }
  }

  const handledPasswordResetToken = handlePasswordResetToken();
  const handledGitHubCallback = await handleGitHubCallback();
  if (hasWindow) {
    window.addEventListener('popstate', syncPublicPageFromBrowserPath);
    window.addEventListener('resize', updateDashboardNotificationMenuPosition);
    window.addEventListener('scroll', updateDashboardNotificationMenuPosition, true);
    document.addEventListener('click', handleNavContextOutsideClick);
    document.addEventListener('click', handleDashboardNotificationOutsideClick);
    if (!handledGitHubCallback && !handledPasswordResetToken && !paypalCheckoutPath) {
      if (projectWizardVisible.value) {
        restoreProjectDraft({ silent: true, restoreStep: false });
        if (!guardProjectWizardRouteValidation({ replace: true, silent: false })) {
          updateProjectWizardBrowserPath(true);
        }
      } else {
        updatePublicBrowserPath(publicPage.value, true);
      }
    }
  }
  const runtimePromise = loadRuntimeConfig().catch((error) => showToast(error.message));
  await Promise.all([
    runtimePromise,
    restoreSession(),
    loadMarketplaceData({ silent: true }),
    loadLedgerData({ silent: true }),
    loadLiveFeedData({ silent: true }),
    (publicPage.value === 'protocol' || publicPage.value === 'sdk') ? loadProtocolManifest({ silent: true }) : Promise.resolve(),
  ]);
  if (paypalCheckoutPath) {
    await handlePayPalCheckoutReturn();
  }
});

onUnmounted(() => {
  disconnectWebSocket();
  if (hasWindow) {
    window.removeEventListener('popstate', syncPublicPageFromBrowserPath);
    window.removeEventListener('resize', updateDashboardNotificationMenuPosition);
    window.removeEventListener('scroll', updateDashboardNotificationMenuPosition, true);
    document.removeEventListener('click', handleNavContextOutsideClick);
    document.removeEventListener('click', handleDashboardNotificationOutsideClick);
  }
  stopDashboardRealtime();
});
</script>
